# â”â‚¬â”â‚¬â”â‚¬ Idempotency middleware â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬
# Prevents duplicate mutations when the client retries on network issues.
IDEMPOTENCY_TTL_SECONDS = 300  # 5 minutes

@app.middleware("http")
async def idempotency_middleware(request: Request, call_next):
    idem_key = request.headers.get("x-idempotency-key")
    if not idem_key or request.method in ("GET", "HEAD", "OPTIONS"):
        return await call_next(request)

    cache_key = f"idem:{idem_key}"
    existing = await db.idempotency_cache.find_one({"_id": cache_key})
    if existing:
        return JSONResponse(
            status_code=existing.get("status_code", 200),
            content=existing.get("body"),
        )

    response = await call_next(request)

    # Only cache successful responses for mutations
    if 200 <= response.status_code < 300:
        body_bytes = b""
        async for chunk in response.body_iterator:
            body_bytes += chunk if isinstance(chunk, bytes) else chunk.encode()
        import json as _json
        try:
            body_json = _json.loads(body_bytes)
        except Exception:
            body_json = body_bytes.decode(errors="replace")
        await db.idempotency_cache.update_one(
            {"_id": cache_key},
            {"$set": {"status_code": response.status_code, "body": body_json, "created_at": datetime.now(timezone.utc)}},
            upsert=True,
        )
        return JSONResponse(status_code=response.status_code, content=body_json, headers=dict(response.headers))

    return response

MOJIBAKE_MARKERS = (
    "Ã",
    "",
    "â€™",
    "â€œ",
    "â€",
    "â€“",
    "â€”",
    "â€",
)


def _mojibake_score(value: str) -> int:
    return sum(value.count(marker) for marker in MOJIBAKE_MARKERS)


def _repair_mojibake_text(value: str) -> str:
    if not isinstance(value, str) or not value:
        return value

    repaired = value
    for _ in range(2):
        if _mojibake_score(repaired) == 0:
            break
        try:
            candidate = repaired.encode("latin-1").decode("utf-8")
        except Exception:
            break
        if _mojibake_score(candidate) <= _mojibake_score(repaired):
            repaired = candidate
        else:
            break

    replacements = {
        "â€™": "'",
        "â€œ": '"',
        "â€": '"',
        "â€“": "-",
        "â€”": "-",
        "Â ": " ",
    }
    for bad, good in replacements.items():
        repaired = repaired.replace(bad, good)
    return repaired


def _repair_mojibake_payload(payload: Any) -> Any:
    if isinstance(payload, dict):
        return {k: _repair_mojibake_payload(v) for k, v in payload.items()}
    if isinstance(payload, list):
        return [_repair_mojibake_payload(item) for item in payload]
    if isinstance(payload, str):
        return _repair_mojibake_text(payload)
    return payload


@app.middleware("http")
async def normalize_mojibake_json_response(request: Request, call_next):
    response = await call_next(request)
    content_type = (response.headers.get("content-type") or "").lower()
    if "application/json" not in content_type:
        return response
    if isinstance(response, StreamingResponse):
        return response

    body_bytes = b""
    async for chunk in response.body_iterator:
        body_bytes += chunk if isinstance(chunk, bytes) else str(chunk).encode("utf-8")

    try:
        payload = json.loads(body_bytes)
    except Exception:
        return Response(
            content=body_bytes,
            status_code=response.status_code,
            headers=dict(response.headers),
            media_type=response.media_type,
        )

    repaired_payload = _repair_mojibake_payload(payload)
    headers = dict(response.headers)
    headers.pop("content-length", None)
    return JSONResponse(
        status_code=response.status_code,
        content=repaired_payload,
        headers=headers,
    )

