@app.get("/api/public/receipts/{sale_id}", response_model=PublicReceipt)
async def get_legacy_public_receipt(sale_id: str):
    raise HTTPException(status_code=410, detail="Ce lien de reçu a été révoqué. Utilisez le nouveau lien sécurisé.")


@app.get("/api/public/receipts/t/{public_token}", response_model=PublicReceipt)
async def get_public_receipt(public_token: str):
    """Public endpoint to view receipt details without authentication."""
    sale = await db.sales.find_one({"public_receipt_token": public_token})
    if not sale:
        raise HTTPException(status_code=404, detail="Reçu non trouvé")
    
    # Get store info
    store = await db.stores.find_one({"store_id": sale["store_id"]})
    store_name = (store or {}).get("receipt_business_name") or (store or {}).get("name") or "Ma Boutique"
    store_address = store.get("address") if store else None
    receipt_footer = store.get("receipt_footer") if store else None

    items = [
        PublicReceiptItem(
            product_name=item["product_name"],
            quantity=item["quantity"],
            selling_price=item["selling_price"],
            total=item["total"],
            sold_quantity_input=item.get("sold_quantity_input"),
            sold_unit=item.get("sold_unit"),
        ) for item in sale["items"]
    ]

    return PublicReceipt(
        sale_id=sale["sale_id"],
        items=items,
        total_amount=sale["total_amount"],
        payment_method=sale["payment_method"],
        created_at=sale["created_at"],
        store_name=store_name,
        store_address=store_address,
        receipt_footer=receipt_footer
    )


@app.get("/public/receipts/t/{public_token}", response_class=HTMLResponse)
async def view_public_receipt_page(public_token: str):
    """Public HTML receipt page for QR scans."""
    receipt = await get_public_receipt(public_token)

    def fmt_amount(value: float) -> str:
        try:
            return f"{float(value):,.0f}".replace(",", " ")
        except Exception:
            return str(value)

    created_label = receipt.created_at.astimezone(timezone.utc).strftime("%d/%m/%Y %H:%M UTC") if receipt.created_at else ""
    items_html = "".join(
        f"""
        <tr>
            <td>{escape(item.product_name)}</td>
            <td style="text-align:center;">{escape(str(item.sold_quantity_input if item.sold_quantity_input is not None else item.quantity))}{f" {escape(item.sold_unit)}" if item.sold_unit else ""}</td>
            <td style="text-align:right;">{fmt_amount(item.selling_price)}</td>
            <td style="text-align:right;">{fmt_amount(item.total)}</td>
        </tr>
        """
        for item in receipt.items
    )

    return HTMLResponse(content=f"""
        <!DOCTYPE html>
        <html lang="fr">
        <head>
            <meta charset="utf-8" />
            <meta name="viewport" content="width=device-width, initial-scale=1" />
            <title>Reçu {escape(receipt.sale_id)}</title>
            <style>
                :root {{
                    color-scheme: light;
                    --bg: #f5f1e8;
                    --card: #fffdf8;
                    --ink: #1f2937;
                    --muted: #6b7280;
                    --line: #eadfcb;
                    --accent: #2563eb;
                }}
                * {{ box-sizing: border-box; }}
                body {{
                    margin: 0;
                    font-family: Arial, sans-serif;
                    background: linear-gradient(180deg, #f8f4ec 0%, #efe7d8 100%);
                    color: var(--ink);
                    padding: 20px;
                }}
                .wrap {{
                    max-width: 760px;
                    margin: 0 auto;
                }}
                .card {{
                    background: var(--card);
                    border: 1px solid var(--line);
                    border-radius: 24px;
                    padding: 24px;
                    box-shadow: 0 16px 40px rgba(15, 23, 42, 0.08);
                }}
                .eyebrow {{
                    font-size: 12px;
                    text-transform: uppercase;
                    letter-spacing: 0.12em;
                    color: var(--accent);
                    font-weight: 700;
                }}
                h1 {{
                    margin: 8px 0 4px;
                    font-size: 28px;
                    line-height: 1.1;
                }}
                .meta {{
                    color: var(--muted);
                    font-size: 14px;
                    margin-bottom: 20px;
                }}
                .total {{
                    margin: 20px 0;
                    padding: 16px 18px;
                    border-radius: 16px;
                    background: #eff6ff;
                    display: flex;
                    justify-content: space-between;
                    align-items: center;
                    gap: 12px;
                    font-weight: 700;
                }}
                table {{
                    width: 100%;
                    border-collapse: collapse;
                    margin-top: 8px;
                }}
                th, td {{
                    padding: 12px 8px;
                    border-bottom: 1px solid var(--line);
                    font-size: 14px;
                    vertical-align: top;
                }}
                th {{
                    text-align: left;
                    color: var(--muted);
                    font-size: 12px;
                    text-transform: uppercase;
                    letter-spacing: 0.04em;
                }}
                .footer {{
                    margin-top: 20px;
                    color: var(--muted);
                    font-size: 14px;
                    text-align: center;
                }}
                .actions {{
                    display: flex;
                    gap: 12px;
                    flex-wrap: wrap;
                    margin-top: 20px;
                }}
                .btn {{
                    display: inline-flex;
                    align-items: center;
                    justify-content: center;
                    padding: 12px 16px;
                    border-radius: 999px;
                    text-decoration: none;
                    font-weight: 700;
                    border: 1px solid var(--line);
                    color: var(--ink);
                    background: white;
                }}
                .btn-primary {{
                    background: var(--accent);
                    color: white;
                    border-color: var(--accent);
                }}
                @media print {{
                    body {{
                        background: white;
                        padding: 0;
                    }}
                    .card {{
                        box-shadow: none;
                        border: none;
                        border-radius: 0;
                        padding: 0;
                    }}
                    .actions {{ display: none; }}
                }}
            </style>
        </head>
        <body>
            <div class="wrap">
                <div class="card">
                    <div class="eyebrow">Reçu numérique</div>
                    <h1>{escape(receipt.store_name)}</h1>
                    <div class="meta">
                        {escape(receipt.store_address or "")}<br />
                        Référence vente : {escape(receipt.sale_id)}<br />
                        Date : {escape(created_label)}<br />
                        Paiement : {escape(receipt.payment_method)}
                    </div>

                    <div class="total">
                        <span>Total</span>
                        <span>{fmt_amount(receipt.total_amount)}</span>
                    </div>

                    <table>
                        <thead>
                            <tr>
                                <th>Produit</th>
                                <th style="text-align:center;">Quantité</th>
                                <th style="text-align:right;">Prix</th>
                                <th style="text-align:right;">Total</th>
                            </tr>
                        </thead>
                        <tbody>
                            {items_html}
                        </tbody>
                    </table>

                    <div class="actions">
                        <a class="btn btn-primary" href="javascript:window.print()">Imprimer / PDF</a>
                    </div>

                    <div class="footer">{escape(receipt.receipt_footer or "Merci de votre visite.")}</div>
                </div>
            </div>
        </body>
        </html>
    """)

