async def detect_anomalies_internal(user_id: str, store_id: Optional[str] = None, lang: str = "fr") -> List[dict]:
    """Core logic for AI anomaly detection, returns list of anomaly objects"""
    api_key = os.environ.get("GOOGLE_API_KEY")
    if not api_key:
        return []

    try:
        now = datetime.now(timezone.utc)
        query = {"user_id": user_id}
        if store_id:
            query["store_id"] = store_id
        
        products = await db.products.find(query, {"_id": 0}).to_list(1000)
        # Skip anomaly detection for empty accounts — avoids AI false positives
        if not products:
            return []
        seven_days_ago = now - timedelta(days=7)
        thirty_days_ago = now - timedelta(days=30)
        sales_30 = await db.sales.find({**query, "created_at": {"$gte": thirty_days_ago}}).to_list(10000)

        daily_rev = defaultdict(float)
        daily_count = defaultdict(int)
        product_sales_7d = defaultdict(int)
        product_sales_prev = defaultdict(int)

        for s in sales_30:
            sale_date = parse_datetime_value(s.get("created_at"))
            if not sale_date:
                continue
            day_key = sale_date.strftime("%Y-%m-%d")
            daily_rev[day_key] += s.get("total_amount", 0)
            daily_count[day_key] += 1
            is_last_7 = sale_date >= seven_days_ago
            for item in s.get("items", []):
                pid = item.get("product_id", "")
                qty = item.get("quantity", 0)
                if is_last_7:
                    product_sales_7d[pid] += qty
                else:
                    product_sales_prev[pid] += qty

        user_doc = await db.users.find_one({"user_id": user_id})
        business_profile = get_ai_business_profile(user_doc)
        business_guidance = get_ai_business_guidance(business_profile, lang)
        currency = user_doc.get("currency", "XOF") if user_doc else "XOF"
        
        avg_daily_rev = sum(daily_rev.values()) / max(len(daily_rev), 1)
        out_of_stock_count = len([p for p in products if _safe_float(p.get("quantity"), 0.0) <= 0])
        out_of_stock_ratio = out_of_stock_count / max(len(products), 1)
        low_revenue_days = len([value for value in daily_rev.values() if value <= (avg_daily_rev * 0.4)])
        active_days_14 = len(daily_rev)

        # Hard guards to reduce noisy alerts:
        # each anomaly type must be supported by concrete metrics.
        signal_map: Dict[str, bool] = {
            "revenue": active_days_14 >= 10 and avg_daily_rev > 0 and low_revenue_days >= 4,
            "volume": len(volume_changes) >= 2,
            "margin": len(margin_issues) >= 3,
            "stock": out_of_stock_count >= 5 or out_of_stock_ratio >= 0.25,
        }

        # If there is no strong signal, skip AI generation entirely.
        if not any(signal_map.values()):
            return []

        revenue_data = [f"{d}: {r:.0f} {currency} ({c} ventes)" for d, r, c in
                        sorted([(d, daily_rev[d], daily_count[d]) for d in daily_rev], key=lambda x: x[0])[-14:]]

        margin_issues = []
        volume_changes = []
        for p in products:
            purchase = p.get("purchase_price", 0)
            selling = p.get("selling_price", 0)
            if purchase > 0 and selling > 0:
                margin = (selling - purchase) / selling * 100
                if margin < 5:
                    margin_issues.append(f"- {p['name']}: marge={margin:.1f}% (achat={purchase}, vente={selling})")
                elif margin > 80:
                    margin_issues.append(f"- {p['name']}: marge très élevée={margin:.1f}%")

            pid = p["product_id"]
            s7 = product_sales_7d.get(pid, 0)
            s_prev_daily = product_sales_prev.get(pid, 0) / 23.0
            s7_daily = s7 / 7.0
            if s_prev_daily > 0 and s7_daily > s_prev_daily * 3:
                volume_changes.append(f"- {p['name']}: pic x{s7_daily/s_prev_daily:.1f}")
            elif s_prev_daily > 1 and s7_daily < s_prev_daily * 0.3:
                volume_changes.append(f"- {p['name']}: chute x{s_prev_daily/max(s7_daily,0.1):.1f}")

        lang_instr = get_language_instruction(lang)
        prompt = f"""Tu es un analyste business expert. Analyse ces données d'un commerce et détecte les ANOMALIES.
CA quotidien (14 derniers jours) : {chr(10).join(revenue_data) if revenue_data else "Aucune"}
CA moyen journalier : {avg_daily_rev:.0f} {currency}
Changements de volume inhabituels : {chr(10).join(volume_changes[:15]) if volume_changes else "Aucun"}
Marges anormales : {chr(10).join(margin_issues[:15]) if margin_issues else "Normales"}
Produits : {len(products)}
Ruptures : {len([p for p in products if p.get('quantity', 0) == 0])}
Contexte métier : {business_profile.get('sector_label')}
Consigne métier : {business_guidance["anomalies"]}

Réponds UNIQUEMENT en JSON (sans markdown) avec ce format :
[ {{"type": "revenue"|"volume"|"margin"|"stock", "severity": "critical"|"warning", "title": "Titre court", "description": "Explication et recommandation en 1-2 phrases"}} ]
Contraintes importantes:
- N'inclure que des anomalies actionnables (pas d'information normale).
- Eviter les alertes faibles ou ambiguës.
- Maximum 3 anomalies.
{lang_instr}"""

        genai.configure(api_key=api_key)
        model = genai.GenerativeModel('gemini-2.5-flash')
        response = model.generate_content(prompt)
        text = response.text.strip()
        if text.startswith("```"):
            text = text.split("\n", 1)[1].rsplit("```", 1)[0].strip()
        parsed = json.loads(text)
        if not isinstance(parsed, list):
            return []

        severity_rank = {"critical": 2, "warning": 1}
        filtered: List[dict] = []
        best_by_type: Dict[str, dict] = {}

        for item in parsed:
            if not isinstance(item, dict):
                continue
            anomaly_type = str(item.get("type") or "").strip().lower()
            severity = str(item.get("severity") or "").strip().lower()
            title = str(item.get("title") or "").strip()
            description = str(item.get("description") or "").strip()

            if anomaly_type not in signal_map or not signal_map.get(anomaly_type):
                continue
            if severity not in severity_rank:
                continue
            if not title or not description:
                continue

            normalized = {
                "type": anomaly_type,
                "severity": severity,
                "title": title,
                "description": description,
            }
            current = best_by_type.get(anomaly_type)
            if current is None or severity_rank[severity] > severity_rank.get(current.get("severity", ""), 0):
                best_by_type[anomaly_type] = normalized

        filtered = list(best_by_type.values())
        filtered.sort(key=lambda anomaly: severity_rank.get(str(anomaly.get("severity", "")).lower(), 0), reverse=True)

        # Politique produit: priorité forte au stock.
        # - Garder l'alerte stock si présente.
        # - Autoriser au plus une autre alerte non-stock, uniquement si critique.
        stock_alerts = [a for a in filtered if a.get("type") == "stock"]
        non_stock_critical = [
            a for a in filtered
            if a.get("type") != "stock" and str(a.get("severity", "")).lower() == "critical"
        ]

        prioritized: List[dict] = []
        if stock_alerts:
            prioritized.append(stock_alerts[0])
            if non_stock_critical:
                prioritized.append(non_stock_critical[0])
        else:
            # Si aucune alerte stock, on reste strict: une seule critique non-stock.
            if non_stock_critical:
                prioritized.append(non_stock_critical[0])

        return prioritized
    except Exception as e:
        logger.error(f"Internal anomaly check error: {e}")
        return []

