@api_router.get("/ai/product-correlations")
async def get_product_correlations(
    min_support: int = 3,
    user: User = Depends(require_operational_access)
):
    """
    Find product pairs frequently bought together (market basket analysis).
    Uses co-occurrence in sales with ≥2 items. Computes lift score.
    Enterprise only.
    """
    owner_id = get_owner_id(user)
    plan = _resolve_ai_plan(user)
    _check_ai_gate(owner_id, "product_correlations", plan)

    cache_key = f"product_correlations:{owner_id}"
    cached = _ai_cache.get(cache_key)
    if cached and (datetime.now(timezone.utc).timestamp() - _ai_cache_ts.get(cache_key, 0)) < 86400:
        return cached

    ninety_days_ago = datetime.now(timezone.utc) - timedelta(days=90)

    # Fetch multi-item sales
    sales = await db.sales.find(
        {"user_id": owner_id, "created_at": {"$gte": ninety_days_ago}, f"items.1": {"$exists": True}},
        {"items.product_id": 1, "items.name": 1}
    ).to_list(2000)

    if not sales:
        return {"pairs": [], "total_baskets": 0}

    # Build co-occurrence matrix
    from itertools import combinations
    co_occurrence: Dict[tuple, int] = {}
    product_freq: Dict[str, int] = {}
    total_baskets = len(sales)

    product_names: Dict[str, str] = {}

    for sale in sales:
        items = sale.get("items", [])
        pids = []
        for item in items:
            pid = item.get("product_id")
            if pid:
                pids.append(pid)
                product_freq[pid] = product_freq.get(pid, 0) + 1
                if pid not in product_names and item.get("name"):
                    product_names[pid] = item["name"]

        pids = list(set(pids))  # deduplicate within basket
        for pair in combinations(sorted(pids), 2):
            co_occurrence[pair] = co_occurrence.get(pair, 0) + 1

    # Filter by min_support and compute lift
    pairs = []
    for (pid_a, pid_b), count in co_occurrence.items():
        if count < min_support:
            continue
        freq_a = product_freq.get(pid_a, 1)
        freq_b = product_freq.get(pid_b, 1)
        support = count / total_baskets
        expected = (freq_a / total_baskets) * (freq_b / total_baskets)
        lift = support / expected if expected > 0 else 0
        if lift >= 1.5:
            pairs.append({
                "product_a_id": pid_a,
                "product_a_name": product_names.get(pid_a, pid_a),
                "product_b_id": pid_b,
                "product_b_name": product_names.get(pid_b, pid_b),
                "co_occurrence": count,
                "lift": round(lift, 2),
                "support": round(support * 100, 1),
            })

    pairs.sort(key=lambda x: x["lift"], reverse=True)
    pairs = pairs[:20]

    _track_ai_usage_lite(owner_id, "product_correlations", plan)

    result = {
        "pairs": pairs,
        "total_baskets": total_baskets,
        "analysis_window_days": 90,
        "min_lift": 1.5,
    }

    _ai_cache[cache_key] = result
    _ai_cache_ts[cache_key] = datetime.now(timezone.utc).timestamp()
    return result


# ===================== END VAGUE 5 =====================

# ===================== VAGUE 4 — MULTI-STORE INTELLIGENCE =====================

@api_router.get("/ai/rebalance-suggestions")
async def get_rebalance_suggestions(user: User = Depends(require_operational_access)):
    """
    Suggest stock transfers between stores based on stock level vs sales velocity.
    Enterprise only.
    """
    owner_id = get_owner_id(user)
    plan = _resolve_ai_plan(user)
    _check_ai_gate(owner_id, "rebalance_suggestions", plan)

    cache_key = f"rebalance:{owner_id}"
    cached = _ai_cache.get(cache_key)
    if cached and (datetime.now(timezone.utc).timestamp() - _ai_cache_ts.get(cache_key, 0)) < 3600:
        return cached

    def _to_float(value: Any, default: float = 0.0) -> float:
        try:
            if value is None:
                return default
            return float(value)
        except (TypeError, ValueError):
            return default

    # Get all stores
    raw_stores = await db.stores.find({"user_id": owner_id}, {"_id": 0}).to_list(20)
    stores = []
    for store in raw_stores:
        store_id = str(store.get("store_id") or "").strip()
        if not store_id:
            continue
        stores.append({
            **store,
            "store_id": store_id,
            "name": str(store.get("name") or store_id),
        })

    if len(stores) < 2:
        return {"suggestions": [], "stores_count": len(stores), "message": "Nécessite au moins 2 boutiques"}

    store_ids = [s["store_id"] for s in stores]
    store_names = {s["store_id"]: s["name"] for s in stores}

    thirty_days_ago = datetime.now(timezone.utc) - timedelta(days=30)

    # Get stock per product per store
    all_products = await db.products.find(
        {"user_id": owner_id, "store_id": {"$in": store_ids}},
        {"product_id": 1, "name": 1, "store_id": 1, "stock_quantity": 1, "reorder_point": 1, "cost_price": 1}
    ).to_list(500)

    # Build stock map: {product_id: {store_id: stock}}
    # Group by base product name to match across stores
    product_by_name: Dict[str, list] = {}
    for product in all_products:
        product_id = str(product.get("product_id") or "").strip()
        store_id = str(product.get("store_id") or "").strip()
        if not product_id or not store_id:
            continue
        key = str(product.get("name") or "").lower().strip()
        if key:
            if key not in product_by_name:
                product_by_name[key] = []
            product_by_name[key].append({
                **product,
                "product_id": product_id,
                "store_id": store_id,
                "stock_quantity": _to_float(product.get("stock_quantity"), _to_float(product.get("quantity"), 0.0)),
                "cost_price": _to_float(product.get("cost_price"), _to_float(product.get("purchase_price"), 0.0)),
            })

    # Sales velocity per product per store (last 30 days)
    velocity_agg = await db.sales.aggregate([
        {"$match": {"user_id": owner_id, "created_at": {"$gte": thirty_days_ago}}},
        {"$unwind": "$items"},
        {"$group": {
            "_id": {"product_id": "$items.product_id", "store_id": "$store_id"},
            "qty_sold": {"$sum": "$items.quantity"}
        }}
    ]).to_list(2000)

    velocity_map: Dict[str, Dict[str, float]] = {}
    for velocity_entry in velocity_agg:
        velocity_id = velocity_entry.get("_id") or {}
        pid = str(velocity_id.get("product_id") or "").strip()
        sid = str(velocity_id.get("store_id") or "").strip()
        if not pid or not sid:
            continue
        if pid not in velocity_map:
            velocity_map[pid] = {}
        velocity_map[pid][sid] = max(0.0, _to_float(velocity_entry.get("qty_sold"), 0.0)) / 30  # daily velocity

    suggestions = []
    for name, variants in product_by_name.items():
        if len(variants) < 2:
            continue

        # Find overstocked (stock >> velocity) and understocked (stock << velocity) pairs
        scored = []
        for product in variants:
            pid = str(product.get("product_id") or "").strip()
            sid = str(product.get("store_id") or "").strip()
            if not pid or not sid:
                continue
            stock = _to_float(product.get("stock_quantity"), 0.0)
            vel = max(0.0, _to_float(velocity_map.get(pid, {}).get(sid, 0.0), 0.0))
            days_cover = stock / vel if vel > 0 else 9999
            scored.append({**product, "velocity": vel, "days_cover": days_cover})

        if len(scored) < 2:
            continue

        # Sort by days of coverage
        scored.sort(key=lambda x: x["days_cover"])
        understocked = scored[0]   # lowest coverage
        overstocked = scored[-1]   # highest coverage

        under_store_id = str(understocked.get("store_id") or "").strip()
        over_store_id = str(overstocked.get("store_id") or "").strip()
        if not under_store_id or not over_store_id:
            continue
        if under_store_id == over_store_id:
            continue
        under_days_cover = _to_float(understocked.get("days_cover"), 9999.0)
        over_days_cover = _to_float(overstocked.get("days_cover"), 9999.0)
        under_velocity = max(0.0, _to_float(understocked.get("velocity"), 0.0))
        over_velocity = max(0.0, _to_float(overstocked.get("velocity"), 0.0))
        under_stock = _to_float(understocked.get("stock_quantity"), 0.0)
        over_stock = _to_float(overstocked.get("stock_quantity"), 0.0)

        if under_days_cover >= 14:
            continue  # not urgent
        if over_days_cover <= 14:
            continue  # source store also needs stock
        if over_stock <= 0:
            continue

        # How much to transfer: enough to give 14 days to understocked
        needed = max(0, round((14 * under_velocity) - under_stock))
        available = max(0, over_stock - round(14 * over_velocity))
        transfer_qty = min(needed, available)

        if transfer_qty <= 0:
            continue

        product_id_from = str(overstocked.get("product_id") or "").strip()
        product_id_to = str(understocked.get("product_id") or "").strip()
        if not product_id_from or not product_id_to:
            continue

        suggestions.append({
            "product_id_from": product_id_from,
            "product_id_to": product_id_to,
            "product_name": overstocked.get("name", name),
            "from_store_id": over_store_id,
            "from_store_name": store_names.get(over_store_id, over_store_id),
            "to_store_id": under_store_id,
            "to_store_name": store_names.get(under_store_id, under_store_id),
            "transfer_quantity": int(transfer_qty),
            "from_stock": over_stock,
            "to_stock": under_stock,
            "from_days_cover": round(over_days_cover),
            "to_days_cover": round(under_days_cover) if under_days_cover < 9999 else 0,
            "estimated_value": round(transfer_qty * _to_float(overstocked.get("cost_price"), 0.0), 2),
        })

    suggestions.sort(key=lambda x: x["to_days_cover"])
    suggestions = suggestions[:15]

    _track_ai_usage_lite(owner_id, "rebalance_suggestions", plan)

    result = {
        "suggestions": suggestions,
        "stores_count": len(stores),
        "total_found": len(suggestions),
    }

    _ai_cache[cache_key] = result
    _ai_cache_ts[cache_key] = datetime.now(timezone.utc).timestamp()
    return result


@api_router.get("/ai/store-benchmark")
async def get_store_benchmark(user: User = Depends(require_operational_access)):
    """
    Compare performance metrics across all stores: revenue, margin, stock rotation.
    Enterprise only.
    """
    owner_id = get_owner_id(user)
    plan = _resolve_ai_plan(user)
    _check_ai_gate(owner_id, "store_benchmark", plan)

    cache_key = f"store_benchmark:{owner_id}"
    cached = _ai_cache.get(cache_key)
    if cached and (datetime.now(timezone.utc).timestamp() - _ai_cache_ts.get(cache_key, 0)) < 21600:
        return cached

    stores = await db.stores.find({"user_id": owner_id}, {"_id": 0}).to_list(20)
    if len(stores) < 2:
        return {"stores": [], "message": "Nécessite au moins 2 boutiques"}

    thirty_days_ago = datetime.now(timezone.utc) - timedelta(days=30)

    store_stats = []
    for store in stores:
        sid = store["store_id"]
        store_query = {"user_id": owner_id, "store_id": sid}

        # Revenue + gross margin
        sales_agg = await db.sales.aggregate([
            {"$match": {**store_query, "created_at": {"$gte": thirty_days_ago}}},
            {"$group": {
                "_id": None,
                "revenue": {"$sum": "$total_amount"},
                "cost": {"$sum": "$cost_total"},
                "count": {"$sum": 1}
            }}
        ]).to_list(1)

        revenue = sales_agg[0]["revenue"] if sales_agg else 0
        cost = sales_agg[0]["cost"] if sales_agg else 0
        sales_count = sales_agg[0]["count"] if sales_agg else 0
        gross_margin = revenue - cost
        gross_margin_pct = round((gross_margin / revenue * 100) if revenue > 0 else 0, 1)

        # Stock value
        stock_agg = await db.products.aggregate([
            {"$match": store_query},
            {"$group": {"_id": None, "total": {"$sum": {"$multiply": ["$stock_quantity", {"$ifNull": ["$cost_price", 0]}]}}}}
        ]).to_list(1)
        stock_value = stock_agg[0]["total"] if stock_agg else 0

        # Stock rotation = revenue / avg_stock_value (simplified)
        rotation = round(revenue / stock_value if stock_value > 0 else 0, 2)

        # Product count
        product_count = await db.products.count_documents(store_query)

        store_stats.append({
            "store_id": sid,
            "store_name": store["name"],
            "revenue_30d": round(revenue, 2),
            "gross_margin": round(gross_margin, 2),
            "gross_margin_pct": gross_margin_pct,
            "sales_count": sales_count,
            "stock_value": round(stock_value, 2),
            "stock_rotation": rotation,
            "product_count": product_count,
            "avg_basket": round(revenue / sales_count if sales_count > 0 else 0, 2),
        })

    # Rank stores
    if store_stats:
        max_rev = max(s["revenue_30d"] for s in store_stats) or 1
        max_margin = max(s["gross_margin_pct"] for s in store_stats) or 1
        max_rotation = max(s["stock_rotation"] for s in store_stats) or 1
        for s in store_stats:
            s["performance_score"] = round(
                (s["revenue_30d"] / max_rev * 40) +
                (s["gross_margin_pct"] / max_margin * 40) +
                (s["stock_rotation"] / max_rotation * 20), 1
            )
        store_stats.sort(key=lambda x: x["performance_score"], reverse=True)
        store_stats[0]["rank_label"] = "top"
        if len(store_stats) > 1:
            store_stats[-1]["rank_label"] = "bottom"

    _track_ai_usage_lite(owner_id, "store_benchmark", plan)

    result = {
        "stores": store_stats,
        "period_days": 30,
        "total_stores": len(store_stats),
    }

    _ai_cache[cache_key] = result
    _ai_cache_ts[cache_key] = datetime.now(timezone.utc).timestamp()
    return result


# ===================== END VAGUE 4 =====================

# ===================== VAGUE 7 — LLM FEATURES =====================

@api_router.get("/ai/customer-summary/{customer_id}")
async def get_customer_summary(customer_id: str, lang: str = "fr", user: User = Depends(require_operational_access)):
    """
    Generate a narrative AI summary for a customer: purchase habits, loyalty, risk, recommendations.
    Enterprise only. Uses Gemini.
    """
    owner_id = get_owner_id(user)
    plan = _resolve_ai_plan(user)
    _check_ai_gate(owner_id, "customer_summary", plan)

    effective_store_id = user.active_store_id
    cache_key = f"customer_summary:{owner_id}:{effective_store_id or 'all'}:{customer_id}:{lang}"
    cached = _ai_cache.get(cache_key)
    if cached and (datetime.now(timezone.utc).timestamp() - _ai_cache_ts.get(cache_key, 0)) < 43200:
        return cached

    api_key = os.environ.get("GOOGLE_API_KEY")
    if not api_key:
        raise HTTPException(status_code=503, detail="Clé API IA manquante")

    # Fetch customer
    customer_query = apply_accessible_store_scope({"customer_id": customer_id, "user_id": owner_id}, user, effective_store_id)
    customer = await db.customers.find_one(customer_query, {"_id": 0})
    if not customer:
        raise HTTPException(status_code=404, detail="Client introuvable")

    ninety_days_ago = datetime.now(timezone.utc) - timedelta(days=90)

    # Aggregate customer sales
    sales_match = apply_accessible_store_scope(
        {"user_id": owner_id, "customer_id": customer_id, "created_at": {"$gte": ninety_days_ago}},
        user,
        effective_store_id,
    )
    sales_match = apply_completed_sales_scope(sales_match)
    sales_agg = await db.sales.aggregate([
        {"$match": sales_match},
        {"$unwind": "$items"},
        {"$group": {
            "_id": None,
            "total_revenue": {"$sum": "$total_amount"},
            "sales_count": {"$sum": 1},
            "top_products": {"$push": "$items.name"},
            "last_purchase": {"$max": "$created_at"},
        }}
    ]).to_list(1)

    # All-time totals from customer document
    total_spent_lifetime = customer.get("total_spent", 0)
    visit_count = customer.get("visit_count", 0)
    current_debt = customer.get("current_debt", 0)
    loyalty_points = customer.get("loyalty_points", 0)
    tier = customer.get("tier", "bronze")
    notes = customer.get("notes", "")

    recent = sales_agg[0] if sales_agg else {}
    recent_revenue = recent.get("total_revenue", 0)
    recent_count = recent.get("sales_count", 0)
    all_products = recent.get("top_products", [])
    last_purchase = recent.get("last_purchase")

    # Product frequency
    product_freq: Dict[str, int] = {}
    for p in all_products:
        if p:
            product_freq[p] = product_freq.get(p, 0) + 1
    top_products = sorted(product_freq.items(), key=lambda x: x[1], reverse=True)[:5]

    days_since_last = None
    if last_purchase:
        lp = last_purchase if isinstance(last_purchase, datetime) else datetime.fromisoformat(str(last_purchase).replace("Z", "+00:00"))
        days_since_last = (datetime.now(timezone.utc) - lp).days

    lang_map = {"fr": "français", "en": "English", "ar": "العربية", "es": "español", "pt": "português"}
    lang_instr = f"Réponds en {lang_map.get(lang, 'français')}."

    prompt = f"""{lang_instr}
Tu es un assistant CRM expert. Génère un résumé client concis et actionnable (4-6 phrases max).
Inclus : profil comportemental, fidélité, risques, 1-2 recommandations commerciales concrètes.
Ne répète pas les chiffres bruts — interprète-les.

CLIENT : {customer.get('name', 'Inconnu')} | Tier : {tier} | Points fidélité : {loyalty_points}
ACHATS 90j : {recent_count} visites · {recent_revenue:.0f} de CA · Panier moyen {(recent_revenue/recent_count if recent_count else 0):.0f}
HISTORIQUE : {visit_count} visites total · {total_spent_lifetime:.0f} lifetime
DERNIÈRE VISITE : {f"il y a {days_since_last} jours" if days_since_last is not None else "inconnue"}
DETTE ACTUELLE : {current_debt:.0f}
TOP PRODUITS : {", ".join(f"{p[0]} (x{p[1]})" for p in top_products) or "N/A"}
NOTES : {notes or "Aucune"}
"""

    try:
        genai.configure(api_key=api_key)
        model = genai.GenerativeModel("gemini-2.0-flash")
        response = model.generate_content(prompt)
        summary_text = response.text.strip()
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"Erreur IA : {str(e)}")

    _track_ai_usage_lite(owner_id, "customer_summary", plan)

    result = {
        "customer_id": customer_id,
        "customer_name": customer.get("name"),
        "summary": summary_text,
        "stats": {
            "recent_revenue": round(recent_revenue, 2),
            "recent_count": recent_count,
            "days_since_last": days_since_last,
            "top_products": [p[0] for p in top_products],
            "current_debt": current_debt,
            "tier": tier,
        },
        "lang": lang,
        "store_id": effective_store_id,
    }

    _ai_cache[cache_key] = result
    _ai_cache_ts[cache_key] = datetime.now(timezone.utc).timestamp()
    return result


# ===================== END VAGUE 7 (customer summary) =====================

# ===================== VAGUE 7 — generate customer message =====================

@api_router.post("/ai/generate-customer-message")
async def generate_customer_message(body: dict = Body(...), user: User = Depends(require_operational_access)):
    """Generate a personalized marketing/communication message for a customer via Gemini."""
    owner_id = get_owner_id(user)
    plan = _resolve_ai_plan(user)
    if plan not in ("enterprise",):
        raise HTTPException(status_code=403, detail="Enterprise plan required")

    customer_id = body.get("customer_id", "")
    message_type = body.get("message_type", "promo")  # promo | reengagement | debt_reminder | birthday | custom
    context = body.get("context", "")  # optional extra instructions
    lang = body.get("lang", "fr")

    if not customer_id:
        raise HTTPException(status_code=400, detail="customer_id required")

    _check_ai_gate(owner_id, "customer_message", plan)

    # Fetch customer
    effective_store_id = user.active_store_id
    customer_query = apply_accessible_store_scope({"customer_id": customer_id, "user_id": owner_id}, user, effective_store_id)
    customer = await db.customers.find_one(customer_query, {"_id": 0})
    if not customer:
        raise HTTPException(status_code=404, detail="Customer not found")

    customer_name = customer.get("name", "Client")
    tier = customer.get("tier", "bronze")
    current_debt = round(customer.get("current_debt", 0), 2)
    loyalty_points = customer.get("loyalty_points", 0)
    total_spent = round(customer.get("total_spent", 0), 2)

    # Fetch recent purchases (last 90 days)
    since = datetime.now(timezone.utc) - timedelta(days=90)
    sales_query = apply_accessible_store_scope(
        {"user_id": owner_id, "customer_id": customer_id, "created_at": {"$gte": since}},
        user,
        effective_store_id,
    )
    sales_query = apply_completed_sales_scope(sales_query)
    sales = await db.sales.find(sales_query).sort("created_at", -1).limit(10).to_list(None)

    top_products = []
    for s in sales:
        for item in (s.get("items") or []):
            name = item.get("name") or item.get("product_name")
            if name and name not in top_products:
                top_products.append(name)
            if len(top_products) >= 3:
                break
        if len(top_products) >= 3:
            break

    last_purchase_date = sales[0].get("created_at") if sales else None
    days_inactive = None
    if last_purchase_date:
        try:
            lp = last_purchase_date if isinstance(last_purchase_date, datetime) else datetime.fromisoformat(str(last_purchase_date).replace("Z", "+00:00"))
            if lp.tzinfo is None:
                lp = lp.replace(tzinfo=timezone.utc)
            days_inactive = (datetime.now(timezone.utc) - lp).days
        except Exception:
            pass

    # Build type-specific instructions
    type_instructions = {
        "promo": "Write a friendly promotional message announcing an exclusive offer or discount for loyal customers.",
        "reengagement": "Write a warm re-engagement message to invite the customer back, mentioning it has been a while.",
        "debt_reminder": "Write a polite, non-aggressive reminder about an outstanding balance, keeping a positive tone.",
        "birthday": "Write a warm birthday greeting with a special loyalty reward mention.",
        "custom": f"Write a message following these instructions: {context}" if context else "Write a friendly personalized message.",
    }.get(message_type, "Write a friendly personalized message.")

    lang_names = {"fr": "French", "en": "English", "es": "Spanish", "ar": "Arabic", "pt": "Portuguese"}
    lang_name = lang_names.get(lang, "French")

    prompt = f"""You are a marketing assistant for a retail store. Generate a SHORT, warm, personalized message (2-4 sentences max) to send to a customer via WhatsApp or SMS.

Customer profile:
- Name: {customer_name}
- Loyalty tier: {tier}
- Total spent: {total_spent}
- Loyalty points: {loyalty_points}
- Current debt: {current_debt}
- Days since last purchase: {days_inactive if days_inactive is not None else 'unknown'}
- Favorite products: {', '.join(top_products) if top_products else 'unknown'}

Task: {type_instructions}
{"Additional context: " + context if context and message_type != "custom" else ""}

Rules:
- Write in {lang_name}
- Use the customer's first name if possible (use "{customer_name.split()[0] if customer_name else 'cher client'}")
- Keep it SHORT (2-4 sentences), warm, and natural — like a real human message
- Do NOT use generic templates. Make it feel personal.
- Output ONLY the message text, no quotes, no labels.
"""

    import google.generativeai as genai
    api_key = os.environ.get("GEMINI_API_KEY", "")
    if not api_key:
        raise HTTPException(status_code=503, detail="AI service not configured")

    genai.configure(api_key=api_key)
    model = genai.GenerativeModel("gemini-2.0-flash")
    response = model.generate_content(prompt)
    message_text = response.text.strip() if response and response.text else ""

    if not message_text:
        raise HTTPException(status_code=500, detail="AI generation failed")

    _track_ai_usage_lite(owner_id, "customer_message", plan)

    return {
        "customer_id": customer_id,
        "customer_name": customer_name,
        "message_type": message_type,
        "message": message_text,
        "lang": lang,
        "store_id": effective_store_id,
    }


# ===================== END VAGUE 7 (generate customer message) =====================

# ===================== VAGUE 7 — natural language query =====================

# Intent patterns: (regex, intent_key)
_NL_PATTERNS = [
    # Revenue / CA
    (r"(chiffre|ca|revenue|combien.*vendu|ventes?\s*(du\s*)?(jour|mois|semaine|total)|montant.*vente)", "revenue"),
    # Top products
    (r"(top|meilleur|plus\s+vendu|mieux.*vendu|best.*sell|produit.*perform|perform.*produit)", "top_products"),
    # Low stock / ruptures
    (r"(stock\s*bas|rupture|manque|bient.t\s*fini|presque\s*vide|stock\s*faible|r.approvisionn)", "low_stock"),
    # Deadstock / dormants
    (r"(dorm|ne\s*se\s*vend\s*pas|invendu|bloqu|immobilis|sans\s*mouvement)", "deadstock"),
    # Customers with debt
    (r"(client.*doit|dette.*client|d.biteur|d.b.*client|qui\s*doit|cr.dit.*client)", "debt_customers"),
    # Expenses
    (r"(d.pense|charge|co.t|sortie.*argent|d.caiss)", "expenses"),
    # Orders / suppliers
    (r"(commande|fournisseur|livraison|approvisionnement)", "orders"),
    # Margin / profit
    (r"(marge|b.n.fice|profit|gain|r.sultat|rentable)", "margin"),
    # Alerts
    (r"(alerte|alert|notification|probl.me)", "alerts"),
    # Inventory count
    (r"(inventaire|comptage|stock\s*physique)", "inventory"),
]

import re as _re

def _parse_nl_intent(query: str):
    """Returns (intent, period_days) from natural language query."""
    q = query.lower()
    # Extract period
    period_days = 30  # default
    if _re.search(r"(aujourd.hui|ce\s*jour|today)", q):
        period_days = 1
    elif _re.search(r"(cette?\s*semaine|7\s*jour|week)", q):
        period_days = 7
    elif _re.search(r"(ce\s*mois|30\s*jour|month)", q):
        period_days = 30
    elif _re.search(r"(3\s*mois|90\s*jour|trimestre|quarter)", q):
        period_days = 90
    elif _re.search(r"(6\s*mois|180\s*jour)", q):
        period_days = 180
    elif _re.search(r"(an|ann.e|year|365\s*jour)", q):
        period_days = 365

    for pattern, intent in _NL_PATTERNS:
        if _re.search(pattern, q):
            return intent, period_days
    return None, period_days


async def _execute_nl_intent(intent: str, period_days: int, owner_id: str, user: User, store_id: Optional[str] = None) -> dict:
    """Execute MongoDB query for resolved intent."""
    effective_store_id = store_id or user.active_store_id
    since = datetime.now(timezone.utc) - timedelta(days=period_days)

    if intent == "revenue":
        sales_match = apply_accessible_store_scope({"user_id": owner_id, "created_at": {"$gte": since}}, user, effective_store_id)
        sales_match = apply_completed_sales_scope(sales_match)
        pipeline = [
            {"$match": sales_match},
            {"$group": {"_id": None, "total": {"$sum": "$total_amount"}, "count": {"$sum": 1}}},
        ]
        rows = await db.sales.aggregate(pipeline).to_list(None)
        total = rows[0]["total"] if rows else 0
        count = rows[0]["count"] if rows else 0
        return {
            "intent": "revenue",
            "answer": f"Chiffre d'affaires sur {period_days} jour(s) : {round(total, 2)}",
            "data": [{"label": "Chiffre d'affaires", "value": round(total, 2)}, {"label": "Nombre de ventes", "value": count}],
        }

    elif intent == "top_products":
        sales_match = apply_accessible_store_scope({"user_id": owner_id, "created_at": {"$gte": since}}, user, effective_store_id)
        sales_match = apply_completed_sales_scope(sales_match)
        pipeline = [
            {"$match": sales_match},
            {"$unwind": "$items"},
            {"$group": {"_id": {"$ifNull": ["$items.name", "$items.product_name"]}, "qty": {"$sum": "$items.quantity"}, "revenue": {"$sum": {"$multiply": ["$items.quantity", "$items.unit_price"]}}}},
            {"$sort": {"qty": -1}},
            {"$limit": 10},
        ]
        rows = await db.sales.aggregate(pipeline).to_list(None)
        return {
            "intent": "top_products",
            "answer": f"Top produits vendus sur {period_days} jour(s)",
            "data": [{"label": r["_id"] or "?", "value": r["qty"], "revenue": round(r.get("revenue", 0), 2)} for r in rows if r.get("_id")],
        }

    elif intent == "low_stock":
        product_query = apply_accessible_store_scope({"user_id": owner_id}, user, effective_store_id)
        products = await db.products.find(product_query).limit(200).to_list(None)
        low_stock = [
            p for p in products
            if (p.get("quantity", p.get("stock_quantity", 0)) or 0)
            <= (p.get("alert_threshold", p.get("min_stock", 0)) or 0)
        ][:20]
        return {
            "intent": "low_stock",
            "answer": f"{len(low_stock)} produit(s) en stock bas ou rupture",
            "data": [{"label": p.get("name", "?"), "value": p.get("quantity", p.get("stock_quantity", 0)), "threshold": p.get("alert_threshold", p.get("min_stock", 0))} for p in low_stock],
        }

    elif intent == "deadstock":
        since_ds = datetime.now(timezone.utc) - timedelta(days=60)
        sales_match = apply_accessible_store_scope({"user_id": owner_id, "created_at": {"$gte": since_ds}}, user, effective_store_id)
        sales_match = apply_completed_sales_scope(sales_match)
        sold_ids_cursor = db.sales.aggregate([
            {"$match": sales_match},
            {"$unwind": "$items"},
            {"$group": {"_id": "$items.product_id"}},
        ])
        sold_ids = {r["_id"] async for r in sold_ids_cursor if r.get("_id")}
        product_query = apply_accessible_store_scope({"user_id": owner_id}, user, effective_store_id)
        products = await db.products.find(product_query).limit(200).to_list(None)
        dormant = [p for p in products if p.get("product_id") not in sold_ids and (p.get("quantity", p.get("stock_quantity", 0)) or 0) > 0]
        dormant.sort(key=lambda p: (p.get("quantity", p.get("stock_quantity", 0)) or 0) * (p.get("price", p.get("selling_price", 0)) or 0), reverse=True)
        return {
            "intent": "deadstock",
            "answer": f"{len(dormant)} produit(s) sans vente depuis 60 jours",
            "data": [{"label": p.get("name", "?"), "value": p.get("quantity", p.get("stock_quantity", 0)), "stock_value": round((p.get("quantity", p.get("stock_quantity", 0)) or 0) * (p.get("price", p.get("selling_price", 0)) or 0), 2)} for p in dormant[:15]],
        }

    elif intent == "debt_customers":
        customer_query = apply_accessible_store_scope({"user_id": owner_id, "current_debt": {"$gt": 0}}, user, effective_store_id)
        customers = await db.customers.find(customer_query).sort("current_debt", -1).limit(15).to_list(None)
        total_debt = sum(c.get("current_debt", 0) for c in customers)
        return {
            "intent": "debt_customers",
            "answer": f"{len(customers)} client(s) avec dette — total {round(total_debt, 2)}",
            "data": [{"label": c.get("name", "?"), "value": round(c.get("current_debt", 0), 2)} for c in customers],
        }

    elif intent == "expenses":
        expense_query = apply_accessible_store_scope({"user_id": owner_id, "created_at": {"$gte": since}}, user, effective_store_id)
        pipeline = [
            {"$match": expense_query},
            {"$group": {"_id": "$category", "total": {"$sum": "$amount"}, "count": {"$sum": 1}}},
            {"$sort": {"total": -1}},
        ]
        rows = await db.expenses.aggregate(pipeline).to_list(None)
        grand_total = sum(r["total"] for r in rows)
        return {
            "intent": "expenses",
            "answer": f"Dépenses sur {period_days} jour(s) : {round(grand_total, 2)}",
            "data": [{"label": r["_id"] or "Autre", "value": round(r["total"], 2), "count": r["count"]} for r in rows],
        }

    elif intent == "orders":
        orders_query = apply_accessible_store_scope({"user_id": owner_id}, user, effective_store_id)
        orders = await db.orders.find(orders_query).sort("created_at", -1).limit(10).to_list(None)
        return {
            "intent": "orders",
            "answer": f"{len(orders)} commande(s) récente(s)",
            "data": [{"label": o.get("supplier_name", "?"), "value": round(o.get("total_amount", 0), 2), "status": o.get("status", "?")} for o in orders],
        }

    elif intent == "margin":
        sales_match = apply_accessible_store_scope({"user_id": owner_id, "created_at": {"$gte": since}}, user, effective_store_id)
        sales_match = apply_completed_sales_scope(sales_match)
        pipeline = [
            {"$match": sales_match},
            {"$unwind": "$items"},
            {"$group": {"_id": None,
                "revenue": {"$sum": {"$multiply": ["$items.quantity", "$items.unit_price"]}},
                "cost": {"$sum": {"$multiply": ["$items.quantity", {"$ifNull": ["$items.purchase_price", 0]}]}}}},
        ]
        rows = await db.sales.aggregate(pipeline).to_list(None)
        revenue = rows[0]["revenue"] if rows else 0
        cost = rows[0]["cost"] if rows else 0
        margin = revenue - cost
        margin_pct = round(margin / revenue * 100, 1) if revenue else 0
        return {
            "intent": "margin",
            "answer": f"Marge brute sur {period_days} jour(s) : {round(margin, 2)} ({margin_pct}%)",
            "data": [{"label": "CA", "value": round(revenue, 2)}, {"label": "Coût", "value": round(cost, 2)}, {"label": "Marge", "value": round(margin, 2)}, {"label": "Marge %", "value": margin_pct}],
        }

    elif intent == "alerts":
        alert_query = apply_accessible_store_scope({"user_id": owner_id, "is_read": False}, user, effective_store_id)
        alerts = await db.alerts.find(alert_query).sort("created_at", -1).limit(10).to_list(None)
        return {
            "intent": "alerts",
            "answer": f"{len(alerts)} alerte(s) non lue(s)",
            "data": [{"label": a.get("message", a.get("title", "?")), "value": a.get("type", "info")} for a in alerts],
        }

    elif intent == "inventory":
        product_query = apply_accessible_store_scope({"user_id": owner_id}, user, effective_store_id)
        products = await db.products.find(product_query).limit(20).to_list(None)
        total_value = sum((p.get("quantity", p.get("stock_quantity", 0)) or 0) * (p.get("price", p.get("selling_price", 0)) or 0) for p in products)
        return {
            "intent": "inventory",
            "answer": f"Valeur stock estimée : {round(total_value, 2)} ({len(products)} produits)",
            "data": [{"label": p.get("name", "?"), "value": p.get("quantity", p.get("stock_quantity", 0))} for p in products[:15]],
        }

    return {"intent": "unknown", "answer": "Aucun résultat trouvé.", "data": []}


@api_router.post("/ai/natural-query")
async def natural_language_query(body: dict = Body(...), user: User = Depends(require_operational_access)):
    """Parse a natural language query and return structured business data."""
    owner_id = get_owner_id(user)
    plan = _resolve_ai_plan(user)
    if plan not in ("enterprise",):
        raise HTTPException(status_code=403, detail="Enterprise plan required")

    query = (body.get("query") or "").strip()
    store_id = body.get("store_id") or user.active_store_id
    if store_id:
        ensure_user_store_access(user, store_id)
    if not query:
        raise HTTPException(status_code=400, detail="query required")

    _check_ai_gate(owner_id, "natural_query", plan)

    # Step 1: try regex parser
    intent, period_days = _parse_nl_intent(query)

    # Step 2: Gemini fallback if no intent found
    if intent is None:
        try:
            import google.generativeai as genai
            api_key = os.environ.get("GEMINI_API_KEY", "")
            if api_key:
                genai.configure(api_key=api_key)
                model = genai.GenerativeModel("gemini-2.0-flash")
                prompt = f"""You are a business data assistant. Classify this query into ONE of these intents:
revenue, top_products, low_stock, deadstock, debt_customers, expenses, orders, margin, alerts, inventory, unknown

Also extract the time period in days (default 30 if not specified).

Query: "{query}"

Reply with JSON only, exactly: {{"intent": "...", "period_days": N}}"""
                resp = model.generate_content(prompt)
                if resp and resp.text:
                    import json as _json
                    text = resp.text.strip().strip("```json").strip("```").strip()
                    parsed = _json.loads(text)
                    intent = parsed.get("intent", "unknown")
                    period_days = int(parsed.get("period_days", 30))
        except Exception:
            intent = "unknown"

    if not intent or intent == "unknown":
        return {"query": query, "intent": "unknown", "answer": "Je n'ai pas compris cette question. Essayez : 'top produits ce mois', 'stock bas', 'dettes clients', 'dépenses', etc.", "data": [], "resolved_by": "none"}

    resolved_by = "regex" if _parse_nl_intent(query)[0] else "llm"
    result = await _execute_nl_intent(intent, period_days, owner_id, user, store_id)
    result["query"] = query
    result["period_days"] = period_days
    result["resolved_by"] = resolved_by
    result["store_id"] = store_id

    _track_ai_usage_lite(owner_id, "natural_query", plan)
    return result


# ===================== END VAGUE 7 (natural query) =====================

# ===================== VAGUE 7 — voice to cart =====================

def _match_products_from_text(text: str, products: list) -> list:
    """Match product names from transcribed text. Returns list of {product, qty}."""
    text_lower = text.lower()
    results = []
    # Sort by name length descending (longest match first to avoid partial collisions)
    sorted_products = sorted(products, key=lambda p: len(p.get("name", "")), reverse=True)

    import re as _re
    for product in sorted_products:
        name = (product.get("name") or "").lower().strip()
        if not name or len(name) < 2:
            continue

        # Look for the product name in the text
        # Also look for common quantity patterns before/after the name
        # e.g. "2 coca", "coca fois 3", "trois bouteilles de coca"
        pattern = _re.escape(name)
        match = _re.search(pattern, text_lower)
        if not match:
            continue

        # Try to extract quantity near the match
        qty = 1
        start = match.start()
        end = match.end()
        context_before = text_lower[max(0, start - 20):start]
        context_after = text_lower[end:min(len(text_lower), end + 20)]

        # Number words
        word_to_num = {
            "un": 1, "une": 1, "one": 1, "uno": 1,
            "deux": 2, "two": 2, "dos": 2, "deux": 2,
            "trois": 3, "three": 3, "tres": 3,
            "quatre": 4, "four": 4, "cuatro": 4,
            "cinq": 5, "five": 5, "cinco": 5,
            "six": 6, "sept": 7, "huit": 8, "neuf": 9, "dix": 10,
        }

        # Numeric digit before name
        num_before = _re.search(r'(\d+)\s*$', context_before)
        num_after = _re.search(r'^\s*(?:fois|x|×)\s*(\d+)', context_after)
        word_before = None
        for word, val in word_to_num.items():
            if _re.search(r'\b' + word + r'\s*$', context_before):
                word_before = val
                break

        if num_before:
            qty = int(num_before.group(1))
        elif num_after:
            qty = int(num_after.group(1))
        elif word_before:
            qty = word_before

        qty = max(1, min(qty, 999))
        results.append({"product": product, "qty": qty})

    return results


@api_router.post("/ai/voice-to-cart")
async def voice_to_cart(body: dict = Body(...), user: User = Depends(require_operational_access)):
    """Transcribe voice audio and match products to build a cart."""
    owner_id = get_owner_id(user)
    plan = _resolve_ai_plan(user)

    audio_base64 = body.get("audio_base64", "")
    lang = body.get("lang", "fr")
    store_id = body.get("store_id")

    if not audio_base64:
        raise HTTPException(status_code=400, detail="audio_base64 required")

    _check_ai_gate(owner_id, "voice_to_cart", plan)

    # Transcribe audio with Gemini
    import google.generativeai as genai
    api_key = os.environ.get("GEMINI_API_KEY", "")
    if not api_key:
        raise HTTPException(status_code=503, detail="AI service not configured")

    genai.configure(api_key=api_key)
    model = genai.GenerativeModel("gemini-2.0-flash")

    lang_names = {"fr": "French", "en": "English", "es": "Spanish", "ar": "Arabic", "pt": "Portuguese"}
    lang_name = lang_names.get(lang, "French")

    try:
        import base64 as _b64
        audio_bytes = _b64.b64decode(audio_base64)
        audio_part = {"inline_data": {"mime_type": "audio/m4a", "data": audio_base64}}
        transcription_prompt = f"Transcribe exactly what is said in this audio in {lang_name}. Output only the transcription, no comments."
        response = model.generate_content([transcription_prompt, audio_part])
        transcription = (response.text or "").strip() if response else ""
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"Transcription failed: {str(e)}")

    if not transcription:
        return {"transcription": "", "items": [], "unmatched": True}

    # Fetch products catalogue
    store_filter = {"store_id": store_id} if store_id else {}
    products = await db.products.find(
        {"owner_id": owner_id, **store_filter, "quantity": {"$gt": 0}}
    ).limit(500).to_list(None)

    # Match products in transcription
    matched = _match_products_from_text(transcription, products)

    items = []
    for m in matched:
        p = m["product"]
        items.append({
            "product_id": p.get("product_id"),
            "name": p.get("name"),
            "quantity": m["qty"],
            "unit_price": p.get("price", 0),
            "stock_available": p.get("quantity", 0),
            "barcode": p.get("barcode"),
        })

    _track_ai_usage_lite(owner_id, "voice_to_cart", plan)

    return {
        "transcription": transcription,
        "items": items,
        "matched_count": len(items),
        "lang": lang,
    }


# ===================== END VAGUE 7 (voice to cart) =====================

@admin_router.get("/disputes")
async def admin_list_disputes(status: Optional[str] = None, type: Optional[str] = None, skip: int = 0, limit: int = 50):
    """List all disputes with optional filters"""
    query = {}
    if status: query["status"] = status
    if type: query["type"] = type
    disputes = await db.disputes.find(query, {"_id": 0}).sort("created_at", -1).skip(skip).limit(limit).to_list(limit)
    total = await db.disputes.count_documents(query)
    return {"items": disputes, "total": total}

@admin_router.post("/disputes/{dispute_id}/reply")
async def admin_reply_dispute(dispute_id: str, reply: SupportReply, user: User = Depends(require_superadmin)):
    """Reply to a dispute"""
    msg = DisputeMessage(sender_id=user.user_id, sender_name="Admin Stockman", content=reply.content)
    result = await db.disputes.update_one(
        {"dispute_id": dispute_id},
        {"$push": {"messages": msg.model_dump()}, "$set": {"updated_at": datetime.now(timezone.utc)}}
    )
    if result.modified_count == 0:
        raise HTTPException(status_code=404, detail="Litige non trouvé")
    updated = await db.disputes.find_one({"dispute_id": dispute_id}, {"_id": 0})

    # Notify dispute reporter via push + email
    try:
        reporter_id = updated.get("reporter_id")
        dispute_subject = updated.get("subject", "Litige")
        if reporter_id:
            await notification_service.notify_user(
                db, reporter_id,
                f"Réponse à votre litige: {dispute_subject}",
                reply.content[:200],
                {"type": "dispute_reply", "dispute_id": dispute_id}
            )
            reporter_email = updated.get("reporter_email")
            if reporter_email:
                await notification_service.send_email_notification(
                    [reporter_email],
                    f"Stockman — Litige: {dispute_subject}",
                    f"<h3>Réponse de l'équipe Stockman</h3><p>{reply.content}</p><p style='color:#666;font-size:12px;'>Connectez-vous à l'app pour répondre.</p>"
                )
    except Exception as e:
        logger.warning(f"Failed to notify user of dispute reply: {e}")

    return updated

@admin_router.put("/disputes/{dispute_id}/status")
async def admin_update_dispute_status(dispute_id: str, update: DisputeStatusUpdate):
    """Update dispute status"""
    update_fields = {"status": update.status, "updated_at": datetime.now(timezone.utc)}
    if update.resolution: update_fields["resolution"] = update.resolution
    if update.admin_notes: update_fields["admin_notes"] = update.admin_notes
    
    result = await db.disputes.update_one(
        {"dispute_id": dispute_id},
        {"$set": update_fields}
    )
    if result.modified_count == 0:
        raise HTTPException(status_code=404, detail="Litige non trouvé")
    return {"message": f"Litige mis à jour: {update.status}"}

@admin_router.get("/disputes/stats")
async def admin_dispute_stats():
    """Get dispute statistics"""
    total = await db.disputes.count_documents({})
    open_count = await db.disputes.count_documents({"status": "open"})
    investigating = await db.disputes.count_documents({"status": "investigating"})
    resolved = await db.disputes.count_documents({"status": "resolved"})
    rejected = await db.disputes.count_documents({"status": "rejected"})
    
    type_pipeline = [{"$group": {"_id": "$type", "count": {"$sum": 1}}}]
    type_data = await db.disputes.aggregate(type_pipeline).to_list(10)
    by_type = {t["_id"]: t["count"] for t in type_data}
    
    return {
        "total": total,
        "open": open_count,
        "investigating": investigating,
        "resolved": resolved,
        "rejected": rejected,
        "by_type": by_type
    }

