@api_router.post("/products/{product_id}/adjust", response_model=Product)
async def adjust_product_stock(product_id: str, adj_data: StockAdjustmentRequest, user: User = Depends(require_permission("stock", "write"))):
    owner_id = get_owner_id(user)
    product = await db.products.find_one({"product_id": product_id, "user_id": owner_id}, {"_id": 0})
    if not product:
        raise HTTPException(status_code=404, detail="Produit non trouvé")
    
    ensure_scoped_document_access(user, product, detail="Acces refuse pour ce produit")
    product = normalize_product_measurement_fields(product)
    previous_quantity = float(product["quantity"])
    actual_quantity = adj_data.actual_quantity
    diff = actual_quantity - previous_quantity
    
    if diff == 0:
        return _product_response(product) # No change needed
    
    # Update product quantity
    await db.products.update_one(
        {"product_id": product_id, "user_id": owner_id},
        {"$set": {"quantity": actual_quantity, "updated_at": datetime.now(timezone.utc)}}
    )
    
    # Record movement
    movement = StockMovement(
        product_id=product_id,
        product_name=product["name"],
        user_id=user.user_id,
        store_id=user.active_store_id,
        type="in" if diff > 0 else "out",
        quantity=abs(diff),
        reason=adj_data.reason or "Inventaire physique",
        previous_quantity=previous_quantity,
        new_quantity=actual_quantity
    )
    await db.stock_movements.insert_one(movement.model_dump())
    _invalidate_dashboard_ai_caches(owner_id, product.get("store_id") or user.active_store_id)
    
    # Log activity
    await log_activity(
        user=user,
        action="stock_adjustment",
        module="stock",
        description=f"Ajustement d'inventaire pour {product['name']}: {previous_quantity} -> {actual_quantity}",
        details={"product_id": product_id, "previous": previous_quantity, "actual": actual_quantity}
    )

    # Check for alerts
    product["quantity"] = actual_quantity
    normalized_product = normalize_product_measurement_fields(product)
    await check_and_create_alerts(Product(**normalized_product), owner_id, store_id=user.active_store_id)
    
    return Product(**normalized_product)

@api_router.delete("/products/{product_id}")
async def delete_product(product_id: str, user: User = Depends(require_permission("stock", "write"))):
    owner_id = get_owner_id(user)
    product = await db.products.find_one(
        {"product_id": product_id, "user_id": owner_id},
        {"_id": 0, "name": 1, "store_id": 1, "is_active": 1},
    )
    ensure_scoped_document_access(user, product, detail="Acces refuse pour ce produit")
    if not product:
        raise HTTPException(status_code=404, detail="Produit non trouve")
    if product.get("is_active") is False:
        return {"message": "Produit deja supprime"}

    now = datetime.now(timezone.utc)
    result = await db.products.update_one(
        {"product_id": product_id, "user_id": owner_id},
        {"$set": {"is_active": False, "deleted_at": now, "updated_at": now}},
    )
    if result.matched_count == 0:
        raise HTTPException(status_code=404, detail="Produit non trouve")

    _invalidate_dashboard_ai_caches(owner_id, product.get("store_id") or user.active_store_id)
    await log_activity(
        user,
        "product_deleted",
        "stock",
        f"Produit '{product.get('name', product_id)}' supprime",
        {"product_id": product_id},
    )
    return {"message": "Produit supprime"}


@api_router.post("/products/delete-jobs", response_model=ProductDeleteJobResponse)
async def create_product_delete_job(
    data: BulkProductDeleteRequest,
    user: User = Depends(require_permission("stock", "write")),
):
    owner_id = get_owner_id(user)
    requested_ids = list(dict.fromkeys([product_id for product_id in data.product_ids if product_id]))
    if not requested_ids:
        raise HTTPException(status_code=400, detail="Aucun produit selectionne")

    query = {
        "user_id": owner_id,
        "product_id": {"$in": requested_ids},
    }
    query = apply_store_scope(query, user)
    products = await db.products.find(
        query,
        {"_id": 0, "product_id": 1, "name": 1, "store_id": 1, "is_active": 1},
    ).to_list(len(requested_ids))

    found_ids = {product["product_id"] for product in products}
    active_products = [product for product in products if product.get("is_active") is not False]
    active_ids = [product["product_id"] for product in active_products]
    inactive_ids = [product["product_id"] for product in products if product.get("is_active") is False]
    missing_ids = [product_id for product_id in requested_ids if product_id not in found_ids]

    initial_errors = [
        {"product_id": product_id, "message": "Produit introuvable"}
        for product_id in missing_ids
    ] + [
        {"product_id": product_id, "message": "Produit deja supprime"}
        for product_id in inactive_ids
    ]

    if not active_ids:
        raise HTTPException(status_code=400, detail="Aucun produit actif a supprimer")

    now = datetime.now(timezone.utc)
    job = {
        "job_id": f"prod_delete_{uuid.uuid4().hex[:12]}",
        "user_id": owner_id,
        "store_id": user.active_store_id,
        "product_ids": active_ids,
        "store_ids": list({product.get("store_id") for product in active_products if product.get("store_id")}),
        "status": "queued",
        "requested_count": len(requested_ids),
        "total_products": len(active_ids),
        "processed_products": 0,
        "deleted_count": 0,
        "error_count": len(initial_errors),
        "errors": initial_errors,
        "last_error": None,
        "created_at": now,
        "updated_at": now,
        "started_at": None,
        "completed_at": None,
    }
    await db.product_delete_jobs.insert_one(job)
    schedule_product_delete_job(job["job_id"], owner_id)
    return ProductDeleteJobResponse(**serialize_product_delete_job(job))


@api_router.get("/products/delete-jobs/active")
async def get_active_product_delete_job(current_user: User = Depends(require_auth)):
    user_id = get_owner_id(current_user)
    query: Dict[str, Any] = {
        "user_id": user_id,
        "status": {"$in": ["queued", "running"]},
    }
    if current_user.active_store_id:
        query["store_id"] = current_user.active_store_id
    job = await db.product_delete_jobs.find_one(query, sort=[("created_at", -1)])
    if not job:
        return {"job": None}
    if job.get("status") in {"queued", "running"}:
        schedule_product_delete_job(job["job_id"], user_id)
        job = await db.product_delete_jobs.find_one({"job_id": job["job_id"], "user_id": user_id})
    return {"job": serialize_product_delete_job(job)}


@api_router.get("/products/delete-jobs/{job_id}", response_model=ProductDeleteJobResponse)
async def get_product_delete_job_status(job_id: str, current_user: User = Depends(require_auth)):
    user_id = get_owner_id(current_user)
    job = await db.product_delete_jobs.find_one({"job_id": job_id, "user_id": user_id})
    if not job:
        raise HTTPException(status_code=404, detail="Job de suppression introuvable")
    if job.get("status") in {"queued", "running"}:
        schedule_product_delete_job(job["job_id"], user_id)
        job = await db.product_delete_jobs.find_one({"job_id": job_id, "user_id": user_id})
    serialized_job = serialize_product_delete_job(job)
    if not serialized_job:
        raise HTTPException(status_code=404, detail="Job de suppression introuvable")
    return ProductDeleteJobResponse(**serialized_job)


@api_router.post("/products/{product_id}/restore", response_model=Product)
async def restore_product(product_id: str, user: User = Depends(require_permission("stock", "write"))):
    owner_id = get_owner_id(user)
    product = await db.products.find_one(
        {"product_id": product_id, "user_id": owner_id},
        {"_id": 0},
    )
    ensure_scoped_document_access(user, product, detail="Acces refuse pour ce produit")
    if not product:
        raise HTTPException(status_code=404, detail="Produit non trouve")

    if product.get("is_active") is not False:
        return _product_response_for_user(user, product)

    now = datetime.now(timezone.utc)
    await db.products.update_one(
        {"product_id": product_id, "user_id": owner_id},
        {"$set": {"is_active": True, "deleted_at": None, "updated_at": now}},
    )

    restored = await db.products.find_one({"product_id": product_id, "user_id": owner_id}, {"_id": 0})
    if not restored:
        raise HTTPException(status_code=404, detail="Produit non trouve")

    _invalidate_dashboard_ai_caches(owner_id, restored.get("store_id") or user.active_store_id)
    await log_activity(
        user,
        "product_restored",
        "stock",
        f"Produit '{restored.get('name', product_id)}' restaure",
        {"product_id": product_id},
    )
    return _product_response_for_user(user, restored)


@api_router.delete("/products/{product_id}/permanent")
async def permanently_delete_product(product_id: str, user: User = Depends(require_permission("stock", "write"))):
    owner_id = get_owner_id(user)
    product = await db.products.find_one(
        {"product_id": product_id, "user_id": owner_id},
        {"_id": 0, "name": 1, "store_id": 1, "is_active": 1},
    )
    ensure_scoped_document_access(user, product, detail="Acces refuse pour ce produit")
    if not product:
        raise HTTPException(status_code=404, detail="Produit non trouve")
    if product.get("is_active", True):
        raise HTTPException(status_code=400, detail="Le produit doit etre dans la corbeille avant suppression definitive")

    result = await db.products.delete_one({"product_id": product_id, "user_id": owner_id})
    if result.deleted_count == 0:
        raise HTTPException(status_code=404, detail="Produit non trouve")

    _invalidate_dashboard_ai_caches(owner_id, product.get("store_id") or user.active_store_id)
    await log_activity(
        user,
        "product_deleted_permanently",
        "stock",
        f"Produit '{product.get('name', product_id)}' supprime definitivement",
        {"product_id": product_id},
    )
    return {"message": "Produit supprime definitivement"}

# ===================== STOCK MOVEMENT ROUTES =====================

@api_router.post("/stock/movement", response_model=StockMovement)
async def create_stock_movement(mov_data: StockMovementCreate, user: User = Depends(require_permission("stock", "write"))):
    owner_id = get_owner_id(user)
    product_query = {"product_id": mov_data.product_id, "user_id": owner_id}
    product_query = apply_store_scope(product_query, user)
    product = await db.products.find_one(product_query, {"_id": 0})
    if not product:
        raise HTTPException(status_code=404, detail="Produit non trouvé")

    ensure_scoped_document_access(user, product, detail="Acces refuse pour ce produit")
    previous_quantity = product["quantity"]

    # Handle Batch Sync
    if mov_data.type == "in":
        new_quantity = round_quantity(previous_quantity + mov_data.quantity)
        if mov_data.batch_id:
            await db.batches.update_one(
                {"batch_id": mov_data.batch_id, "user_id": owner_id},
                {"$inc": {"quantity": mov_data.quantity}, "$set": {"updated_at": datetime.now(timezone.utc)}}
            )
        # Atomic increment
        await db.products.update_one(
            {"product_id": mov_data.product_id, "user_id": owner_id, "store_id": product.get("store_id")},
            {"$inc": {"quantity": mov_data.quantity}, "$set": {"updated_at": datetime.now(timezone.utc)}}
        )
    else: # OUT
        # Atomic decrement with floor at 0 — prevents negative stock
        updated_product = await db.products.find_one_and_update(
            {
                "product_id": mov_data.product_id,
                "user_id": owner_id,
                "store_id": product.get("store_id"),
                "quantity": {"$gte": mov_data.quantity},
            },
            {"$inc": {"quantity": -mov_data.quantity}, "$set": {"updated_at": datetime.now(timezone.utc)}},
            return_document=True,
        )
        if not updated_product:
            raise HTTPException(status_code=400, detail=f"Stock insuffisant pour {product.get('name', mov_data.product_id)}")
        new_quantity = round_quantity(updated_product["quantity"])

        # FEFO Logic for Outflows
        if mov_data.batch_id:
            # Specific batch selected
            await db.batches.update_one(
                {"batch_id": mov_data.batch_id, "user_id": owner_id},
                {"$inc": {"quantity": -mov_data.quantity}, "$set": {"updated_at": datetime.now(timezone.utc)}}
            )
        else:
            # Automatic FEFO: Take from oldest expiring batches first
            qty_to_deduct = float(mov_data.quantity)
            active_batches = await db.batches.find(
                {"product_id": mov_data.product_id, "user_id": owner_id, "quantity": {"$gt": 0}},
                {"_id": 0}
            ).sort("expiry_date", 1).to_list(None)

            for b in active_batches:
                if qty_to_deduct <= 0:
                    break

                deduct = min(float(b["quantity"]), qty_to_deduct)
                await db.batches.update_one(
                    {"batch_id": b["batch_id"]},
                    {"$inc": {"quantity": -deduct}, "$set": {"updated_at": datetime.now(timezone.utc)}}
                )
                qty_to_deduct -= deduct
    
    # Create movement record
    movement = StockMovement(
        product_id=mov_data.product_id,
        product_name=product["name"],
        user_id=owner_id,
        store_id=product.get("store_id") or user.active_store_id,
        type=mov_data.type,
        quantity=mov_data.quantity,
        reason=mov_data.reason,
        batch_id=mov_data.batch_id,
        previous_quantity=previous_quantity,
        new_quantity=new_quantity
    )
    await db.stock_movements.insert_one(movement.model_dump())
    _invalidate_dashboard_ai_caches(owner_id, product.get("store_id") or user.active_store_id)

    # Log activity
    await log_activity(
        user=user,
        action="stock_movement",
        module="stock",
        description=f"{'Entrée' if mov_data.type == 'in' else 'Sortie'} de {format_quantity(mov_data.quantity, product.get('unit', 'unités'))} pour {product['name']}",
        details={"product_id": mov_data.product_id, "type": mov_data.type, "quantity": mov_data.quantity}
    )

    # Check for alerts
    product["quantity"] = new_quantity
    await check_and_create_alerts(_product_response(product), owner_id, store_id=product.get("store_id") or user.active_store_id)

    return movement

@api_router.post("/stock/movement/{movement_id}/reverse", response_model=StockMovement)
async def reverse_stock_movement(movement_id: str, user: User = Depends(require_permission("stock", "write"))):
    """Create a reverse movement to undo a previous stock movement."""
    ensure_subscription_write_allowed(user)
    owner_id = get_owner_id(user)

    original = await db.stock_movements.find_one({"movement_id": movement_id, "user_id": owner_id})
    if not original:
        raise HTTPException(status_code=404, detail="Mouvement non trouvé")

    # Check not already reversed
    already_reversed = await db.stock_movements.find_one({
        "user_id": owner_id,
        "reason": {"$regex": f"^Annulation de {movement_id}"},
    })
    if already_reversed:
        raise HTTPException(status_code=400, detail="Ce mouvement a déjà été annulé")

    reverse_type = "out" if original["type"] == "in" else "in"
    reverse_reason = f"Annulation de {movement_id}" + (f" ({original.get('reason', '')})" if original.get("reason") else "")

    # Create the reverse movement through the existing endpoint logic
    reverse_movement = await create_stock_movement(
        StockMovementCreate(
            product_id=original["product_id"],
            type=reverse_type,
            quantity=original["quantity"],
            reason=reverse_reason,
            batch_id=original.get("batch_id"),
        ),
        user,
    )

    await log_activity(
        user=user,
        action="stock_movement_reversed",
        module="stock",
        description=f"Mouvement {movement_id} annulé ({original['type']} {original['quantity']}x {original.get('product_name', '')})",
        details={"original_movement_id": movement_id, "reverse_movement_id": reverse_movement.movement_id},
    )

    return reverse_movement

