def get_fuzzy_regex(q: str):
    """Generate a fuzzy regex that allows characters to be separated by other characters"""
    if not q: return None
    # Escape special characters and join with .* for fuzzy matching
    chars = [re.escape(c) for c in q]
    return ".*".join(chars)

@api_router.get("/marketplace/suppliers")
async def search_marketplace_suppliers(
    user: User = Depends(require_auth),
    q: Optional[str] = None,
    category: Optional[str] = None,
    city: Optional[str] = None,
    min_rating: Optional[float] = None,
    verified_only: Optional[bool] = None,
    country_code: Optional[str] = None
):
    filters: List[Dict[str, Any]] = []

    if country_code:
        cc = country_code.upper().strip()
        supplier_users = await db.users.find(
            {"role": "supplier", "country_code": cc},
            {"_id": 0, "user_id": 1}
        ).to_list(3000)
        supplier_ids = [u.get("user_id") for u in supplier_users if u.get("user_id")]
        if not supplier_ids:
            return []
        filters.append({"user_id": {"$in": supplier_ids}})

    if q:
        fuzzy_q = get_fuzzy_regex(q)
        q_regex = {"$regex": fuzzy_q, "$options": "i"}
        catalog_supplier_ids = await db.catalog_products.distinct(
            "supplier_user_id",
            {
                **published_catalog_query(),
                "$and": [
                    {
                        "$or": [
                            {"name": q_regex},
                            {"description": q_regex},
                            {"category": q_regex},
                            {"subcategory": q_regex},
                        ]
                    }
                ],
            },
        )
        q_or_filters: List[Dict[str, Any]] = [
            {"company_name": q_regex},
            {"description": q_regex},
            {"city": q_regex},
            {"categories": {"$elemMatch": q_regex}},
        ]
        if catalog_supplier_ids:
            q_or_filters.append({"user_id": {"$in": catalog_supplier_ids}})
        filters.append({"$or": q_or_filters})

    if category:
        cat_regex = {"$regex": safe_regex(category), "$options": "i"}
        category_supplier_ids = await db.catalog_products.distinct(
            "supplier_user_id",
            {
                **published_catalog_query(),
                "$and": [
                    {
                        "$or": [
                            {"category": cat_regex},
                            {"subcategory": cat_regex},
                        ]
                    }
                ],
            },
        )
        cat_or_filters: List[Dict[str, Any]] = [
            {"categories": {"$elemMatch": cat_regex}},
        ]
        if category_supplier_ids:
            cat_or_filters.append({"user_id": {"$in": category_supplier_ids}})
        filters.append({"$or": cat_or_filters})

    if city:
        filters.append({"city": {"$regex": safe_regex(city), "$options": "i"}})
    if min_rating is not None:
        filters.append({"rating_average": {"$gte": min_rating}})
    if verified_only:
        filters.append({"is_verified": True})

    query: Dict[str, Any] = {"$and": filters} if filters else {}
    profiles = await db.supplier_profiles.find(query, {"_id": 0}).sort("rating_average", -1).to_list(50)

    # Enrich with catalog count
    for profile in profiles:
        catalog_count = await db.catalog_products.count_documents(
            published_catalog_query({"supplier_user_id": profile["user_id"]})
        )
        profile["catalog_count"] = catalog_count

    return profiles

@api_router.get("/marketplace/suppliers/{supplier_user_id}")
async def get_marketplace_supplier(supplier_user_id: str, user: User = Depends(require_auth)):
    profile = await db.supplier_profiles.find_one({"user_id": supplier_user_id}, {"_id": 0})
    if not profile:
        raise HTTPException(status_code=404, detail="Fournisseur non trouvé")

    catalog = await db.catalog_products.find(
        published_catalog_query({"supplier_user_id": supplier_user_id}),
        {"_id": 0},
    ).to_list(200)
    ratings = await db.supplier_ratings.find({"supplier_user_id": supplier_user_id}, {"_id": 0}).sort("created_at", -1).to_list(20)

    # Get raters names
    rater_ids = [r["shopkeeper_user_id"] for r in ratings]
    raters = await db.users.find({"user_id": {"$in": rater_ids}}, {"_id": 0, "user_id": 1, "name": 1}).to_list(100)
    raters_map = {u["user_id"]: u["name"] for u in raters}
    for r in ratings:
        r["shopkeeper_name"] = raters_map.get(r["shopkeeper_user_id"], "Anonyme")

    return {
        "profile": profile,
        "catalog": catalog,
        "ratings": ratings
    }

@api_router.post("/marketplace/suppliers/{supplier_user_id}/connect", response_model=Supplier)
async def connect_marketplace_supplier(
    supplier_user_id: str,
    user: User = Depends(require_permission("suppliers", "write")),
):
    owner_id = get_owner_id(user)
    existing_supplier = await db.suppliers.find_one(
        {"user_id": owner_id, "linked_user_id": supplier_user_id},
        {"_id": 0},
    )
    if existing_supplier:
        return Supplier(**existing_supplier)

    profile = await db.supplier_profiles.find_one({"user_id": supplier_user_id}, {"_id": 0})
    if not profile:
        raise HTTPException(status_code=404, detail="Fournisseur marketplace non trouvé")

    supplier = Supplier(
        user_id=owner_id,
        store_id=user.active_store_id,
        name=profile.get("company_name") or "Fournisseur marketplace",
        contact_name=profile.get("company_name") or None,
        email=profile.get("email") or None,
        phone=profile.get("phone") or None,
        address=profile.get("address") or None,
        notes=profile.get("description") or None,
        products_supplied=", ".join(profile.get("categories") or []),
        delivery_delay=f"{int(profile.get('average_delivery_days') or 0)} jour(s)" if profile.get("average_delivery_days") is not None else "",
        payment_conditions="À confirmer avec le fournisseur",
    )
    supplier_doc = supplier.model_dump()
    supplier_doc["linked_user_id"] = supplier_user_id
    supplier_doc["source"] = "marketplace"
    supplier_doc["is_connected"] = True
    await db.suppliers.insert_one(supplier_doc)
    return supplier

@api_router.get("/marketplace/search-products")
async def search_marketplace_products(
    user: User = Depends(require_auth),
    q: Optional[str] = None,
    category: Optional[str] = None,
    price_min: Optional[float] = None,
    price_max: Optional[float] = None,
    min_supplier_rating: Optional[float] = None
):
    query: dict = published_catalog_query()
    if q:
        fuzzy_q = get_fuzzy_regex(q)
        query["name"] = {"$regex": fuzzy_q, "$options": "i"}
    if category:
        query["category"] = {"$regex": safe_regex(category), "$options": "i"}
    
    if price_min is not None or price_max is not None:
        price_filter = {}
        if price_min is not None: price_filter["$gte"] = price_min
        if price_max is not None: price_filter["$lte"] = price_max
        query["price"] = price_filter

    # Fetch products
    products = await db.catalog_products.find(query, {"_id": 0}).to_list(100)

    # Enrich with supplier profile info and filter by rating if requested
    supplier_ids = list(set(p["supplier_user_id"] for p in products))
    profiles = await db.supplier_profiles.find({"user_id": {"$in": supplier_ids}}, {"_id": 0}).to_list(100)
    profiles_map = {p["user_id"]: p for p in profiles}

    filtered_products = []
    for product in products:
        sup_profile = profiles_map.get(product["supplier_user_id"])
        rating = sup_profile.get("rating_average", 0) if sup_profile else 0
        
        # Filter by supplier rating
        if min_supplier_rating is not None and rating < min_supplier_rating:
            continue
            
        product["supplier_name"] = sup_profile.get("company_name", "Inconnu") if sup_profile else "Inconnu"
        product["supplier_city"] = sup_profile.get("city", "") if sup_profile else ""
        product["supplier_rating"] = rating
        filtered_products.append(product)

    return filtered_products

