def _user_has_module_access(user: User, *modules: str, level: str = "read") -> bool:
    if user.role in {"admin", "superadmin"} or is_org_admin_user(user):
        return True
    permissions = user.effective_permissions or user.permissions or {}
    accepted_levels = {"read", "write"} if level == "read" else {"write"}
    return any(permissions.get(module) in accepted_levels for module in modules)


def _build_ai_access_summary(user: User) -> str:
    permissions = user.effective_permissions or user.permissions or {}
    visible_modules = [
        f"{module}:{permissions.get(module)}"
        for module in PERMISSION_MODULES
        if permissions.get(module) in {"read", "write"}
    ]
    account_roles = ", ".join(user.account_roles or []) or "aucun"
    allowed_stores = ", ".join(user.store_ids or []) or "aucune"
    active_store = user.active_store_id or "aucune"
    return (
        f"Role plateforme: {user.role}\n"
        f"Roles de compte: {account_roles}\n"
        f"Boutique active: {active_store}\n"
        f"Boutiques autorisees: {allowed_stores}\n"
        f"Modules autorises: {', '.join(visible_modules) if visible_modules else 'aucun module metier'}\n"
        f"Acces reglages organisation: {'oui' if is_org_admin_user(user) else 'non'}\n"
        f"Acces reglages facturation: {'oui' if is_billing_admin_user(user) else 'non'}\n"
        f"Plan effectif: {user.effective_plan or user.subscription_plan or user.plan or 'starter'}\n"
        f"Phase d'acces abonnement: {user.subscription_access_phase or 'active'}\n"
        f"Ecriture autorisee: {'oui' if user.can_write_data else 'non'}\n"
        f"Fonctionnalites avancees autorisees: {'oui' if user.can_use_advanced_features else 'non'}"
    )


def _build_ai_platform_plan_guidance(user: User, client_platform: Optional[str]) -> str:
    effective_plan = normalize_plan(user.effective_plan or user.subscription_plan or user.plan or "starter")
    platform_label = (client_platform or "non precise").strip().lower() or "non precise"
    lines = [
        f"Plateforme cliente demandee: {platform_label}",
        f"Plan effectif courant: {effective_plan}",
    ]
    if platform_label == "web":
        lines.append("Si une fonctionnalite differe entre web et mobile, privilegie d'abord l'explication web.")
    elif platform_label == "mobile":
        lines.append("Si une fonctionnalite differe entre mobile et web, privilegie d'abord l'explication mobile.")
    else:
        lines.append("Si la plateforme n'est pas claire et que l'emplacement UI change, indique la difference web/mobile.")

    lines.append("Si une fonctionnalite depend du plan, indique le plan requis et le benefice concret debloque.")
    lines.append("Ne pousse un upgrade que s'il repond directement a la demande de l'utilisateur ou au blocage observe.")
    return "\n".join(lines)


def _build_ai_scope_cache_key(
    store_id: Optional[str] = None,
    days: Optional[int] = None,
    start_date: Optional[str] = None,
    end_date: Optional[str] = None,
    category_id: Optional[str] = None,
    supplier_id: Optional[str] = None,
) -> str:
    return "|".join(
        [
            store_id or "",
            str(days or ""),
            start_date or "",
            end_date or "",
            category_id or "",
            supplier_id or "",
        ]
    )


def _invalidate_dashboard_ai_caches(owner_id: str, store_id: Optional[str] = None) -> None:
    target_store = store_id or ""
    for feature in ("business_health_score", "dashboard_prediction"):
        ai_governance.cache_invalidate(owner_id, feature)
        if target_store:
            ai_governance.cache_invalidate(owner_id, feature, target_store)

class AiTools:
    def __init__(
        self,
        user_id: str,
        store_id: Optional[str] = None,
        currency: str = "XOF",
        lang: str = "fr",
        requesting_user: Optional[User] = None,
    ):
        self.user_id = user_id
        self.store_id = store_id
        self.currency = currency
        self.lang = lang
        self.requesting_user = requesting_user

    def _resolve_period_bounds(self, days: int = 30) -> tuple[datetime, datetime]:
        end_date = datetime.now(timezone.utc)
        start_date = end_date - timedelta(days=max(1, int(days or 30)))
        return start_date, end_date

    async def get_sales_stats(self, period: str = "today", start_date: str = None, end_date: str = None):
        """
        Get sales statistics (revenue, count) for a specific period or date range.
        Args:
            period: 'today', 'yesterday', 'week', 'month', 'year', or 'custom'.
            start_date: For custom range, format 'YYYY-MM-DD'.
            end_date: For custom range, format 'YYYY-MM-DD' (optional, defaults to next day after start_date if only start_date is given).
        """
        now = datetime.now(timezone.utc)
        s_date = now
        e_date = None
        
        if period == "today":
            s_date = now.replace(hour=0, minute=0, second=0, microsecond=0)
        elif period == "yesterday":
            s_date = (now - timedelta(days=1)).replace(hour=0, minute=0, second=0, microsecond=0)
            e_date = s_date + timedelta(days=1)
        elif period == "week":
            s_date = now - timedelta(days=7)
        elif period == "month":
            s_date = now - timedelta(days=30)
        elif period == "year":
            s_date = now - timedelta(days=365)
        elif period == "custom" or start_date:
            try:
                if start_date:
                    s_date = datetime.strptime(start_date, "%Y-%m-%d").replace(tzinfo=timezone.utc)
                if end_date:
                    e_date = datetime.strptime(end_date, "%Y-%m-%d").replace(tzinfo=timezone.utc)
                elif start_date:
                    e_date = s_date + timedelta(days=1)
            except ValueError:
                return i18n.t("ai.tools.forecast.invalid_date", self.lang)
            
        initial_query = {"user_id": self.user_id, "created_at": {"$gte": s_date}}
        if e_date:
            initial_query["created_at"]["$lt"] = e_date
        if self.store_id:
            initial_query["store_id"] = self.store_id
            
        pipeline = [
            {"$match": initial_query},
            {"$group": {"_id": None, "total_revenue": {"$sum": "$total_amount"}, "sales_count": {"$sum": 1}}}
        ]
        
        result = await db.sales.aggregate(pipeline).to_list(1)
        if not result:
            return {"period": period, "revenue": 0, "sales_count": 0}
            
        stats = result[0]
        return {
            "period": period,
            "revenue": stats.get("total_revenue", 0),
            "sales_count": stats.get("sales_count", 0),
            "currency": self.currency
        }

    async def get_product_info(self, name: str):
        """
        Get detailed information about a product by name (fuzzy search).
        Args:
            name: The name of the product to search for.
        """
        query = {
            "user_id": self.user_id,
            "name": {"$regex": name, "$options": "i"}
        }
        if self.store_id:
            query["store_id"] = self.store_id
            
        products = await db.products.find(query).limit(5).to_list(5)
        if not products:
            return i18n.t("ai.tools.product_info.not_found", self.lang, name=name)
            
        info = []
        for p in products:
            status = i18n.t("ai.tools.product_info.status_out", self.lang) if p.get("quantity", 0) <= 0 else i18n.t("ai.tools.product_info.status_in", self.lang)
            info.append({
                "name": p.get("name"),
                "stock": p.get("quantity"),
                "price": p.get("selling_price"),
                "status": status
            })
        return info

    async def check_inventory_alerts(self):
        """
        Check for low stock or out of stock items.
        """
        query = {"user_id": self.user_id, "quantity": {"$lte": 5}}
        if self.store_id:
            query["store_id"] = self.store_id
            
        low_stock = await db.products.find(query).limit(10).to_list(10)
        
        alerts = []
        for p in low_stock:
             alerts.append(i18n.t("ai.tools.inventory_alerts.format", self.lang, name=p.get('name'), quantity=p.get('quantity'), min_stock=p.get('min_stock', '?')))
             
        if not alerts:
            return i18n.t("ai.tools.inventory_alerts.empty", self.lang)
        return {"alerts": alerts, "count": len(alerts)}
    
    async def get_system_alerts(self):
        """
        Get global system alerts (Admin only).
        Detects security issues, performance drops, or critical errors.
        """
        now = datetime.now(timezone.utc)
        yesterday = now - timedelta(days=1)
        
        # 1. Security check
        failed_logins = await db.security_events.count_documents({
            "type": "login_failed", 
            "timestamp": {"$gte": yesterday}
        })
        
        # 2. Support backlog
        open_tickets = await db.support_tickets.count_documents({"status": "open"})
        
        # 3. Critical DB health
        # (Could add more checks here)
        
        alerts = []
        if failed_logins > 10:
            alerts.append(i18n.t("ai.tools.system_alerts.critical_login", self.lang, count=failed_logins))
        if open_tickets > 5:
            alerts.append(i18n.t("ai.tools.system_alerts.support_backlog", self.lang, count=open_tickets))
            
        if not alerts:
            return i18n.t("ai.tools.system_alerts.empty", self.lang)
        return {"system_alerts": alerts, "status": "ATTENTION"}

    async def get_metric_methodology(self, metric: str):
        """
        Explain how a business metric is calculated and what data scope it uses.
        Args:
            metric: Metric name or keyword, for example 'sante du business', 'projection fin de mois', 'prevision ventes' or 'conseils'.
        """
        raw_metric = (metric or "").strip().lower()
        if not raw_metric:
            return {
                "error": "Metrique manquante",
                "supported_metrics": [
                    "sante du business",
                    "projection fin de mois",
                    "prevision ventes",
                    "conseils du moment",
                    "doublons",
                ],
            }

        def has_any(*keywords: str) -> bool:
            return any(keyword in raw_metric for keyword in keywords)

        if has_any("sante", "santé", "business health", "health score", "score sante"):
            return {
                "metric": "sante_du_business",
                "type": "algorithme_metier",
                "uses_llm": False,
                "description": "Score composite de 0 a 100 pour evaluer la sante commerciale sur la periode et le perimetre actifs.",
                "formula": {
                    "margin": {"weight_pct": 30, "description": "Marge brute de la periode, convertie en score sur 100."},
                    "rotation": {"weight_pct": 20, "description": "Rotation de stock estimee a partir du cout des ventes et de la valeur du stock courant."},
                    "debt_recovery": {"weight_pct": 20, "description": "Penalite liee au poids des dettes clients par rapport au chiffre d'affaires de la periode."},
                    "trend": {"weight_pct": 30, "description": "Evolution du chiffre d'affaires par rapport a la periode precedente de meme duree."},
                },
                "score_formula": "score = margin*0.30 + rotation*0.20 + debt_recovery*0.20 + trend*0.30",
                "data_inputs": [
                    "ventes terminees sur la periode selectionnee",
                    "articles vendus et prix d'achat des lignes",
                    "stock courant de la boutique ou du filtre selectionne",
                    "dettes clients du perimetre accessible",
                    "periode precedente de meme duree pour la tendance",
                ],
                "scope_rules": {
                    "store": "prend la boutique active ou le store_id passe explicitement",
                    "filters": "prend aussi en compte category_id et supplier_id quand ils sont fournis",
                    "date_range": "prend days ou start_date/end_date selon le contexte de l'ecran",
                },
                "refresh_rules": [
                    "se recalcule apres vente, depense, mouvement de stock ou inventaire grace a l'invalidation du cache",
                    "le web envoie maintenant les filtres du dashboard a cette metrique",
                ],
            }

        if has_any("projection", "fin de mois", "dashboard prediction", "prediction"):
            return {
                "metric": "projection_fin_de_mois",
                "type": "algorithme_metier",
                "uses_llm": False,
                "description": "Projection du chiffre d'affaires de fin de mois a partir du rythme courant et d'un historique recent.",
                "formula": {
                    "current_month_revenue": "somme du chiffre d'affaires du mois en cours sur le perimetre actif",
                    "daily_pace": "current_month_revenue / jours_ecoules",
                    "linear_projection": "daily_pace * nombre_de_jours_du_mois",
                    "weighted_history": "moyenne ponderee des deux mois precedents, avec plus de poids sur le mois le plus recent",
                    "final_projection": "combinaison du rythme courant et de l'historique pondere",
                },
                "data_inputs": [
                    "ventes terminees du mois en cours",
                    "ventes terminees des deux mois precedents",
                    "produits filtres si category_id ou supplier_id sont fournis",
                ],
                "scope_rules": {
                    "store": "prend la boutique active ou le store_id passe explicitement",
                    "filters": "prend category_id et supplier_id",
                    "month_length": "utilise le vrai nombre de jours du mois courant",
                },
            }

        if has_any("prevision ventes", "prévision ventes", "forecast", "j+7", "j+30"):
            return {
                "metric": "prevision_ventes",
                "type": "algorithme_metier",
                "uses_llm": False,
                "description": "Projection de ventes par produit a horizon court a partir de la velocite de vente recente.",
                "data_inputs": [
                    "ventes recentes par produit",
                    "stock courant",
                    "tendance recente",
                ],
                "scope_rules": {
                    "store": "alimentee par la boutique active",
                    "period": "fenetre courte pour estimer J+7 et J+30",
                },
            }

        if has_any("conseil", "tips", "conseils du moment", "contextual"):
            return {
                "metric": "conseils_du_moment",
                "type": "moteur_de_regles",
                "uses_llm": False,
                "description": "Les conseils du moment sont generes par des regles metier, pas par un LLM.",
                "data_inputs": [
                    "stocks bas ou ruptures",
                    "evolution du chiffre d'affaires",
                    "marge et depenses",
                    "clients inactifs ou a risque",
                ],
                "scope_rules": {
                    "store": "prend la boutique active",
                    "plan": "certaines regles avancees ne s'activent qu'en Pro ou Enterprise",
                },
            }

        if has_any("doublon", "duplicate"):
            return {
                "metric": "detection_doublons",
                "type": "algorithme_metier",
                "uses_llm": False,
                "description": "Detection de paires tres proches via similarite textuelle et rapprochements de references ou contacts.",
                "formula": {
                    "products": "similarite trigramme sur le nom, avec bonus si SKU tres proche",
                    "suppliers": "similarite trigramme sur le nom, avec bonus si telephone ou email identiques",
                },
                "scope_rules": {
                    "products": "filtre sur la boutique active",
                    "suppliers": "perimetre compte utilisateur",
                    "resolutions": "les paires ignorees ou marquees differente ne remontent plus",
                },
            }

        return {
            "known": False,
            "metric": metric,
            "message": "Aucune methode explicite n'est definie pour cette metrique. Utiliser le RAG et le code metier pour completer.",
        }

    async def get_data_summary(self):
        """Get a general summary of the business data."""
        return await _get_ai_data_summary(self.user_id, self.store_id, requesting_user=self.requesting_user)

    async def get_settings_snapshot(self, section: str = "all"):
        """
        Get the effective settings visible to the requesting user.
        Args:
            section: 'all', 'account', 'organization', 'notifications', 'documents', 'stores', or 'security'.
        """
        if not self.requesting_user:
            return {"error": "Utilisateur de contexte introuvable"}

        allowed_sections = {"all", "account", "organization", "notifications", "documents", "stores", "security"}
        normalized_section = (section or "all").strip().lower()
        if normalized_section not in allowed_sections:
            return {
                "error": "Section de reglages non supportee",
                "allowed_sections": sorted(allowed_sections),
            }

        settings = await load_effective_settings_for_user(self.requesting_user)
        settings = filter_settings_for_viewer(settings, self.requesting_user)
        settings_doc = settings.model_dump()

        stores_query: Dict[str, Any] = {"user_id": self.user_id}
        if self.requesting_user.store_ids:
            stores_query = {"store_id": {"$in": self.requesting_user.store_ids}}
        stores = await db.stores.find(stores_query, {"_id": 0, "store_id": 1, "name": 1, "city": 1}).to_list(50)
        active_store = next((store for store in stores if store.get("store_id") == self.requesting_user.active_store_id), None)

        def _extract_enabled_reminders(reminders: Dict[str, Any]) -> List[str]:
            enabled = []
            for key, rule in (reminders or {}).items():
                if isinstance(rule, dict) and rule.get("enabled"):
                    threshold = rule.get("threshold")
                    enabled.append(f"{key} (seuil={threshold})" if threshold is not None else key)
            return enabled

        def _notification_contacts_summary(source: Dict[str, Any]) -> Dict[str, List[str]]:
            result: Dict[str, List[str]] = {}
            for key, value in (source or {}).items():
                emails = [email for email in (value or []) if isinstance(email, str) and email.strip()]
                if emails:
                    result[key] = emails
            return result

        tabs = {
            "account": {
                "language": settings_doc.get("language") or "fr",
                "currency": settings_doc.get("currency") or self.currency,
                "simple_mode": bool(settings_doc.get("simple_mode")),
                "billing_contact_name": settings_doc.get("billing_contact_name"),
                "billing_contact_email": settings_doc.get("billing_contact_email"),
            },
            "organization": {
                "modules": settings_doc.get("modules") or {},
                "loyalty": settings_doc.get("loyalty") or {},
                "enabled_reminder_rules": _extract_enabled_reminders(settings_doc.get("reminder_rules") or {}),
            },
            "notifications": {
                "preferences": settings_doc.get("notification_preferences") or {},
                "organization_contacts": _notification_contacts_summary(settings_doc.get("notification_contacts") or {}),
                "store_contacts": _notification_contacts_summary(settings_doc.get("store_notification_contacts") or {}),
            },
            "documents": {
                "tax_enabled": bool(settings_doc.get("tax_enabled")),
                "tax_rate": float(settings_doc.get("tax_rate") or 0),
                "tax_mode": settings_doc.get("tax_mode") or "ttc",
                "terminals": settings_doc.get("terminals") or [],
                "receipt": {
                    "business_name": settings_doc.get("receipt_business_name"),
                    "footer": settings_doc.get("receipt_footer"),
                },
                "invoice": {
                    "business_name": settings_doc.get("invoice_business_name"),
                    "address": settings_doc.get("invoice_business_address"),
                    "label": settings_doc.get("invoice_label"),
                    "prefix": settings_doc.get("invoice_prefix"),
                    "footer": settings_doc.get("invoice_footer"),
                    "payment_terms": settings_doc.get("invoice_payment_terms"),
                },
            },
            "stores": {
                "active_store_id": self.requesting_user.active_store_id,
                "active_store_name": active_store.get("name") if active_store else None,
                "accessible_stores_count": len(stores),
                "accessible_stores": stores,
            },
            "security": {
                "auth_type": self.requesting_user.auth_type,
                "auth_providers": self.requesting_user.auth_providers or {},
                "can_change_password": self.requesting_user.auth_type == "email" or self.requesting_user.password_set,
                "can_delete_account": True,
                "can_logout": True,
            },
        }

        if normalized_section == "all":
            return {
                "scope": "effective_settings",
                "organization_admin": is_org_admin_user(self.requesting_user),
                "billing_admin": is_billing_admin_user(self.requesting_user),
                "tabs": tabs,
            }

        return {
            "scope": "effective_settings",
            "section": normalized_section,
            "organization_admin": is_org_admin_user(self.requesting_user),
            "billing_admin": is_billing_admin_user(self.requesting_user),
            "data": tabs[normalized_section],
        }

    async def get_marketplace_overview(
        self,
        query: Optional[str] = None,
        category: Optional[str] = None,
        city: Optional[str] = None,
    ):
        """
        Get marketplace supplier and catalog overview.
        Args:
            query: Optional free-text supplier/product search.
            category: Optional category filter.
            city: Optional city filter.
        """
        filters: List[Dict[str, Any]] = []
        if query:
            fuzzy_q = get_fuzzy_regex(query)
            q_regex = {"$regex": fuzzy_q, "$options": "i"}
            catalog_supplier_ids = await db.catalog_products.distinct(
                "supplier_user_id",
                {
                    **published_catalog_query(),
                    "$or": [
                        {"name": q_regex},
                        {"description": q_regex},
                        {"category": q_regex},
                        {"subcategory": q_regex},
                    ],
                },
            )
            supplier_filters: List[Dict[str, Any]] = [
                {"company_name": q_regex},
                {"description": q_regex},
                {"city": q_regex},
                {"categories": {"$elemMatch": q_regex}},
            ]
            if catalog_supplier_ids:
                supplier_filters.append({"user_id": {"$in": catalog_supplier_ids}})
            filters.append({"$or": supplier_filters})

        if category:
            cat_regex = {"$regex": safe_regex(category), "$options": "i"}
            category_supplier_ids = await db.catalog_products.distinct(
                "supplier_user_id",
                {
                    **published_catalog_query(),
                    "$or": [
                        {"category": cat_regex},
                        {"subcategory": cat_regex},
                    ],
                },
            )
            cat_filters: List[Dict[str, Any]] = [{"categories": {"$elemMatch": cat_regex}}]
            if category_supplier_ids:
                cat_filters.append({"user_id": {"$in": category_supplier_ids}})
            filters.append({"$or": cat_filters})

        if city:
            filters.append({"city": {"$regex": safe_regex(city), "$options": "i"}})

        profile_query: Dict[str, Any] = {"$and": filters} if filters else {}
        profiles = await db.supplier_profiles.find(profile_query, {"_id": 0}).sort("rating_average", -1).limit(20).to_list(20)
        supplier_ids = [profile.get("user_id") for profile in profiles if profile.get("user_id")]

        catalog_query = published_catalog_query()
        if supplier_ids:
            catalog_query["supplier_user_id"] = {"$in": supplier_ids}
        elif filters:
            catalog_query["supplier_user_id"] = {"$in": []}

        catalog_count = await db.catalog_products.count_documents(catalog_query)
        total_suppliers = await db.supplier_profiles.count_documents(profile_query)
        total_catalog_products = await db.catalog_products.count_documents(published_catalog_query())

        return {
            "scope": "marketplace",
            "supplier_count": total_suppliers,
            "catalog_product_count": total_catalog_products if not filters else catalog_count,
            "filtered": bool(filters),
            "filters": {
                "query": query,
                "category": category,
                "city": city,
            },
            "top_suppliers": [
                {
                    "supplier_user_id": profile.get("user_id"),
                    "name": profile.get("company_name") or "Fournisseur",
                    "city": profile.get("city"),
                    "rating": profile.get("rating_average", 0),
                    "verified": bool(profile.get("is_verified")),
                }
                for profile in profiles[:8]
            ],
        }

    async def get_crm_snapshot(self, days: int = 30):
        """
        Get CRM overview for the active scope.
        """
        if not self.requesting_user:
            return {"error": "Utilisateur de contexte introuvable"}

        owner_id = self.user_id
        date_range = _parse_optional_range(days=days)
        rows = await _build_crm_customer_rows(owner_id, date_range["start"], date_range["end"], store_id=self.store_id)
        total_customers = len(rows)
        active_customers = len([row for row in rows if row.get("period_visit_count", 0) > 0])
        inactive_customers = len([row for row in rows if (row.get("inactive_days") or 9999) > 30])
        at_risk_customers = len([row for row in rows if row.get("segment") == "at_risk"])
        debt_customers = len([row for row in rows if row.get("current_debt", 0) > 0])
        debt_balance = round(sum(float(row.get("current_debt") or 0) for row in rows), 2)
        period_revenue = round(sum(float(row.get("period_revenue") or 0) for row in rows), 2)
        period_sales_count = sum(int(row.get("period_visit_count") or 0) for row in rows)
        average_basket = round(period_revenue / period_sales_count, 2) if period_sales_count > 0 else 0.0
        repeat_customers = len([row for row in rows if row.get("period_visit_count", 0) >= 2])
        repeat_rate = round((repeat_customers / active_customers) * 100, 2) if active_customers > 0 else 0.0

        top_customers = sorted(rows, key=lambda row: row.get("period_revenue", 0), reverse=True)[:5]
        return {
            "scope": "crm",
            "days": days,
            "kpis": {
                "total_customers": total_customers,
                "active_customers": active_customers,
                "inactive_customers": inactive_customers,
                "at_risk_customers": at_risk_customers,
                "debt_customers": debt_customers,
                "debt_balance": debt_balance,
                "average_basket": average_basket,
                "repeat_rate": repeat_rate,
            },
            "top_customers": [
                {
                    "customer_id": customer.get("customer_id"),
                    "name": customer.get("name") or "Client",
                    "period_revenue": round(float(customer.get("period_revenue") or 0), 2),
                    "segment": customer.get("segment"),
                    "current_debt": round(float(customer.get("current_debt") or 0), 2),
                }
                for customer in top_customers
            ],
            "recommendations": _build_crm_recommendations(
                active_customers=active_customers,
                total_customers=total_customers,
                repeat_rate=repeat_rate,
                inactive_customers=inactive_customers,
                at_risk_customers=at_risk_customers,
                debt_customers=debt_customers,
                birthdays_soon=len([row for row in rows if row.get("birthday_in_days") is not None and row.get("birthday_in_days") <= 7]),
            ),
        }

    async def get_accounting_snapshot(self, days: int = 30):
        """
        Get accounting overview for the active scope.
        """
        start_date, end_date = self._resolve_period_bounds(days)
        user_id = self.user_id

        sales_query: Dict[str, Any] = {"user_id": user_id, "created_at": {"$gte": start_date, "$lte": end_date}}
        expenses_query: Dict[str, Any] = {"user_id": user_id, "created_at": {"$gte": start_date, "$lte": end_date}}
        if self.requesting_user:
            sales_query = apply_accessible_store_scope(sales_query, self.requesting_user, self.store_id)
            expenses_query = apply_accessible_store_scope(expenses_query, self.requesting_user, self.store_id)
        elif self.store_id:
            sales_query["store_id"] = self.store_id
            expenses_query["store_id"] = self.store_id
        sales_query = apply_completed_sales_scope(sales_query)

        sales = await db.sales.find(sales_query, {"_id": 0, "total_amount": 1, "items": 1, "payment_method": 1}).to_list(5000)
        expenses = await db.expenses.find(expenses_query, {"_id": 0, "amount": 1, "category": 1, "description": 1, "created_at": 1}).sort("created_at", -1).to_list(500)

        revenue = 0.0
        cogs = 0.0
        payment_breakdown: Dict[str, float] = defaultdict(float)
        for sale in sales:
            revenue += float(sale.get("total_amount") or 0)
            payment_breakdown[sale.get("payment_method") or "cash"] += float(sale.get("total_amount") or 0)
            for item in sale.get("items", []):
                qty = float(item.get("quantity") or 0)
                cogs += float(item.get("purchase_price") or 0) * qty

        total_expenses = round(sum(float(expense.get("amount") or 0) for expense in expenses), 2)
        gross_profit = round(revenue - cogs, 2)
        net_profit = round(gross_profit - total_expenses, 2)
        gross_margin_pct = round((gross_profit / revenue) * 100, 2) if revenue > 0 else 0.0
        net_margin_pct = round((net_profit / revenue) * 100, 2) if revenue > 0 else 0.0
        expenses_breakdown: Dict[str, float] = defaultdict(float)
        for expense in expenses:
            expenses_breakdown[expense.get("category") or "other"] += float(expense.get("amount") or 0)

        top_expenses = sorted(expenses_breakdown.items(), key=lambda item: item[1], reverse=True)[:5]
        return {
            "scope": "accounting",
            "days": days,
            "kpis": {
                "revenue": round(revenue, 2),
                "gross_profit": gross_profit,
                "net_profit": net_profit,
                "expenses": total_expenses,
                "gross_margin_pct": gross_margin_pct,
                "net_margin_pct": net_margin_pct,
            },
            "payment_breakdown": {key: round(value, 2) for key, value in payment_breakdown.items()},
            "top_expense_categories": [
                {"category": category, "amount": round(amount, 2)}
                for category, amount in top_expenses
            ],
            "recent_expenses": [
                {
                    "category": expense.get("category") or "other",
                    "amount": round(float(expense.get("amount") or 0), 2),
                    "description": expense.get("description") or "",
                    "created_at": expense.get("created_at"),
                }
                for expense in expenses[:5]
            ],
        }

    async def get_procurement_snapshot(self, days: int = 30):
        """
        Get suppliers, orders, and procurement overview for the active scope.
        """
        start_date, end_date = self._resolve_period_bounds(days)
        suppliers_query: Dict[str, Any] = {"user_id": self.user_id}
        orders_query: Dict[str, Any] = {"user_id": self.user_id, "created_at": {"$gte": start_date, "$lte": end_date}}
        if self.store_id:
            suppliers_query["store_id"] = self.store_id
            orders_query["store_id"] = self.store_id

        suppliers = await db.suppliers.find(suppliers_query, {"_id": 0, "supplier_id": 1, "name": 1, "is_connected": 1, "source": 1}).to_list(1000)
        orders = await db.orders.find(orders_query, {"_id": 0, "order_id": 1, "supplier_id": 1, "supplier_name": 1, "status": 1, "total_amount": 1, "created_at": 1}).sort("created_at", -1).to_list(1000)

        status_counts: Dict[str, int] = defaultdict(int)
        total_amount = 0.0
        supplier_order_counts: Dict[str, int] = defaultdict(int)
        supplier_name_map: Dict[str, str] = {}
        for order in orders:
            status_counts[order.get("status") or "unknown"] += 1
            total_amount += float(order.get("total_amount") or 0)
            supplier_key = order.get("supplier_id") or order.get("supplier_name") or "unknown"
            supplier_order_counts[supplier_key] += 1
            if order.get("supplier_name"):
                supplier_name_map[supplier_key] = order.get("supplier_name")

        connected_suppliers = [supplier for supplier in suppliers if supplier.get("is_connected") or supplier.get("source") == "marketplace"]
        top_suppliers = sorted(supplier_order_counts.items(), key=lambda item: item[1], reverse=True)[:5]
        return {
            "scope": "procurement",
            "days": days,
            "kpis": {
                "suppliers_count": len(suppliers),
                "connected_suppliers_count": len(connected_suppliers),
                "orders_count": len(orders),
                "orders_total_amount": round(total_amount, 2),
            },
            "order_statuses": dict(status_counts),
            "top_suppliers_by_orders": [
                {
                    "supplier": supplier_name_map.get(key) or next((supplier.get("name") for supplier in suppliers if supplier.get("supplier_id") == key), key),
                    "orders": count,
                }
                for key, count in top_suppliers
            ],
            "recent_orders": orders[:5],
        }

    async def get_kpi_analysis(self, days: int = 30, start_date: str = None, end_date: str = None):
        """
        Compute ALL business KPIs for a given period: revenue, margin, avg basket, stock turnover, deadstock, customer debt, expenses, top categories, and business health score.
        Also automatically compares to the previous equivalent period.
        Args:
            days: Period length in days (default 30). Ignored if start_date is provided.
            start_date: Period start date in 'YYYY-MM-DD' format (optional).
            end_date: Period end date in 'YYYY-MM-DD' format (optional, defaults to today).
        """
        now = datetime.now(timezone.utc)
        if start_date:
            try:
                cur_start = datetime.strptime(start_date, "%Y-%m-%d").replace(tzinfo=timezone.utc)
                cur_end = datetime.strptime(end_date, "%Y-%m-%d").replace(tzinfo=timezone.utc) + timedelta(days=1) if end_date else now
            except ValueError:
                return {"error": "Format de date invalide. Utilise YYYY-MM-DD."}
        else:
            days = max(1, min(days, 365))
            cur_end = now
            cur_start = now - timedelta(days=days)

        period_len = max(cur_end - cur_start, timedelta(days=1))
        prev_start = cur_start - period_len
        prev_end = cur_start

        ru = self.requesting_user
        can_sales = ru is None or _user_has_module_access(ru, "pos", "accounting")
        can_stock = ru is None or _user_has_module_access(ru, "stock")
        can_accounting = ru is None or _user_has_module_access(ru, "accounting")
        can_crm = ru is None or _user_has_module_access(ru, "crm")
        can_suppliers = ru is None or _user_has_module_access(ru, "suppliers")

        uid = self.user_id
        sid = self.store_id
        base_q: Dict[str, Any] = {"user_id": uid}
        if sid:
            base_q["store_id"] = sid

        sales_q_c = {**base_q, "created_at": {"$gte": cur_start, "$lte": cur_end}, "status": {"$in": ["completed", "paid"]}}
        sales_q_p = {**base_q, "created_at": {"$gte": prev_start, "$lt": prev_end}, "status": {"$in": ["completed", "paid"]}}
        exp_q_c = {**base_q, "created_at": {"$gte": cur_start, "$lte": cur_end}}
        exp_q_p = {**base_q, "created_at": {"$gte": prev_start, "$lt": prev_end}}
        ord_q_c = {**base_q, "created_at": {"$gte": cur_start, "$lte": cur_end}}
        ord_q_p = {**base_q, "created_at": {"$gte": prev_start, "$lt": prev_end}}

        sales_c = await db.sales.find(sales_q_c, {"_id": 0, "total_amount": 1, "items": 1, "payment_method": 1, "created_at": 1}).to_list(10000) if can_sales else []
        sales_p = await db.sales.find(sales_q_p, {"_id": 0, "total_amount": 1, "items": 1}).to_list(10000) if can_sales else []
        expenses_c = await db.expenses.find(exp_q_c, {"_id": 0, "amount": 1, "category": 1}).to_list(5000) if can_accounting else []
        expenses_p = await db.expenses.find(exp_q_p, {"_id": 0, "amount": 1}).to_list(5000) if can_accounting else []
        products = await db.products.find(base_q, {"_id": 0, "product_id": 1, "name": 1, "quantity": 1, "purchase_price": 1, "selling_price": 1, "min_stock": 1, "category": 1}).to_list(5000) if can_stock else []
        customers = await db.customers.find(base_q, {"_id": 0, "current_debt": 1}).to_list(5000) if can_crm else []
        orders_c = await db.orders.find(ord_q_c, {"_id": 0, "total_amount": 1, "status": 1, "supplier_name": 1, "supplier_id": 1, "items": 1}).to_list(2000) if can_suppliers else []
        orders_p = await db.orders.find(ord_q_p, {"_id": 0, "total_amount": 1, "status": 1}).to_list(2000) if can_suppliers else []
        suppliers = await db.suppliers.find(base_q, {"_id": 0, "supplier_id": 1, "name": 1}).to_list(500) if can_suppliers else []

        def _metrics(sales_docs):
            rev, cost, count = 0.0, 0.0, 0
            product_sales: Dict[str, dict] = {}
            cat_rev: Dict[str, float] = defaultdict(float)
            payment_rev: Dict[str, float] = defaultdict(float)
            for sale in sales_docs:
                count += 1
                pm = sale.get("payment_method") or "cash"
                for item in (sale.get("items") or []):
                    qty = float(item.get("quantity") or 0)
                    sp = float(item.get("selling_price") or 0)
                    pp = float(item.get("purchase_price") or 0)
                    item_rev = float(item.get("total") or 0) or sp * qty
                    item_cost = pp * qty
                    rev += item_rev
                    cost += item_cost
                    pid = item.get("product_id") or ""
                    cat = item.get("category") or "Sans catégorie"
                    if pid:
                        if pid not in product_sales:
                            product_sales[pid] = {"name": item.get("name") or pid, "revenue": 0.0, "cost": 0.0, "qty": 0.0, "category": cat}
                        product_sales[pid]["revenue"] += item_rev
                        product_sales[pid]["cost"] += item_cost
                        product_sales[pid]["qty"] += qty
                    cat_rev[cat] += item_rev
                    payment_rev[pm] += item_rev
            return rev, cost, count, product_sales, cat_rev, payment_rev

        rev_c, cost_c, count_c, prod_sales_c, cat_rev_c, pay_rev_c = _metrics(sales_c)
        rev_p, cost_p, count_p, _, _, _ = _metrics(sales_p)
        exp_c = sum(float(e.get("amount") or 0) for e in expenses_c)
        exp_p = sum(float(e.get("amount") or 0) for e in expenses_p)

        gross_c = rev_c - cost_c
        gross_p = rev_p - cost_p
        margin_pct_c = round(gross_c / rev_c * 100, 1) if rev_c > 0 else 0
        margin_pct_p = round(gross_p / rev_p * 100, 1) if rev_p > 0 else 0
        net_c = gross_c - exp_c
        net_p = gross_p - exp_p
        avg_basket_c = round(rev_c / count_c) if count_c > 0 else 0
        avg_basket_p = round(rev_p / count_p) if count_p > 0 else 0

        # --- Fournisseurs ---
        ord_total_c = sum(float(o.get("total_amount") or 0) for o in orders_c)
        ord_total_p = sum(float(o.get("total_amount") or 0) for o in orders_p)
        ord_status_c: Dict[str, int] = defaultdict(int)
        supplier_spend: Dict[str, float] = defaultdict(float)
        supplier_name_map: Dict[str, str] = {}
        for o in orders_c:
            ord_status_c[o.get("status") or "unknown"] += 1
            key = o.get("supplier_id") or o.get("supplier_name") or "unknown"
            supplier_spend[key] += float(o.get("total_amount") or 0)
            if o.get("supplier_name"):
                supplier_name_map[key] = o["supplier_name"]
        top_suppliers_by_spend = sorted(supplier_spend.items(), key=lambda x: -x[1])[:5]

        stock_value = sum(p.get("quantity", 0) * p.get("purchase_price", 0) for p in products)
        turnover = round(cost_c / stock_value, 2) if stock_value > 0 else 0
        out_of_stock = [p["name"] for p in products if p.get("quantity", 0) == 0 and p.get("name")]
        low_stock = [p["name"] for p in products if 0 < p.get("quantity", 0) <= p.get("min_stock", 0) and p.get("name")]
        deadstock_threshold = period_len.days
        sold_pids = set(prod_sales_c.keys())
        deadstock = [p["name"] for p in products if p.get("product_id") not in sold_pids and p.get("quantity", 0) > 0 and p.get("name")]

        total_debt = sum(max(float(c.get("current_debt", 0) or 0), 0) for c in customers)
        debt_ratio = round(total_debt / rev_c * 100, 1) if rev_c > 0 else 0

        exp_by_cat: Dict[str, float] = defaultdict(float)
        for e in expenses_c:
            exp_by_cat[e.get("category") or "Autre"] += float(e.get("amount") or 0)

        top_products = sorted(prod_sales_c.values(), key=lambda x: x["revenue"], reverse=True)[:10]
        for tp in top_products:
            tp["margin_pct"] = round((tp["revenue"] - tp["cost"]) / tp["revenue"] * 100, 1) if tp["revenue"] > 0 else 0

        flop_products = sorted(
            [p for p in products if p.get("name") and p.get("product_id") not in sold_pids and p.get("quantity", 0) > 0],
            key=lambda p: p.get("quantity", 0) * p.get("purchase_price", 0),
            reverse=True
        )[:5]

        def _delta(cur, prev):
            if prev == 0:
                return "+∞" if cur > 0 else "0"
            d = round((cur - prev) / abs(prev) * 100, 1)
            return f"+{d}%" if d >= 0 else f"{d}%"

        top_cats = sorted(cat_rev_c.items(), key=lambda x: -x[1])[:5]
        top_payments = sorted(pay_rev_c.items(), key=lambda x: -x[1])

        restricted = [m for m, ok in [("ventes/caisse", can_sales), ("comptabilite", can_accounting), ("stock", can_stock), ("crm", can_crm), ("fournisseurs", can_suppliers)] if not ok]
        result: Dict[str, Any] = {
            "period": {"start": cur_start.strftime("%Y-%m-%d"), "end": cur_end.strftime("%Y-%m-%d"), "days": period_len.days},
            "previous_period": {"start": prev_start.strftime("%Y-%m-%d"), "end": prev_end.strftime("%Y-%m-%d")},
            "currency": self.currency,
        }
        if restricted:
            result["access_restricted"] = f"Modules non accessibles pour cet utilisateur : {', '.join(restricted)}. Les KPIs correspondants ne sont pas disponibles."
        if can_sales:
            result["revenue"] = {"current": round(rev_c), "previous": round(rev_p), "delta": _delta(rev_c, rev_p)}
            result["gross_margin"] = {"current_amount": round(gross_c), "current_pct": margin_pct_c, "previous_pct": margin_pct_p, "delta": _delta(margin_pct_c, margin_pct_p)}
            result["sales_count"] = {"current": count_c, "previous": count_p, "delta": _delta(count_c, count_p)}
            result["avg_basket"] = {"current": avg_basket_c, "previous": avg_basket_p, "currency": self.currency, "delta": _delta(avg_basket_c, avg_basket_p)}
            result["top_categories"] = [{"category": cat, "revenue": round(rev)} for cat, rev in top_cats]
            result["payment_methods"] = [{"method": pm, "revenue": round(rev), "pct": round(rev / rev_c * 100, 1) if rev_c > 0 else 0} for pm, rev in top_payments]
            result["top_products"] = [{"name": p["name"], "revenue": round(p["revenue"]), "qty_sold": round(p["qty"]), "margin_pct": p["margin_pct"], "category": p["category"]} for p in top_products]
        if can_accounting:
            result["expenses"] = {"current": round(exp_c), "previous": round(exp_p), "delta": _delta(exp_c, exp_p), "by_category": {k: round(v) for k, v in sorted(exp_by_cat.items(), key=lambda x: -x[1])[:8]}}
        if can_sales and can_accounting:
            result["net_profit"] = {"current": round(net_c), "previous": round(net_p), "delta": _delta(net_c, net_p)}
        if can_stock:
            result["stock"] = {"total_products": len(products), "stock_value": round(stock_value), "turnover_ratio": turnover, "out_of_stock": len(out_of_stock), "out_of_stock_names": out_of_stock[:10], "low_stock": len(low_stock), "low_stock_names": low_stock[:10], "deadstock_count": len(deadstock), "deadstock_names": deadstock[:10]}
            result["flop_products"] = [{"name": p.get("name"), "stock": p.get("quantity"), "stock_value": round(p.get("quantity", 0) * p.get("purchase_price", 0))} for p in flop_products]
        if can_crm:
            result["customer_debt"] = {"total": round(total_debt), "debt_ratio_pct": debt_ratio, "currency": self.currency}
        if can_suppliers:
            ord_delta = _delta(ord_total_c, ord_total_p)
            ord_count_delta = _delta(len(orders_c), len(orders_p))
            result["procurement"] = {
                "orders_count": {"current": len(orders_c), "previous": len(orders_p), "delta": ord_count_delta},
                "total_spend": {"current": round(ord_total_c), "previous": round(ord_total_p), "delta": ord_delta, "currency": self.currency},
                "suppliers_count": len(suppliers),
                "order_statuses": dict(ord_status_c),
                "top_suppliers_by_spend": [
                    {"id": sid, "name": supplier_name_map.get(sid, sid), "spend": round(amt)}
                    for sid, amt in top_suppliers_by_spend
                ],
            }
        return result

    async def compare_periods(self, period_a_start: str, period_a_end: str, period_b_start: str, period_b_end: str):
        """
        Compare two arbitrary time periods across all business KPIs: revenue, margin, expenses, basket, stock, debt.
        Use this whenever the user asks to compare months, weeks, quarters, or any two custom date ranges.
        Args:
            period_a_start: Start of period A in 'YYYY-MM-DD' format.
            period_a_end: End of period A in 'YYYY-MM-DD' format.
            period_b_start: Start of period B in 'YYYY-MM-DD' format.
            period_b_end: End of period B in 'YYYY-MM-DD' format.
        """
        try:
            a_start = datetime.strptime(period_a_start, "%Y-%m-%d").replace(tzinfo=timezone.utc)
            a_end = datetime.strptime(period_a_end, "%Y-%m-%d").replace(tzinfo=timezone.utc) + timedelta(days=1)
            b_start = datetime.strptime(period_b_start, "%Y-%m-%d").replace(tzinfo=timezone.utc)
            b_end = datetime.strptime(period_b_end, "%Y-%m-%d").replace(tzinfo=timezone.utc) + timedelta(days=1)
        except ValueError:
            return {"error": "Format de date invalide. Utilise YYYY-MM-DD."}

        ru = self.requesting_user
        can_sales = ru is None or _user_has_module_access(ru, "pos", "accounting")
        can_accounting = ru is None or _user_has_module_access(ru, "accounting")
        can_suppliers = ru is None or _user_has_module_access(ru, "suppliers")

        uid = self.user_id
        sid = self.store_id
        base_q: Dict[str, Any] = {"user_id": uid}
        if sid:
            base_q["store_id"] = sid

        async def _period_kpis(p_start, p_end):
            rev, cost, count, exp_total = 0.0, 0.0, 0, 0.0
            if can_sales:
                sales_q = {**base_q, "created_at": {"$gte": p_start, "$lt": p_end}, "status": {"$in": ["completed", "paid"]}}
                sales = await db.sales.find(sales_q, {"_id": 0, "total_amount": 1, "items": 1}).to_list(10000)
                for sale in sales:
                    count += 1
                    for item in (sale.get("items") or []):
                        qty = float(item.get("quantity") or 0)
                        rev += float(item.get("total") or 0) or (float(item.get("selling_price") or 0) * qty)
                        cost += float(item.get("purchase_price") or 0) * qty
            if can_accounting:
                exp_q = {**base_q, "created_at": {"$gte": p_start, "$lt": p_end}}
                exps = await db.expenses.find(exp_q, {"_id": 0, "amount": 1}).to_list(5000)
                exp_total = sum(float(e.get("amount") or 0) for e in exps)
            ord_total, ord_count = 0.0, 0
            if can_suppliers:
                ord_q = {**base_q, "created_at": {"$gte": p_start, "$lt": p_end}}
                ords = await db.orders.find(ord_q, {"_id": 0, "total_amount": 1}).to_list(2000)
                ord_count = len(ords)
                ord_total = sum(float(o.get("total_amount") or 0) for o in ords)
            gross = rev - cost
            margin_pct = round(gross / rev * 100, 1) if rev > 0 else 0
            net = gross - exp_total
            avg_basket = round(rev / count) if count > 0 else 0
            return {"revenue": round(rev), "cost": round(cost), "gross_margin": round(gross), "margin_pct": margin_pct, "expenses": round(exp_total), "net_profit": round(net), "sales_count": count, "avg_basket": avg_basket, "procurement_spend": round(ord_total), "procurement_orders": ord_count}

        kpis_a, kpis_b = await asyncio.gather(_period_kpis(a_start, a_end), _period_kpis(b_start, b_end))

        def _delta(va, vb):
            if vb == 0:
                return "+∞" if va > 0 else "0%"
            d = round((va - vb) / abs(vb) * 100, 1)
            return f"+{d}%" if d >= 0 else f"{d}%"

        def _winner(va, vb, higher_is_better=True):
            if va == vb:
                return "égal"
            if higher_is_better:
                return "A" if va > vb else "B"
            return "A" if va < vb else "B"

        comparison = {}
        lower_is_better = {"expenses", "procurement_spend"}
        for key in kpis_a:
            va, vb = kpis_a[key], kpis_b[key]
            higher_better = key not in lower_is_better
            comparison[key] = {"period_a": va, "period_b": vb, "delta_a_vs_b": _delta(va, vb), "better": _winner(va, vb, higher_better)}

        result: Dict[str, Any] = {
            "period_a": {"start": period_a_start, "end": period_a_end, "days": (a_end - a_start).days},
            "period_b": {"start": period_b_start, "end": period_b_end, "days": (b_end - b_start).days},
            "currency": self.currency,
            "comparison": comparison,
            "summary": {
                "revenue_winner": comparison["revenue"]["better"],
                "margin_winner": comparison["margin_pct"]["better"],
                "net_profit_winner": comparison["net_profit"]["better"],
                "expenses_winner": comparison["expenses"]["better"],
            },
        }
        if not can_suppliers:
            result["access_restricted_modules"] = (result.get("access_restricted_modules") or []) + ["fournisseurs"]
        return result

    async def get_top_products_analysis(self, days: int = 30, start_date: str = None, end_date: str = None, top_n: int = 10):
        """
        Detailed analysis of top and bottom performing products: revenue, margin, velocity, stock coverage, trend vs previous period.
        Args:
            days: Analysis period in days (default 30). Ignored if start_date is provided.
            start_date: Start date in 'YYYY-MM-DD' format (optional).
            end_date: End date in 'YYYY-MM-DD' format (optional).
            top_n: Number of top products to return (default 10, max 20).
        """
        now = datetime.now(timezone.utc)
        if start_date:
            try:
                cur_start = datetime.strptime(start_date, "%Y-%m-%d").replace(tzinfo=timezone.utc)
                cur_end = datetime.strptime(end_date, "%Y-%m-%d").replace(tzinfo=timezone.utc) + timedelta(days=1) if end_date else now
            except ValueError:
                return {"error": "Format de date invalide. Utilise YYYY-MM-DD."}
        else:
            days = max(1, min(days, 365))
            cur_end = now
            cur_start = now - timedelta(days=days)

        period_len = max(cur_end - cur_start, timedelta(days=1))
        prev_start = cur_start - period_len
        prev_end = cur_start
        top_n = min(max(top_n, 1), 20)

        ru = self.requesting_user
        can_sales = ru is None or _user_has_module_access(ru, "pos", "accounting")
        can_stock = ru is None or _user_has_module_access(ru, "stock")

        if not can_sales and not can_stock:
            return {"error": "Accès insuffisant. Les modules ventes et/ou stock sont requis pour cette analyse."}

        uid = self.user_id
        sid = self.store_id
        base_q: Dict[str, Any] = {"user_id": uid}
        if sid:
            base_q["store_id"] = sid

        sales_q_c = {**base_q, "created_at": {"$gte": cur_start, "$lte": cur_end}, "status": {"$in": ["completed", "paid"]}}
        sales_q_p = {**base_q, "created_at": {"$gte": prev_start, "$lt": prev_end}, "status": {"$in": ["completed", "paid"]}}
        sales_c = await db.sales.find(sales_q_c, {"_id": 0, "items": 1}).to_list(10000) if can_sales else []
        sales_p = await db.sales.find(sales_q_p, {"_id": 0, "items": 1}).to_list(10000) if can_sales else []
        products = await db.products.find(base_q, {"_id": 0, "product_id": 1, "name": 1, "quantity": 1, "purchase_price": 1, "selling_price": 1, "min_stock": 1, "category": 1}).to_list(5000) if can_stock else []
        product_map = {p["product_id"]: p for p in products if p.get("product_id")}

        def _aggregate(sales_docs):
            agg: Dict[str, dict] = {}
            for sale in sales_docs:
                for item in (sale.get("items") or []):
                    pid = item.get("product_id") or ""
                    if not pid:
                        continue
                    qty = float(item.get("quantity") or 0)
                    rev = float(item.get("total") or 0) or (float(item.get("selling_price") or 0) * qty)
                    cost = float(item.get("purchase_price") or 0) * qty
                    if pid not in agg:
                        agg[pid] = {"revenue": 0.0, "cost": 0.0, "qty": 0.0, "name": item.get("name") or pid}
                    agg[pid]["revenue"] += rev
                    agg[pid]["cost"] += cost
                    agg[pid]["qty"] += qty
            return agg

        agg_c = _aggregate(sales_c)
        agg_p = _aggregate(sales_p)
        total_rev = sum(v["revenue"] for v in agg_c.values()) or 1

        enriched = []
        for pid, data in agg_c.items():
            p_info = product_map.get(pid) or {}
            stock = p_info.get("quantity", 0)
            velocity = data["qty"] / period_len.days if period_len.days > 0 else 0
            days_cover = round(stock / velocity) if velocity > 0 else None
            margin_pct = round((data["revenue"] - data["cost"]) / data["revenue"] * 100, 1) if data["revenue"] > 0 else 0
            prev_rev = agg_p.get(pid, {}).get("revenue", 0)
            trend = round((data["revenue"] - prev_rev) / prev_rev * 100, 1) if prev_rev > 0 else (100.0 if data["revenue"] > 0 else 0.0)
            enriched.append({
                "product_id": pid,
                "name": data["name"],
                "category": p_info.get("category") or "—",
                "revenue": round(data["revenue"]),
                "revenue_share_pct": round(data["revenue"] / total_rev * 100, 1),
                "qty_sold": round(data["qty"]),
                "margin_pct": margin_pct,
                "velocity_per_day": round(velocity, 2),
                "stock_current": stock,
                "days_of_coverage": days_cover,
                "trend_vs_prev_period": f"+{trend}%" if trend >= 0 else f"{trend}%",
                "alert": "rupture_imminente" if days_cover is not None and days_cover < 7 else ("rupture_active" if stock == 0 else None),
            })

        top = sorted(enriched, key=lambda x: x["revenue"], reverse=True)[:top_n]
        bottom = [p for p in products if p.get("product_id") not in agg_c and p.get("quantity", 0) > 0 and p.get("name")]
        bottom_sorted = sorted(bottom, key=lambda p: p.get("quantity", 0) * p.get("purchase_price", 0), reverse=True)[:5]

        return {
            "period": {"start": cur_start.strftime("%Y-%m-%d"), "end": cur_end.strftime("%Y-%m-%d"), "days": period_len.days},
            "currency": self.currency,
            "top_products": top,
            "no_sales_products": [{"name": p["name"], "stock": p.get("quantity"), "stock_value": round(p.get("quantity", 0) * p.get("purchase_price", 0))} for p in bottom_sorted],
            "insights": {
                "highest_margin": max(enriched, key=lambda x: x["margin_pct"], default={}).get("name"),
                "lowest_margin": min(enriched, key=lambda x: x["margin_pct"], default={}).get("name"),
                "fastest_moving": max(enriched, key=lambda x: x["velocity_per_day"], default={}).get("name"),
                "at_risk_rupture": [p["name"] for p in enriched if p.get("alert")],
            },
        }

    async def get_subscription_snapshot(self):
        """
        Get the current subscription/trial status for the account.
        """
        if not self.requesting_user:
            return {"error": "Utilisateur de contexte introuvable"}

        owner_id = self.user_id
        owner_doc = await db.users.find_one({"user_id": owner_id}, {"_id": 0})
        if not owner_doc:
            return {"error": "Compte introuvable"}

        account_doc = await ensure_business_account_for_user_doc(owner_doc)
        source = account_doc or owner_doc
        access_policy = compute_subscription_access_policy(source)
        effective_plan = normalize_plan(source.get("plan", "starter")) if access_policy["can_use_advanced_features"] else "starter"

        remaining_days = 0
        if source.get("subscription_end"):
            remaining_days = max(0, (source["subscription_end"].replace(tzinfo=timezone.utc) - datetime.now(timezone.utc)).days)
        elif source.get("trial_ends_at"):
            remaining_days = max(0, (source["trial_ends_at"].replace(tzinfo=timezone.utc) - datetime.now(timezone.utc)).days)

        return {
            "scope": "subscription",
            "plan": normalize_plan(source.get("plan", "starter")),
            "effective_plan": effective_plan,
            "status": source.get("subscription_status", "active"),
            "subscription_access_phase": access_policy["subscription_access_phase"],
            "remaining_days": remaining_days,
            "trial_ends_at": source.get("trial_ends_at"),
            "subscription_end": source.get("subscription_end"),
            "subscription_provider": source.get("subscription_provider", "none"),
            "requires_payment_attention": access_policy["requires_payment_attention"],
            "can_write_data": access_policy["can_write_data"],
            "can_use_advanced_features": access_policy["can_use_advanced_features"],
            "billing_contact_name": source.get("billing_contact_name"),
            "billing_contact_email": source.get("billing_contact_email"),
        }

    async def get_business_health_score(self, days: int = 30):
        """
        Calculate and return the current business health score (0-100) with a full breakdown of each component, raw values, and concrete improvement actions.
        Args:
            days: Analysis period in days (default 30). Use 7 for a weekly view, 90 for a quarterly view.
        """
        if not self.requesting_user:
            return {"error": "Utilisateur de contexte introuvable"}

        owner_id = self.user_id
        store_id = self.requesting_user.active_store_id
        currency = (await db.users.find_one({"user_id": owner_id}, {"currency": 1}) or {}).get("currency", "XOF")

        now = datetime.now(timezone.utc)
        days = max(7, min(days, 90))
        current_end = now
        current_start = now - timedelta(days=days)
        previous_start = current_start - timedelta(days=days)
        previous_end = current_start

        def _sale_metrics(sales_docs):
            revenue, cost = 0.0, 0.0
            for sale in sales_docs:
                for item in (sale.get("items") or []):
                    qty = float(item.get("quantity") or 0)
                    revenue += float(item.get("total") or 0) or (float(item.get("selling_price") or 0) * qty)
                    cost += float(item.get("purchase_price") or 0) * qty
            return revenue, cost

        base_q: Dict[str, Any] = {"user_id": owner_id}
        if store_id:
            base_q["store_id"] = store_id

        products = await db.products.find(base_q, {"_id": 0, "quantity": 1, "purchase_price": 1}).to_list(5000)
        sales_q_cur = {**base_q, "created_at": {"$gte": current_start, "$lte": current_end}, "status": {"$in": ["completed", "paid"]}}
        sales_q_prev = {**base_q, "created_at": {"$gte": previous_start, "$lt": previous_end}, "status": {"$in": ["completed", "paid"]}}
        sales_cur = await db.sales.find(sales_q_cur, {"_id": 0, "total_amount": 1, "items": 1}).to_list(5000)
        sales_prev = await db.sales.find(sales_q_prev, {"_id": 0, "total_amount": 1, "items": 1}).to_list(5000)
        customers = await db.customers.find(base_q, {"_id": 0, "current_debt": 1}).to_list(5000)

        revenue_cur, cost_cur = _sale_metrics(sales_cur)
        revenue_prev, _ = _sale_metrics(sales_prev)

        # 1. Marge brute (30%)
        margin_pct = (revenue_cur - cost_cur) / revenue_cur * 100 if revenue_cur > 0 else 0
        margin_score = min(max(margin_pct / 50 * 100, 0), 100)

        # 2. Rotation stock (20%)
        stock_value = sum(p.get("quantity", 0) * p.get("purchase_price", 0) for p in products)
        turnover = (cost_cur / stock_value) if stock_value > 0 else 0
        rotation_score = min(turnover / 2 * 100, 100)

        # 3. Poids dettes clients (20%)
        total_debt = sum(max(float(c.get("current_debt", 0) or 0), 0) for c in customers)
        debt_ratio = (total_debt / revenue_cur) if revenue_cur > 0 else 0
        debt_score = max(100 - debt_ratio * 200, 0)

        # 4. Tendance CA (30%)
        if revenue_prev > 0:
            trend_pct = (revenue_cur - revenue_prev) / revenue_prev * 100
        else:
            trend_pct = 100.0 if revenue_cur > 0 else 0.0
        trend_score = min(max(50 + trend_pct, 0), 100)

        score = round(margin_score * 0.30 + rotation_score * 0.20 + debt_score * 0.20 + trend_score * 0.30)
        score = min(max(score, 0), 100)
        grade = "excellent" if score >= 80 else "bon" if score >= 60 else "moyen" if score >= 40 else "critique"
        color = "green" if score >= 70 else "orange" if score >= 40 else "red"

        def _actions(component: str, val: float) -> list:
            if component == "margin":
                if val < 20:
                    return ["Renégocier les prix d'achat fournisseurs (priorité absolue)", "Identifier les produits vendus en dessous de leur prix de revient", "Augmenter les prix sur les produits peu concurrentiels"]
                if val < 40:
                    return ["Revoir la grille tarifaire sur les catégories à faible marge", "Proposer des bundles pour augmenter le panier moyen", "Identifier les 20% de produits qui font 80% de la marge"]
                return ["Maintenir la stratégie tarifaire actuelle", "Surveiller les hausses de prix d'achat fournisseurs"]
            if component == "rotation":
                if val < 0.5:
                    return ["Identifier les produits dormants (>60 jours sans vente)", "Lancer une promotion de déstockage sur les références lentes", "Réduire les quantités commandées sur les produits peu vendus"]
                if val < 1.0:
                    return ["Optimiser les niveaux de stock min/max", "Aligner les quantités commandées sur la vélocité réelle"]
                return ["Rotation saine, maintenir le niveau de réapprovisionnement actuel"]
            if component == "debt":
                if val > 0.3:
                    return ["Relancer immédiatement les clients avec des dettes > 30 jours", "Instaurer un plafond de crédit par client", "Exiger un acompte sur les prochaines commandes des mauvais payeurs"]
                if val > 0.1:
                    return ["Envoyer des rappels de paiement aux clients en retard", "Vérifier les conditions de paiement dans les fiches clients"]
                return ["Recouvrement sain, continuer le suivi régulier"]
            if component == "trend":
                if val < -20:
                    return ["Analyser les causes de la baisse (saisonnalité, concurrence, stock ?)", "Relancer les clients inactifs avec une offre promotionnelle", "Vérifier si des ruptures de stock ont freiné les ventes"]
                if val < 0:
                    return ["Surveiller la tendance semaine par semaine", "Identifier les catégories en baisse vs celles en hausse"]
                return ["CA en progression, capitaliser sur les produits qui tirent la croissance"]
            return []

        return {
            "score": score,
            "grade": grade,
            "color": color,
            "period_days": days,
            "currency": currency,
            "components": {
                "margin": {
                    "label": "Marge brute", "weight_pct": 30,
                    "score": round(margin_score), "value": round(margin_pct, 1), "unit": "%",
                    "interpretation": f"Marge de {round(margin_pct,1)}% sur {days} jours. Cible recommandée : >30%.",
                    "actions": _actions("margin", margin_pct),
                },
                "rotation": {
                    "label": "Rotation stock", "weight_pct": 20,
                    "score": round(rotation_score), "value": round(turnover, 2), "unit": "x/mois",
                    "interpretation": f"Rotation de {round(turnover,2)}x ce mois (stock_value={round(stock_value)} {currency}). Cible : >1x/mois.",
                    "actions": _actions("rotation", turnover),
                },
                "debt_recovery": {
                    "label": "Poids dettes clients", "weight_pct": 20,
                    "score": round(debt_score), "value": round(total_debt), "unit": currency,
                    "debt_ratio_pct": round(debt_ratio * 100, 1),
                    "interpretation": f"Dettes clients : {round(total_debt)} {currency} soit {round(debt_ratio*100,1)}% du CA. Cible : <10%.",
                    "actions": _actions("debt", debt_ratio),
                },
                "trend": {
                    "label": "Tendance CA", "weight_pct": 30,
                    "score": round(trend_score), "value": round(trend_pct, 1), "unit": "%",
                    "revenue_current": round(revenue_cur), "revenue_previous": round(revenue_prev),
                    "interpretation": f"CA {'+' if trend_pct >= 0 else ''}{round(trend_pct,1)}% vs période précédente ({round(revenue_prev)} → {round(revenue_cur)} {currency}).",
                    "actions": _actions("trend", trend_pct),
                },
            },
            "summary": f"Score de santé : {score}/100 ({grade}). " + (
                "Les points forts sont à maintenir. " if score >= 70 else
                "Des améliorations ciblées peuvent rapidement faire progresser le score. " if score >= 40 else
                "Situation critique — actions immédiates recommandées. "
            ),
        }

    async def get_feature_access_guidance(self, feature: str, platform: Optional[str] = None):
        """
        Explain whether a feature is available on the current plan and platform.
        Args:
            feature: Feature name or keyword.
            platform: Optional target platform ('web' or 'mobile'). Defaults to current client context when possible.
        """
        if not self.requesting_user:
            return {"error": "Utilisateur de contexte introuvable"}

        effective_plan = normalize_plan(
            self.requesting_user.effective_plan
            or self.requesting_user.subscription_plan
            or self.requesting_user.plan
            or "starter"
        )
        normalized_platform = (platform or "").strip().lower() or "all"
        normalized_feature = safe_regex(feature or "").lower()
        raw_feature = (feature or "").strip().lower()

        def _is_allowed(required_plan: str) -> bool:
            order = {"starter": 0, "pro": 1, "enterprise": 2}
            return order.get(effective_plan, 0) >= order.get(required_plan, 0)

        feature_rules = {
            "backoffice web": {
                "aliases": {"web", "backoffice", "back-office", "dashboard web", "web app", "pilotage web"},
                "required_plan": "enterprise",
                "platforms": {"web"},
                "reason": "Le back-office web de pilotage avance est reserve aux comptes Enterprise.",
                "upgrade_value": "Il debloque le pilotage web, les analyses plus detaillees et la consolidation avancee.",
            },
            "suggestion prix ia": {
                "aliases": {"suggestion prix", "prix ia", "price suggestion", "suggest_price"},
                "required_plan": "enterprise",
                "platforms": {"web", "mobile"},
                "reason": "La suggestion de prix IA est reservee au plan Enterprise.",
                "upgrade_value": "Elle aide a estimer un prix plus coherent a partir du contexte produit.",
            },
            "generation description ia": {
                "aliases": {"description ia", "generation description", "generate description", "product description"},
                "required_plan": "enterprise",
                "platforms": {"web", "mobile"},
                "reason": "La generation de description IA est reservee au plan Enterprise.",
                "upgrade_value": "Elle accelere la creation de fiches produit plus completes.",
            },
            "detection anomalies ia": {
                "aliases": {"anomalies", "detection anomalies", "detect_anomalies", "anomaly detection"},
                "required_plan": "pro",
                "platforms": {"web", "mobile"},
                "reason": "La detection d'anomalies IA est reservee aux plans Pro et Enterprise.",
                "upgrade_value": "Elle aide a reperer plus vite des variations inhabituelles ou des signaux faibles.",
            },
            "resume quotidien ia": {
                "aliases": {"resume quotidien", "daily summary", "summary"},
                "required_plan": "starter",
                "platforms": {"web", "mobile"},
                "reason": "Le resume quotidien IA est disponible sur tous les plans, avec une limite d'une fois par jour.",
                "upgrade_value": "L'upgrade ne sert pas a le debloquer, mais a debloquer d'autres fonctions avancees.",
            },
            "recherche langage naturel": {
                "aliases": {"recherche langage naturel", "natural query", "natural search", "question en langage naturel"},
                "required_plan": "enterprise",
                "platforms": {"web"},
                "reason": "La recherche en langage naturel est actuellement exposee sur le web et reservee a l'offre avancee.",
                "upgrade_value": "Elle permet de poser des questions metier plus librement depuis le dashboard web.",
            },
            "voice to cart": {
                "aliases": {"voice-to-cart", "voice to cart", "caisse vocale", "voice pos"},
                "required_plan": "starter",
                "platforms": {"mobile"},
                "reason": "La caisse vocale est disponible sur mobile pour tous les plans, avec un quota mensuel qui varie selon l'offre.",
                "upgrade_value": "L'upgrade augmente surtout le nombre d'utilisations disponibles et debloque d'autres fonctions IA plus avancees.",
            },
            "scan produit photo": {
                "aliases": {"scan produit", "photo produit", "scan-product", "saisie photo"},
                "required_plan": "enterprise",
                "platforms": {"mobile"},
                "reason": "La saisie produit par photo est une fonction IA reservee au plan Enterprise et ciblee mobile.",
                "upgrade_value": "Elle reduit le temps de creation produit depuis le terrain.",
            },
        }

        matched = None
        for canonical, rule in feature_rules.items():
            aliases = {canonical, *(rule.get("aliases") or set())}
            if raw_feature in aliases or any(alias in raw_feature for alias in aliases):
                matched = (canonical, rule)
                break

        if not matched:
            return {
                "scope": "feature_access",
                "feature": feature,
                "known": False,
                "message": "Aucune regle explicite trouvee pour cette fonctionnalite. Utiliser le contexte RAG et les permissions du profil.",
                "effective_plan": effective_plan,
                "platform": normalized_platform,
            }

        canonical, rule = matched
        supported_platforms = sorted(rule["platforms"])
        platform_supported = normalized_platform in {"all", ""} or normalized_platform in rule["platforms"]
        plan_allowed = _is_allowed(rule["required_plan"])
        available = plan_allowed and platform_supported
        return {
            "scope": "feature_access",
            "feature": canonical,
            "requested_feature": feature,
            "effective_plan": effective_plan,
            "required_plan": rule["required_plan"],
            "platform": normalized_platform,
            "supported_platforms": supported_platforms,
            "available": available,
            "platform_supported": platform_supported,
            "plan_allowed": plan_allowed,
            "reason": rule["reason"],
            "upgrade_value": rule["upgrade_value"],
        }

    async def get_seasonal_forecast(self, product_name: str):
        """
        Analyze sales history to forecast demand for a product.
        Args:
            product_name: Name of the product.
        """
        # 1. Find Product
        query = {"user_id": self.user_id, "name": {"$regex": product_name, "$options": "i"}}
        if self.store_id:
            query["store_id"] = self.store_id
        product = await db.products.find_one(query)
        
        if not product:
            return i18n.t("ai.tools.forecast.not_found", self.lang, name=product_name)
            
        pid = product["product_id"]
        
        # 2. Get Sales History (last 3 months)
        now = datetime.now(timezone.utc)
        three_months_ago = now - timedelta(days=90)
        
        sales_query = {
            "user_id": self.user_id,
            "created_at": {"$gte": three_months_ago},
            "items.product_id": pid
        }
        if self.store_id:
            sales_query["store_id"] = self.store_id
            
        sales = await db.sales.find(sales_query).to_list(1000)
        
        # 3. Aggregate by month
        monthly_sales = {} # "YYYY-MM" -> qty
        total_qty = 0
        
        for s in sales:
            month_key = s["created_at"].strftime("%Y-%m")
            for item in s["items"]:
                if item["product_id"] == pid:
                    qty = item["quantity"]
                    monthly_sales[month_key] = monthly_sales.get(month_key, 0) + qty
                    total_qty += qty
                    
        # 4. Simple Forecast
        avg_monthly = total_qty / 3 if total_qty > 0 else 0
        trend = "stable"
        
        sorted_months = sorted(monthly_sales.keys())
        if len(sorted_months) >= 2:
            last_month = monthly_sales[sorted_months[-1]]
            prev_month = monthly_sales[sorted_months[-2]]
            if last_month > prev_month * 1.1:
                trend = "en hausse"
            elif last_month < prev_month * 0.9:
                trend = "en baisse"
                
        forecast_qty = int(avg_monthly * 1.1) if trend == "en hausse" else int(avg_monthly)
        
        return {
            "product": product["name"],
            "current_stock": product["quantity"],
            "avg_monthly_sales": round(avg_monthly, 1),
            "trend": trend,
            "forecast_next_month": forecast_qty,
            "analysis": f"Basé sur {total_qty} ventes ces 3 derniers mois. Tendance {trend}."
        }

# ===================== AI SUPPORT =====================

async def _get_ai_data_summary(
    user_id: str,
    store_id: Optional[str] = None,
    requesting_user: Optional[User] = None,
) -> str:
    """Aggregate an AI data summary while respecting the requesting user's effective access."""
    try:
        user_doc = await db.users.find_one({"user_id": user_id}) or {}
        is_admin = bool(user_doc.get("role") in {"admin", "superadmin"})
        business_profile = get_ai_business_profile(user_doc)
        currency = user_doc.get("currency", "XOF")

        now = datetime.now(timezone.utc)
        thirty_days_ago = now - timedelta(days=30)
        twenty_four_hours_ago = now - timedelta(days=1)
        day_start = now.replace(hour=0, minute=0, second=0, microsecond=0)

        if requesting_user and requesting_user.role in {"admin", "superadmin"}:
            is_admin = True

        if is_admin:
            total_users = await db.users.count_documents({})
            new_users_24h = await db.users.count_documents({"created_at": {"$gte": twenty_four_hours_ago}})
            failed_logins = await db.security_events.count_documents(
                {
                    "type": "login_failed",
                    "timestamp": {"$gte": twenty_four_hours_ago},
                }
            )
            sales_global = await db.sales.find({"created_at": {"$gte": twenty_four_hours_ago}}).to_list(1000)
            rev_today = sum(sale.get("total_amount", 0) for sale in sales_global)
            open_tickets = await db.support_tickets.count_documents({"status": "open"})
            open_disputes = await db.disputes.count_documents({"status": "open"})
            return (
                "--- VUE GLOBALE ADMINISTRATEUR (24 HEURES) ---\n"
                f"Utilisateurs totaux: {total_users} | Nouveaux: {new_users_24h}\n"
                f"CA global: {rev_today:.0f} {currency} | Ventes: {len(sales_global)}\n"
                f"Tickets ouverts: {open_tickets} | Litiges en cours: {open_disputes}\n\n"
                "--- SECURITE ---\n"
                f"Echecs de connexion: {failed_logins}"
            )

        can_read_stock = requesting_user is None or _user_has_module_access(requesting_user, "stock")
        can_read_sales = requesting_user is None or _user_has_module_access(requesting_user, "pos", "accounting")
        can_read_accounting = requesting_user is None or _user_has_module_access(requesting_user, "accounting")
        can_read_crm = requesting_user is None or _user_has_module_access(requesting_user, "crm")
        can_read_suppliers = requesting_user is None or _user_has_module_access(requesting_user, "suppliers")
        can_read_settings = requesting_user is not None

        base_period_query: Dict[str, Any] = {"user_id": user_id, "created_at": {"$gte": thirty_days_ago}}
        if store_id:
            base_period_query["store_id"] = store_id

        stock_query: Dict[str, Any] = {"user_id": user_id}
        crm_query: Dict[str, Any] = {"user_id": user_id}
        if store_id:
            stock_query["store_id"] = store_id
            crm_query["store_id"] = store_id

        products = await db.products.find(stock_query).to_list(1000) if can_read_stock else []
        sales = await db.sales.find(base_period_query).to_list(5000) if can_read_sales else []
        expenses = await db.expenses.find(base_period_query).to_list(1000) if can_read_accounting else []
        customers = await db.customers.find(crm_query).to_list(1000) if can_read_crm else []
        settings_doc = await db.user_settings.find_one({"user_id": user_id}) if can_read_settings else None
        loyalty = settings_doc.get("loyalty", {}) if settings_doc else {}

        sales_by_product = defaultdict(float)
        payment_breakdown = defaultdict(float)
        total_cogs = 0.0
        for sale in sales:
            payment_breakdown[sale.get("payment_method", "cash")] += sale.get("total_amount", 0)
            for item in sale.get("items", []):
                product_id = item.get("product_id")
                quantity = item.get("quantity", 0)
                if product_id:
                    sales_by_product[product_id] += quantity
                total_cogs += item.get("purchase_price", 0) * quantity

        total_revenue = sum(sale.get("total_amount", 0) for sale in sales)
        total_expenses = sum(expense.get("amount", 0) for expense in expenses)
        gross_profit = total_revenue - total_cogs
        net_profit = gross_profit - total_expenses
        margin_pct = round((gross_profit / total_revenue * 100) if total_revenue > 0 else 0, 1)
        net_margin_pct = round((net_profit / total_revenue * 100) if total_revenue > 0 else 0, 1)
        avg_basket = round(total_revenue / len(sales) if sales else 0, 0)

        low_stock = [product for product in products if 0 < product.get("quantity", 0) <= product.get("min_stock", 0)]
        out_of_stock = [product for product in products if product.get("quantity", 0) == 0]
        product_velocity = {product_id: qty / 30 for product_id, qty in sales_by_product.items()}
        top_products = sorted(
            products,
            key=lambda product: product_velocity.get(product.get("product_id"), 0),
            reverse=True,
        )[:10]
        top_product_lines = [
            (
                f"- {product['name']}: stock={product.get('quantity', 0)} {product.get('unit', '')}, "
                f"vitesse={product_velocity.get(product.get('product_id'), 0):.2f}/j"
            )
            for product in top_products
            if product.get("name")
        ]

        forecast_risks = []
        if can_read_stock and can_read_sales:
            for product in products:
                product_id = product.get("product_id")
                velocity = product_velocity.get(product_id, 0)
                quantity = product.get("quantity", 0)
                if velocity > 0 and quantity > 0:
                    days_left = quantity / velocity
                    if days_left < 7:
                        forecast_risks.append(
                            f"- {product['name']}: rupture estimee dans {days_left:.1f} jour(s) "
                            f"(stock={quantity}, vitesse={velocity:.2f}/j)"
                        )
                elif quantity == 0 and velocity > 0:
                    forecast_risks.append(
                        f"- {product['name']}: rupture active avec une demande estimee a {velocity:.2f}/j"
                    )

        payment_summary = (
            " | ".join(
                [
                    f"{mode}: {amount:.0f} {currency}"
                    for mode, amount in sorted(payment_breakdown.items(), key=lambda item: -item[1])
                ]
            )
            if payment_breakdown
            else "Aucune vente"
        )

        sections: List[str] = []

        if can_read_sales or can_read_accounting:
            # Pre-compute business health score components for AI context
            sixty_days_ago = now - timedelta(days=60)
            prev_query: Dict[str, Any] = {"user_id": user_id, "created_at": {"$gte": sixty_days_ago, "$lt": thirty_days_ago}}
            if store_id:
                prev_query["store_id"] = store_id
            sales_prev_30d = await db.sales.find(prev_query, {"_id": 0, "total_amount": 1, "items": 1}).to_list(5000) if can_read_sales else []
            prev_revenue = 0.0
            prev_cost = 0.0
            for sale in sales_prev_30d:
                for item in (sale.get("items") or []):
                    qty = float(item.get("quantity") or 0)
                    prev_revenue += float(item.get("total") or 0) or (float(item.get("selling_price") or 0) * qty)
                    prev_cost += float(item.get("purchase_price") or 0) * qty

            stock_value_for_score = sum(p.get("quantity", 0) * p.get("purchase_price", 0) for p in products) if can_read_stock else 0
            total_debt_for_score = sum(max(float(c.get("current_debt", 0) or 0), 0) for c in customers) if can_read_crm else 0

            _margin_score = min(max(margin_pct / 50 * 100, 0), 100)
            _turnover = (total_cogs / stock_value_for_score) if stock_value_for_score > 0 else 0
            _rotation_score = min(_turnover / 2 * 100, 100)
            _debt_ratio = (total_debt_for_score / total_revenue) if total_revenue > 0 else 0
            _debt_score = max(100 - _debt_ratio * 200, 0)
            _trend_pct = ((total_revenue - prev_revenue) / prev_revenue * 100) if prev_revenue > 0 else (100.0 if total_revenue > 0 else 0.0)
            _trend_score = min(max(50 + _trend_pct, 0), 100)
            _health_score = round(_margin_score * 0.30 + _rotation_score * 0.20 + _debt_score * 0.20 + _trend_score * 0.30)
            _health_grade = "excellent" if _health_score >= 80 else "bon" if _health_score >= 60 else "moyen" if _health_score >= 40 else "critique"

            sections.append(
                "--- PERFORMANCE (30 JOURS) ---\n"
                f"CA: {total_revenue:.0f} {currency} | Ventes: {len(sales)} | "
                f"Panier moyen: {avg_basket:.0f} {currency}\n"
                f"Marge brute: {gross_profit:.0f} {currency} ({margin_pct}%)\n"
                f"Depenses: {total_expenses:.0f} {currency} | Resultat net: "
                f"{net_profit:.0f} {currency} ({net_margin_pct}%)\n"
                f"Modes de paiement: {payment_summary}"
            )
            sections.append(
                "--- SCORE SANTE BUSINESS (PRE-CALCULE) ---\n"
                f"Score: {_health_score}/100 ({_health_grade})\n"
                f"Marge brute: {margin_pct}% → score {round(_margin_score)}/100 (poids 30%)\n"
                f"Rotation stock: {round(_turnover, 2)}x/mois → score {round(_rotation_score)}/100 (poids 20%)\n"
                f"Dettes clients: {round(total_debt_for_score)} {currency} ({round(_debt_ratio*100,1)}% du CA) → score {round(_debt_score)}/100 (poids 20%)\n"
                f"Tendance CA: {'+' if _trend_pct >= 0 else ''}{round(_trend_pct,1)}% vs periode precedente ({round(prev_revenue)} → {round(total_revenue)} {currency}) → score {round(_trend_score)}/100 (poids 30%)\n"
                f"Note: Pour un analyse detaillee avec actions concretes, utilise l'outil get_business_health_score."
            )
            sections.append(
                "--- METHODES DE CALCUL ---\n"
                "Sante du business: score algorithmique sur 100, calcule avec 30% marge brute + 20% rotation stock + 20% poids des dettes clients + 30% tendance du chiffre d'affaires vs periode precedente.\n"
                "Projection fin de mois: projection algorithmique du CA a partir du rythme du mois en cours et d'une moyenne ponderee des deux mois precedents.\n"
                "Conseils du moment: moteur de regles metier, pas de generation LLM."
            )

        if can_read_stock:
            critical_products = ", ".join(
                [product["name"] for product in (out_of_stock + low_stock)[:10] if product.get("name")]
            ) or "Aucun produit critique"
            stock_section = (
                "--- STOCK ---\n"
                f"Produits en rupture: {len(out_of_stock)} | Stocks bas: {len(low_stock)}\n"
                f"Produits critiques: {critical_products}"
            )
            if forecast_risks:
                stock_section += "\nPrevisions de rupture:\n" + "\n".join(forecast_risks[:10])
            if top_product_lines:
                stock_section += "\nTop produits observes:\n" + "\n".join(top_product_lines)
            sections.append(stock_section)

        if can_read_crm:
            sections.append(
                "--- CRM ---\n"
                f"Total clients: {len(customers)}\n"
                f"Regle fidelite: {loyalty.get('ratio', '?')} {currency} = 1 point"
            )

        if can_read_settings and requesting_user is not None:
            effective_settings = await load_effective_settings_for_user(requesting_user)
            visible_settings = filter_settings_for_viewer(effective_settings, requesting_user).model_dump()
            enabled_modules = sorted(
                [
                    module
                    for module, enabled in (visible_settings.get("modules") or {}).items()
                    if enabled
                ]
            )
            notification_preferences = visible_settings.get("notification_preferences") or {}
            sections.append(
                "--- REGLAGES ---\n"
                f"Langue: {visible_settings.get('language') or 'fr'} | Devise: {visible_settings.get('currency') or currency}\n"
                f"Push: {'oui' if visible_settings.get('push_notifications', True) else 'non'} | "
                f"Canal email: {'oui' if notification_preferences.get('email') else 'non'} | "
                f"Canal in-app: {'oui' if notification_preferences.get('in_app', True) else 'non'}\n"
                f"TVA active: {'oui' if visible_settings.get('tax_enabled') else 'non'} | "
                f"Taux TVA: {float(visible_settings.get('tax_rate') or 0):.1f}% | "
                f"Mode taxe: {visible_settings.get('tax_mode') or 'ttc'}\n"
                f"Modules actifs: {', '.join(enabled_modules) if enabled_modules else 'aucun module actif'}"
            )

        if requesting_user is not None:
            owner_doc_full = await db.users.find_one({"user_id": user_id}, {"_id": 0}) or {}
            account_doc = await ensure_business_account_for_user_doc(owner_doc_full)
            subscription_source = account_doc or owner_doc_full
            access_policy = compute_subscription_access_policy(subscription_source)
            remaining_days = 0
            if subscription_source.get("subscription_end"):
                remaining_days = max(0, (subscription_source["subscription_end"].replace(tzinfo=timezone.utc) - now).days)
            elif subscription_source.get("trial_ends_at"):
                remaining_days = max(0, (subscription_source["trial_ends_at"].replace(tzinfo=timezone.utc) - now).days)
            sections.append(
                "--- ABONNEMENT ---\n"
                f"Plan: {normalize_plan(subscription_source.get('plan', 'starter'))} | "
                f"Plan effectif: {normalize_plan(requesting_user.effective_plan or requesting_user.subscription_plan or requesting_user.plan)}\n"
                f"Statut: {subscription_source.get('subscription_status', 'active')} | "
                f"Phase d'acces: {access_policy['subscription_access_phase']} | "
                f"Jours restants: {remaining_days}\n"
                f"Ecriture autorisee: {'oui' if access_policy['can_write_data'] else 'non'} | "
                f"Fonctionnalites avancees: {'oui' if access_policy['can_use_advanced_features'] else 'non'}"
            )

        if requesting_user is not None and (_user_has_module_access(requesting_user, "suppliers", "stock") or requesting_user.role in {"admin", "superadmin"} or is_org_admin_user(requesting_user)):
            marketplace_suppliers = await db.supplier_profiles.count_documents({})
            marketplace_products = await db.catalog_products.count_documents(published_catalog_query())
            sections.append(
                "--- MARKETPLACE ---\n"
                f"Fournisseurs visibles: {marketplace_suppliers}\n"
                f"Produits catalogue publies: {marketplace_products}"
            )

        if can_read_suppliers:
            orders_query: Dict[str, Any] = {"user_id": user_id, "created_at": {"$gte": thirty_days_ago}}
            returns_query: Dict[str, Any] = {"user_id": user_id, "created_at": {"$gte": thirty_days_ago}}
            if store_id:
                orders_query["store_id"] = store_id
                returns_query["store_id"] = store_id
            orders_count = await db.orders.count_documents(orders_query)
            returns_count = await db.returns.count_documents(returns_query)
            sections.append(
                "--- APPROVISIONNEMENT ---\n"
                f"Bons de commande sur 30 jours: {orders_count}\n"
                f"Retours fournisseurs sur 30 jours: {returns_count}"
            )

        if business_profile["is_restaurant"] and (can_read_sales or can_read_stock):
            today_key = now.date().isoformat()
            tables_query: Dict[str, Any] = {"user_id": user_id}
            reservations_query: Dict[str, Any] = {"user_id": user_id, "date": today_key}
            kitchen_query: Dict[str, Any] = {"user_id": user_id}
            open_orders_query: Dict[str, Any] = {"user_id": user_id, "status": "open"}
            recipes_query: Dict[str, Any] = {"user_id": user_id}
            if store_id:
                tables_query["store_id"] = store_id
                reservations_query["store_id"] = store_id
                kitchen_query["store_id"] = store_id
                open_orders_query["store_id"] = store_id
                recipes_query["store_id"] = store_id

            tables = await db.tables.find(tables_query).to_list(300) if can_read_sales else []
            reservations_today = await db.reservations.find(reservations_query).to_list(300) if can_read_sales else []
            kitchen_pending = (
                await db.sales.count_documents(
                    {
                        **kitchen_query,
                        "kitchen_sent": True,
                        "all_items_ready": {"$ne": True},
                        "created_at": {"$gte": day_start},
                    }
                )
                if can_read_sales
                else 0
            )
            open_orders = await db.sales.count_documents(open_orders_query) if can_read_sales else 0
            recipes_count = await db.recipes.count_documents(recipes_query) if can_read_stock else 0
            sections.append(
                "--- RESTAURATION ---\n"
                f"Tables: {len(tables)} | Reservations du jour: {len(reservations_today)}\n"
                f"Commandes ouvertes: {open_orders} | Tickets cuisine actifs: {kitchen_pending}\n"
                f"Recettes disponibles: {recipes_count}"
            )

        if not sections:
            return "Aucune donnee metier n'est accessible a ce profil pour le contexte courant."

        return "\n\n".join(sections)
    except Exception as e:
        logger.error(f"Error generating AI summary: {e}")
        return "(Note: Erreur partielle lors de la recuperation des donnees analytiques.)"
@api_router.get("/replenishment/suggestions", response_model=List[ReplenishmentSuggestion])
async def get_replenishment_suggestions(user: User = Depends(require_permission("stock", "read"))):
    """Analyze sales velocity and stock levels to suggest replenishment"""
    try:
        owner_id = get_owner_id(user)
        # 1. Get all products
        query = {"user_id": owner_id}
        query = apply_store_scope(query, user)
        
        products = await db.products.find(query).to_list(1000)
        if not products:
            return []
        
        # 2. Calculate velocity (last 30 days)
        thirty_days_ago = datetime.now(timezone.utc) - timedelta(days=30)
        sales_query = {"user_id": owner_id, "created_at": {"$gte": thirty_days_ago}}
        sales_query = apply_store_scope(sales_query, user)
            
        sales = await db.sales.find(sales_query).to_list(5000)
        
        velocity_map = defaultdict(float)
        for s in sales:
            for item in s.get("items", []):
                pid = item.get("product_id")
                qty = item.get("quantity", 0)
                velocity_map[pid] += qty / 30.0 # Average per day
                
        # 3. Get supplier-product mappings
        supplier_products = await db.supplier_products.find({"user_id": owner_id}).to_list(1000)
        sp_map = {sp.get("product_id"): sp for sp in supplier_products if sp.get("product_id")}
        
        # Get suppliers names
        supplier_ids = list(set(sp.get("supplier_id") for sp in supplier_products if sp.get("supplier_id")))
        suppliers = await db.suppliers.find({"supplier_id": {"$in": supplier_ids}, "user_id": owner_id}).to_list(100)
        supplier_names = {s.get("supplier_id"): s.get("name", "Fournisseur") for s in suppliers if s.get("supplier_id")}

        suggestions = []
        
        for p in products:
            try:
                pid = p.get("product_id")
                if not pid: continue

                qty = p.get("quantity", 0)
                min_stock = p.get("min_stock", 0)
                max_stock = p.get("max_stock", 100)
                velocity = velocity_map.get(pid, 0.0)
                lead_time = p.get("lead_time_days", 3)
                
                # Logic:
                # - If qty <= min_stock -> Critical/Warning
                # - If qty / velocity <= lead_time + 2 days -> Warning
                
                days_left = qty / velocity if velocity > 0 else 999
                
                is_needed = False
                priority = "info"
                
                if qty <= min_stock:
                    is_needed = True
                    priority = "critical" if qty == 0 else "warning"
                elif days_left <= (lead_time + 2):
                    is_needed = True
                    priority = "warning"
                    
                if is_needed:
                    suggested_qty = max(0, max_stock - qty)
                    if suggested_qty > 0:
                        sp = sp_map.get(pid)
                        supplier_id = sp.get("supplier_id") if sp else None
                        suggestions.append(ReplenishmentSuggestion(
                            product_id=pid,
                            product_name=p.get("name", "Produit inconnu"),
                            current_quantity=qty,
                            min_stock=min_stock,
                            max_stock=max_stock,
                            daily_velocity=round(velocity, 2),
                            days_until_stock_out=round(days_left, 1) if velocity > 0 else None,
                            suggested_quantity=suggested_qty,
                            priority=priority,
                            supplier_id=supplier_id,
                            supplier_name=supplier_names.get(supplier_id) if supplier_id else "Non assigné"
                        ))
            except Exception as e:
                logger.error(f"Error processing replenishment suggestion for product {p.get('product_id')}: {e}")
                continue
                
        # Sort suggestions by priority (critical first) and then by days_left
        priority_order = {"critical": 0, "warning": 1, "info": 2}
        try:
            suggestions.sort(key=lambda x: (priority_order.get(x.priority, 3), x.days_until_stock_out if x.days_until_stock_out is not None else 999))
        except Exception as e:
            logger.error(f"Error sorting replenishment suggestions: {e}")
        
        return suggestions
    except Exception as e:
        logger.error(f"CRITICAL ERROR in get_replenishment_suggestions: {e}", exc_info=True)
        # Return empty list instead of 500 to keep UI stable
        return []


@api_router.post("/replenishment/automate")
async def automate_replenishment(user: User = Depends(require_procurement_access("write"))):
    """Backend trigger for the automated reorder approval workflow"""
    owner_id = get_owner_id(user)
    suggestions = await get_replenishment_suggestions(user)
    
    # Filter only critical and warning suggestions that have a supplier
    to_reorder = [s for s in suggestions if s.priority in ["critical", "warning"] and s.supplier_id]
    
    if not to_reorder:
        return {"message": "Aucun réapprovisionnement nécessaire pour le moment.", "created_count": 0}

    # Group by supplier
    by_supplier = defaultdict(list)
    for s in to_reorder:
        by_supplier[s.supplier_id].append(s)
        
    created_orders = []
    for supplier_id, items in by_supplier.items():
        # Check if a draft order already exists for this supplier in the last 24h
        day_ago = datetime.now(timezone.utc) - timedelta(days=1)
        existing = await db.orders.find_one({
            "user_id": owner_id,
            "supplier_id": supplier_id,
            "status": "pending",
            "created_at": {"$gte": day_ago}
        })
        
        if existing:
            # Add items to existing draft
            order_id = existing["order_id"]
            for item in items:
                # Check if item already in order
                already_in = await db.order_items.find_one({"order_id": order_id, "product_id": item.product_id})
                if not already_in:
                    await db.order_items.insert_one(OrderItem(
                        order_id=order_id,
                        product_id=item.product_id,
                        product_name=item.product_name,
                        quantity=item.suggested_quantity,
                        unit_price=0.0, # Will be filled by user or from supplier cost
                        total_price=0.0
                    ).model_dump())
            created_orders.append(order_id)
        else:
            # Create new draft order
            order_id = f"ord_{uuid.uuid4().hex[:12]}"
            new_order = {
                "order_id": order_id,
                "user_id": owner_id,
                "supplier_id": supplier_id,
                "status": "pending",
                "total_amount": 0.0,
                "notes": "Généré automatiquement (Réapprovisionnement)",
                "created_at": datetime.now(timezone.utc),
                "updated_at": datetime.now(timezone.utc)
            }
            await db.orders.insert_one(new_order)
            for item in items:
                await db.order_items.insert_one(OrderItem(
                    order_id=order_id,
                    product_id=item.product_id,
                    product_name=item.product_name,
                    quantity=item.suggested_quantity,
                    unit_price=0.0,
                    total_price=0.0
                ).model_dump())
            created_orders.append(order_id)

    return {
        "message": f"{len(created_orders)} brouillon(s) de commande créé(s) ou mis à jour.",
        "created_count": len(created_orders),
        "order_ids": created_orders
    }

@api_router.get("/analytics/procurement/overview")
async def get_procurement_overview(
    days: int = 90,
    start_date: Optional[str] = None,
    end_date: Optional[str] = None,
    store_id: Optional[str] = None,
    supplier_id: Optional[str] = None,
    user: User = Depends(require_procurement_access("read")),
):
    owner_id = get_owner_id(user)
    normalized_days = normalize_analytics_days(days)
    date_range = _parse_optional_range(days=normalized_days, start_date=start_date, end_date=end_date)
    now = date_range["end"]
    cutoff = date_range["start"]

    stores = await load_accessible_stores(user)
    if store_id:
        stores = [store for store in stores if store.get("store_id") == store_id]
    store_name_map = {store["store_id"]: store.get("name", "Boutique") for store in stores if store.get("store_id")}

    orders_query: Dict[str, Any] = {"user_id": owner_id, "created_at": {"$gte": cutoff}}
    orders_query = apply_accessible_store_scope(orders_query, user, store_id)
    if supplier_id:
        orders_query["supplier_id"] = supplier_id
    orders = await db.orders.find(orders_query, {"_id": 0}).to_list(4000)
    order_ids = [order["order_id"] for order in orders]
    order_items = (
        await db.order_items.find({"order_id": {"$in": order_ids}}, {"_id": 0}).to_list(12000)
        if order_ids
        else []
    )
    order_items_by_order: Dict[str, List[dict]] = defaultdict(list)
    for item in order_items:
        order_items_by_order[item["order_id"]].append(item)

    manual_supplier_query: Dict[str, Any] = {"user_id": owner_id}
    if supplier_id:
        manual_supplier_query["supplier_id"] = supplier_id
    manual_suppliers = await db.suppliers.find(manual_supplier_query, {"_id": 0, "supplier_id": 1, "name": 1}).to_list(2000)
    manual_supplier_map = {supplier["supplier_id"]: supplier.get("name", "Fournisseur") for supplier in manual_suppliers}
    scope_label = build_analytics_scope_label(
        stores,
        store_id=store_id,
        supplier_id=supplier_id,
        supplier_name_map=manual_supplier_map,
    )

    marketplace_ids = list({order.get("supplier_user_id") for order in orders if order.get("is_connected") and order.get("supplier_user_id")})
    supplier_profiles = (
        await db.supplier_profiles.find({"user_id": {"$in": marketplace_ids}}, {"_id": 0, "user_id": 1, "company_name": 1}).to_list(500)
        if marketplace_ids
        else []
    )
    marketplace_supplier_map = {profile["user_id"]: profile.get("company_name", "Fournisseur marketplace") for profile in supplier_profiles}

    supplier_metrics: Dict[str, Dict[str, Any]] = {}
    total_spend = 0.0
    open_orders_count = 0
    delivered_statuses = {"delivered", "partially_delivered"}
    open_statuses = {"pending", "confirmed", "shipped"}

    for order in orders:
        is_connected = bool(order.get("is_connected") and order.get("supplier_user_id"))
        supplier_key = f"mp:{order.get('supplier_user_id')}" if is_connected else f"manual:{order.get('supplier_id')}"
        supplier_name = (
            marketplace_supplier_map.get(order.get("supplier_user_id"), "Fournisseur marketplace")
            if is_connected
            else manual_supplier_map.get(order.get("supplier_id"), "Fournisseur")
        )
        metric = supplier_metrics.setdefault(
            supplier_key,
            {
                "supplier_key": supplier_key,
                "supplier_id": order.get("supplier_user_id") if is_connected else order.get("supplier_id"),
                "supplier_name": supplier_name,
                "kind": "marketplace" if is_connected else "manual",
                "orders": [],
                "items": [],
                "stores": set(),
            },
        )
        metric["orders"].append(order)
        metric["items"].extend(order_items_by_order.get(order["order_id"], []))
        if order.get("store_id"):
            metric["stores"].add(order["store_id"])

        if order.get("status") in delivered_statuses:
            total_spend += _safe_float(order.get("total_amount"), 0.0)
        elif order.get("status") in open_statuses:
            open_orders_count += 1

    supplier_ranking: List[dict] = []
    for metric in supplier_metrics.values():
        orders_bucket = metric["orders"]
        items_bucket = metric["items"]
        delivered_orders = [order for order in orders_bucket if order.get("status") == "delivered"]
        partial_orders = [order for order in orders_bucket if order.get("status") == "partially_delivered"]
        cancelled_orders = [order for order in orders_bucket if order.get("status") == "cancelled"]
        timeliness_total = 0
        on_time_count = 0
        late_count = 0
        delays: List[int] = []
        for order in orders_bucket:
            created_at = parse_analytics_datetime(order.get("created_at"))
            updated_at = parse_analytics_datetime(order.get("updated_at"))
            expected_delivery = parse_analytics_datetime(order.get("expected_delivery"))
            if order.get("status") in delivered_statuses:
                if created_at and updated_at:
                    try:
                        delays.append(max((updated_at - created_at).days, 0))
                    except TypeError:
                        logger.warning(
                            "Procurement analytics: skipped delay calc for order %s (incompatible datetimes)",
                            order.get("order_id"),
                        )
                if expected_delivery and updated_at:
                    timeliness_total += 1
                    try:
                        if updated_at <= expected_delivery:
                            on_time_count += 1
                        else:
                            late_count += 1
                    except TypeError:
                        logger.warning(
                            "Procurement analytics: skipped on-time calc for order %s (incompatible datetimes)",
                            order.get("order_id"),
                        )

        avg_lead_time_days = round(sum(delays) / len(delays), 1) if delays else 0.0
        on_time_rate = _safe_rate(on_time_count, timeliness_total)
        full_delivery_rate = _safe_rate(len(delivered_orders), len(orders_bucket))
        partial_delivery_rate = _safe_rate(len(partial_orders), len(orders_bucket))
        cancel_rate = _safe_rate(len(cancelled_orders), len(orders_bucket))
        price_variance_pct = _compute_supplier_price_variance(items_bucket)
        score_payload = _compute_supplier_score(
            on_time_rate=on_time_rate,
            full_delivery_rate=full_delivery_rate,
            partial_delivery_rate=partial_delivery_rate,
            cancel_rate=cancel_rate,
            price_variance_pct=price_variance_pct,
            avg_delivery_days=avg_lead_time_days,
        )
        supplier_ranking.append(
            {
                "supplier_key": metric["supplier_key"],
                "supplier_id": metric["supplier_id"],
                "supplier_name": metric["supplier_name"],
                "kind": metric["kind"],
                "stores_count": len(metric["stores"]),
                "orders_count": len(orders_bucket),
                "open_orders": len([order for order in orders_bucket if order.get("status") in open_statuses]),
                "total_spent": round(
                    sum(_safe_float(order.get("total_amount"), 0.0) for order in orders_bucket if order.get("status") in delivered_statuses),
                    2,
                ),
                "avg_order_value": round(
                    sum(_safe_float(order.get("total_amount"), 0.0) for order in orders_bucket) / len(orders_bucket),
                    2,
                ) if orders_bucket else 0.0,
                "avg_lead_time_days": avg_lead_time_days,
                "on_time_rate": on_time_rate,
                "full_delivery_rate": full_delivery_rate,
                "partial_delivery_rate": partial_delivery_rate,
                "cancel_rate": cancel_rate,
                "price_variance_pct": price_variance_pct,
                "recent_incidents": _build_supplier_recent_incidents(late_count, len(partial_orders), len(cancelled_orders), price_variance_pct),
                **score_payload,
            }
        )
    supplier_ranking.sort(key=lambda item: (-item["score"], -item["total_spent"]))

    products_query: Dict[str, Any] = {"user_id": owner_id, "is_active": True, "min_stock": {"$gt": 0}}
    products_query = apply_accessible_store_scope(products_query, user, store_id)
    products = await db.products.find(products_query, {"_id": 0}).to_list(4000)
    supplier_links_query: Dict[str, Any] = {"user_id": owner_id}
    if supplier_id:
        supplier_links_query["supplier_id"] = supplier_id
    supplier_links = await db.supplier_products.find(supplier_links_query, {"_id": 0}).to_list(4000)
    links_by_product: Dict[str, List[dict]] = defaultdict(list)
    for link in supplier_links:
        if link.get("product_id"):
            links_by_product[link["product_id"]].append(link)
    for product_id in links_by_product:
        links_by_product[product_id].sort(
            key=lambda link: (not bool(link.get("is_preferred")), _safe_float(link.get("supplier_price"), 0.0))
        )

    open_order_product_keys = {
        f"{order.get('store_id')}::{item.get('product_id')}"
        for order in orders
        if order.get("status") in open_statuses
        for item in order_items_by_order.get(order["order_id"], [])
    }

    store_summaries: Dict[str, Dict[str, Any]] = {
        store["store_id"]: {
            "store_id": store["store_id"],
            "store_name": store.get("name", "Boutique"),
            "spent": 0.0,
            "open_orders": 0,
            "critical_replenishments": 0,
            "active_suppliers": set(),
        }
        for store in stores
        if store.get("store_id")
    }
    for order in orders:
        store_id = order.get("store_id")
        if not store_id or store_id not in store_summaries:
            continue
        if order.get("status") in delivered_statuses:
            store_summaries[store_id]["spent"] += _safe_float(order.get("total_amount"), 0.0)
        elif order.get("status") in open_statuses:
            store_summaries[store_id]["open_orders"] += 1
        if order.get("is_connected") and order.get("supplier_user_id"):
            store_summaries[store_id]["active_suppliers"].add(f"mp:{order['supplier_user_id']}")
        elif order.get("supplier_id"):
            store_summaries[store_id]["active_suppliers"].add(f"manual:{order['supplier_id']}")

    local_suggestions: List[dict] = []
    for product in products:
        store_id = product.get("store_id")
        if not store_id or store_id not in store_summaries:
            continue
        quantity = _safe_float(product.get("quantity"), 0.0)
        min_stock = _safe_float(product.get("min_stock"), 0.0)
        if min_stock <= 0 or quantity > min_stock:
            continue
        if f"{store_id}::{product.get('product_id')}" in open_order_product_keys:
            continue
        product_links = links_by_product.get(product.get("product_id"), [])
        if not product_links:
            continue
        preferred_link = product_links[0]
        suggested_quantity = round_quantity(
            max((min_stock * 2) - quantity, max(min_stock - quantity, 1)),
            _safe_float(product.get("quantity_precision"), 1.0),
        )
        supplier_price = _safe_float(preferred_link.get("supplier_price"), 0.0)
        estimated_total = round(supplier_price * suggested_quantity, 2)
        suggestion = {
            "store_id": store_id,
            "store_name": store_summaries[store_id]["store_name"],
            "product_id": product.get("product_id"),
            "product_name": product.get("name", "Produit"),
            "supplier_id": preferred_link.get("supplier_id"),
            "supplier_name": manual_supplier_map.get(preferred_link.get("supplier_id"), "Fournisseur"),
            "current_quantity": quantity,
            "min_stock": min_stock,
            "suggested_quantity": suggested_quantity,
            "supplier_price": supplier_price,
            "estimated_total": estimated_total,
        }
        local_suggestions.append(suggestion)
        store_summaries[store_id]["critical_replenishments"] += 1
        if preferred_link.get("supplier_id"):
            store_summaries[store_id]["active_suppliers"].add(f"manual:{preferred_link['supplier_id']}")

    grouped_suggestions: Dict[str, Dict[str, Any]] = {}
    for suggestion in local_suggestions:
        supplier_id = suggestion.get("supplier_id")
        if not supplier_id:
            continue
        bucket = grouped_suggestions.setdefault(
            supplier_id,
            {
                "supplier_id": supplier_id,
                "supplier_name": suggestion["supplier_name"],
                "stores": defaultdict(lambda: {"store_id": None, "store_name": None, "items": [], "estimated_total": 0.0}),
                "total_estimated_amount": 0.0,
                "total_recommended_quantity": 0.0,
            },
        )
        store_bucket = bucket["stores"][suggestion["store_id"]]
        store_bucket["store_id"] = suggestion["store_id"]
        store_bucket["store_name"] = suggestion["store_name"]
        store_bucket["items"].append(suggestion)
        store_bucket["estimated_total"] += suggestion["estimated_total"]
        bucket["total_estimated_amount"] += suggestion["estimated_total"]
        bucket["total_recommended_quantity"] += suggestion["suggested_quantity"]

    group_opportunities = [
        {
            "supplier_id": supplier_id,
            "supplier_name": payload["supplier_name"],
            "stores_count": len(payload["stores"]),
            "total_estimated_amount": round(payload["total_estimated_amount"], 2),
            "total_recommended_quantity": round(payload["total_recommended_quantity"], 2),
            "stores": [
                {
                    "store_id": store_payload["store_id"],
                    "store_name": store_payload["store_name"],
                    "items_count": len(store_payload["items"]),
                    "estimated_total": round(store_payload["estimated_total"], 2),
                    "items": store_payload["items"][:5],
                }
                for store_payload in payload["stores"].values()
            ],
        }
        for supplier_id, payload in grouped_suggestions.items()
        if len(payload["stores"]) > 1
    ]
    group_opportunities.sort(key=lambda item: (-item["stores_count"], -item["total_estimated_amount"]))

    recommendations: List[str] = []
    if group_opportunities:
        recommendations.append(f"{len(group_opportunities)} opportunite(s) d'achat groupe ont ete detectees entre plusieurs boutiques.")
    if supplier_ranking and supplier_ranking[0]["score"] < 70:
        recommendations.append("Aucun fournisseur n'atteint un score vraiment confortable : surveiller delais et stabilite des prix.")
    low_scored_suppliers = [supplier for supplier in supplier_ranking if supplier["score"] < 60]
    if low_scored_suppliers:
        recommendations.append(f"{len(low_scored_suppliers)} fournisseur(s) sont classes a risque et meritent un benchmark ou une renegociation.")

    return {
        "days": normalized_days,
        "scope_label": scope_label,
        "recommendations": recommendations,
        "approval": {
            "workflow_enabled": any(bool(order.get("approval_required")) for order in orders),
            "pending_orders": len([
                order for order in orders
                if order.get("approval_required") and order.get("approval_status") == "pending"
            ]),
        },
        "kpis": {
            "total_spend": round(total_spend, 2),
            "open_orders": open_orders_count,
            "suppliers_count": len(supplier_ranking),
            "average_supplier_score": round(sum(supplier["score"] for supplier in supplier_ranking) / len(supplier_ranking), 1) if supplier_ranking else 0.0,
            "group_opportunities": len(group_opportunities),
            "local_replenishment_items": len(local_suggestions),
        },
        "supplier_ranking": supplier_ranking[:12],
        "store_summaries": [
            {
                **payload,
                "spent": round(payload["spent"], 2),
                "active_suppliers": len(payload["active_suppliers"]),
            }
            for payload in store_summaries.values()
        ],
        "group_opportunities": group_opportunities[:8],
        "local_suggestions": local_suggestions[:20],
    }


class BatchStockUpdate(BaseModel):
    codes: List[str]
    increment: int = 1

@api_router.post("/products/batch-stock-update")
async def batch_stock_update(data: BatchStockUpdate, user: User = Depends(require_permission("stock", "write"))):
    """Increment stock for all products matching the scanned RFID tags or SKUs"""
    owner_id = get_owner_id(user)
    store_id = user.active_store_id
    
    updated_count = 0
    not_found = []
    for code in data.codes:
        # Search by barcode, RFID or SKU
        query = {
            "user_id": owner_id,
            "$or": [{"barcode": code}, {"rfid_tag": code}, {"sku": code}]
        }
        query = apply_store_scope(query, user)
        target = await db.products.find_one(query)
        
        if target:
            ensure_scoped_document_access(user, target, detail="Acces refuse pour ce produit")
            # Increment quantity
            await db.products.update_one(
                {"product_id": target["product_id"], "user_id": owner_id, "store_id": target.get("store_id")},
                {
                    "$inc": {"quantity": data.increment},
                    "$set": {"updated_at": datetime.now(timezone.utc)}
                }
            )
            
            # Log movement
            await db.stock_movements.insert_one({
                "movement_id": f"mov_{uuid.uuid4().hex[:12]}",
                "product_id": target["product_id"],
                "product_name": target["name"],
                "user_id": owner_id,
                "store_id": target.get("store_id") or store_id,
                "type": "in" if data.increment > 0 else "out",
                "quantity": abs(data.increment),
                "reason": "Mise à jour collective (Scanner)",
                "created_at": datetime.now(timezone.utc)
            })
            updated_count += 1
        else:
            not_found.append(code)
            
    return {
        "message": f"{updated_count} articles mis à jour.",
        "updated_count": updated_count,
        "not_found_count": len(not_found),
        "not_found": not_found
    }

class RFIDAssociation(BaseModel):
    rfid: str
    sku: str

class BatchRFIDAssociation(BaseModel):
    associations: List[RFIDAssociation]

@api_router.post("/products/batch-associate-rfid")
async def batch_associate_rfid(data: BatchRFIDAssociation, user: User = Depends(require_permission("stock", "write"))):
    """Associate multiple RFID tags with existing SKUs"""
    owner_id = get_owner_id(user)
    
    associated_count = 0
    for assoc in data.associations:
        # Find product by SKU
        query = {"user_id": owner_id, "sku": assoc.sku}
        query = apply_store_scope(query, user)
        product = await db.products.find_one(query)
        if product:
            ensure_scoped_document_access(user, product, detail="Acces refuse pour ce produit")
            await db.products.update_one(
                {"product_id": product["product_id"], "user_id": owner_id, "store_id": product.get("store_id")},
                {"$set": {"rfid_tag": assoc.rfid, "updated_at": datetime.now(timezone.utc)}}
            )
            associated_count += 1
            
    return {"message": f"{associated_count} tags RFID associés.", "associated_count": associated_count}


## â”â‚¬â”â‚¬ Delivery Reconciliation (Gemini matching) â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬â”â‚¬

class DeliveryMappingItem(BaseModel):
    catalog_id: str
    product_id: Optional[str] = None     # existing product to link to
    create_new: bool = False              # create a new inventory product

class ConfirmDeliveryRequest(BaseModel):
    mappings: List[DeliveryMappingItem]

class CatalogProductMappingCreate(BaseModel): # Renamed from ManualMapRequest
    catalog_id: str
    product_id: str

@api_router.post("/orders/{order_id}/suggest-matches")
async def get_catalog_suggestions(order_id: str, user: User = Depends(require_permission("stock", "read"))):
    """Use Gemini AI to suggest matches between catalog products and shopkeeper inventory."""
    owner_id = get_owner_id(user)
    order = await db.orders.find_one({"order_id": order_id, "user_id": owner_id}, {"_id": 0})
    order = await backfill_legacy_store_field(
        db.orders,
        {"order_id": order_id, "user_id": owner_id},
        order,
        user,
    )
    if not order:
        raise HTTPException(status_code=404, detail="Commande non trouvée")
    ensure_scoped_document_access(user, order, detail="Acces refuse pour cette commande")
    if not order.get("is_connected"):
        raise HTTPException(status_code=400, detail="Cette commande n'est pas une commande marketplace")

    # Get order items
    items = await db.order_items.find({"order_id": order_id}, {"_id": 0}).to_list(100)
    if not items:
        return {"suggestions": []}

    catalog_ids = [i["product_id"] for i in items]

    # Check existing mappings
    existing_mappings = await db.catalog_product_mappings.find(
        {"user_id": owner_id, "catalog_id": {"$in": catalog_ids}}, {"_id": 0}
    ).to_list(100)
    mapped = {m["catalog_id"]: m["product_id"] for m in existing_mappings}

    # Get catalog product details
    catalog_prods = await db.catalog_products.find(
        {"catalog_id": {"$in": catalog_ids}}, {"_id": 0}
    ).to_list(100)
    catalog_map = {p["catalog_id"]: p for p in catalog_prods}

    # Get shopkeeper inventory
    inventory = await db.products.find(
        {"user_id": owner_id, "is_active": True},
        {"_id": 0, "product_id": 1, "name": 1, "category_id": 1, "subcategory": 1, "quantity": 1, "unit": 1}
    ).to_list(500)

    # Resolve category names for inventory
    cat_ids = list(set(p.get("category_id") for p in inventory if p.get("category_id")))
    categories = await db.categories.find({"category_id": {"$in": cat_ids}}, {"_id": 0}).to_list(100)
    cat_names = {c["category_id"]: c["name"] for c in categories}

    suggestions = []
    items_for_gemini = []

    for item in items:
        cid = item["product_id"]
        cat_prod = catalog_map.get(cid, {})

        if cid in mapped:
            # Already mapped from a previous order
            mapped_prod = next((p for p in inventory if p["product_id"] == mapped[cid]), None)
            suggestions.append({
                "catalog_id": cid,
                "catalog_name": cat_prod.get("name", item.get("product_name", "Produit")),
                "catalog_category": cat_prod.get("category", ""),
                "catalog_subcategory": cat_prod.get("subcategory", ""),
                "quantity": item["quantity"],
                "unit_price": item["unit_price"],
                "matched_product_id": mapped[cid],
                "matched_product_name": mapped_prod["name"] if mapped_prod else "Produit supprimé",
                "confidence": 1.0,
                "reason": "Association existante",
                "source": "mapping"
            })
        else:
            items_for_gemini.append({
                "catalog_id": cid,
                "catalog_name": cat_prod.get("name", item.get("product_name", "Produit")),
                "catalog_category": cat_prod.get("category", ""),
                "catalog_subcategory": cat_prod.get("subcategory", ""),
                "quantity": item["quantity"],
                "unit_price": item["unit_price"],
            })

    # Call Gemini for unmatched items
    if items_for_gemini and inventory:
        api_key = os.environ.get("GOOGLE_API_KEY")
        if api_key:
            try:
                genai.configure(api_key=api_key)

                inv_list = []
                for p in inventory:
                    cat_name = cat_names.get(p.get("category_id"), "")
                    inv_list.append({
                        "product_id": p["product_id"],
                        "name": p["name"],
                        "category": cat_name,
                        "subcategory": p.get("subcategory", ""),
                        "unit": p.get("unit", ""),
                    })

                prompt = f"""Tu es un assistant de gestion de stock. Un commerçant reçoit une livraison de son fournisseur.
Tu dois associer chaque produit du fournisseur au produit correspondant dans l'inventaire du commerçant.

INVENTAIRE DU COMMERÇANT:
{json.dumps(inv_list, ensure_ascii=False)}

PRODUITS REÇUS DU FOURNISSEUR:
{json.dumps([{"catalog_id": i["catalog_id"], "name": i["catalog_name"], "category": i["catalog_category"], "subcategory": i["catalog_subcategory"]} for i in items_for_gemini], ensure_ascii=False)}

Pour chaque produit reçu, trouve le meilleur match dans l'inventaire du commerçant.
Considère les noms (même avec des variantes), les catégories et sous-catégories.
Par exemple "Riz brisé 25kg" et "Riz cassé sac 25" sont le même produit.

Réponds UNIQUEMENT avec un JSON valide (pas de markdown, pas de texte autour), format:
[{{"catalog_id": "...", "matched_product_id": "..." ou null si aucun match, "confidence": 0.0 à 1.0, "reason": "explication courte"}}]"""

                model = genai.GenerativeModel(model_name='gemini-2.5-flash')
                response = model.generate_content(prompt)
                response_text = response.text.strip()

                # Clean potential markdown code block
                if response_text.startswith("```"):
                    response_text = response_text.split("\n", 1)[1] if "\n" in response_text else response_text[3:]
                if response_text.endswith("```"):
                    response_text = response_text[:-3].strip()
                if response_text.startswith("json"):
                    response_text = response_text[4:].strip()

                gemini_matches = json.loads(response_text)
                gemini_map = {m["catalog_id"]: m for m in gemini_matches}

                for item in items_for_gemini:
                    match = gemini_map.get(item["catalog_id"], {})
                    matched_id = match.get("matched_product_id")
                    matched_prod = next((p for p in inventory if p["product_id"] == matched_id), None) if matched_id else None
                    suggestions.append({
                        "catalog_id": item["catalog_id"],
                        "catalog_name": item["catalog_name"],
                        "catalog_category": item["catalog_category"],
                        "catalog_subcategory": item["catalog_subcategory"],
                        "quantity": item["quantity"],
                        "unit_price": item["unit_price"],
                        "matched_product_id": matched_id if matched_prod else None,
                        "matched_product_name": matched_prod["name"] if matched_prod else None,
                        "confidence": match.get("confidence", 0),
                        "reason": match.get("reason", ""),
                        "source": "gemini"
                    })
            except Exception as e:
                logger.error(f"Gemini matching error: {e}")
                # Fallback: return items without matches
                for item in items_for_gemini:
                    suggestions.append({
                        "catalog_id": item["catalog_id"],
                        "catalog_name": item["catalog_name"],
                        "catalog_category": item["catalog_category"],
                        "catalog_subcategory": item["catalog_subcategory"],
                        "quantity": item["quantity"],
                        "unit_price": item["unit_price"],
                        "matched_product_id": None,
                        "matched_product_name": None,
                        "confidence": 0,
                        "reason": "Erreur IA — association manuelle requise",
                        "source": "error"
                    })
        else:
            # No API key — return items without matches
            for item in items_for_gemini:
                suggestions.append({
                    "catalog_id": item["catalog_id"],
                    "catalog_name": item["catalog_name"],
                    "catalog_category": item["catalog_category"],
                    "catalog_subcategory": item["catalog_subcategory"],
                    "quantity": item["quantity"],
                    "unit_price": item["unit_price"],
                    "matched_product_id": None,
                    "matched_product_name": None,
                    "confidence": 0,
                    "reason": "Clé API Gemini non configurée",
                    "source": "none"
                })
    elif items_for_gemini and not inventory:
        # Empty inventory — all items will need new products
        for item in items_for_gemini:
            suggestions.append({
                "catalog_id": item["catalog_id"],
                "catalog_name": item["catalog_name"],
                "catalog_category": item["catalog_category"],
                "catalog_subcategory": item["catalog_subcategory"],
                "quantity": item["quantity"],
                "unit_price": item["unit_price"],
                "matched_product_id": None,
                "matched_product_name": None,
                "confidence": 0,
                "reason": "Inventaire vide — nouveau produit requis",
                "source": "empty_inventory"
            })

    return {"suggestions": suggestions}


@api_router.post("/orders/{order_id}/confirm-delivery")
async def confirm_delivery(order_id: str, data: ConfirmDeliveryRequest, user: User = Depends(require_permission("stock", "write"))):
    """Confirm marketplace delivery with product mappings and stock updates."""
    owner_id = get_owner_id(user)
    order = await db.orders.find_one({"order_id": order_id, "user_id": owner_id}, {"_id": 0})
    order = await backfill_legacy_store_field(
        db.orders,
        {"order_id": order_id, "user_id": owner_id},
        order,
        user,
    )
    if not order:
        raise HTTPException(status_code=404, detail="Commande non trouvée")
    ensure_scoped_document_access(user, order, detail="Acces refuse pour cette commande")
    if not order.get("is_connected"):
        raise HTTPException(status_code=400, detail="Cette commande n'est pas une commande marketplace")
    if order.get("status") == "delivered":
        raise HTTPException(status_code=400, detail="Cette commande a déjà été livrée")

    items = await db.order_items.find({"order_id": order_id}, {"_id": 0}).to_list(100)
    items_map = {i["product_id"]: i for i in items}

    # Get catalog product details for potential new product creation
    catalog_ids = [m.catalog_id for m in data.mappings]
    catalog_prods = await db.catalog_products.find({"catalog_id": {"$in": catalog_ids}}, {"_id": 0}).to_list(100)
    catalog_map = {p["catalog_id"]: p for p in catalog_prods}

    results = []
    for mapping in data.mappings:
        item = items_map.get(mapping.catalog_id)
        if not item:
            continue

        target_product_id = mapping.product_id

        if mapping.create_new:
            # Create a new product in shopkeeper's inventory from catalog product
            cat_prod = catalog_map.get(mapping.catalog_id, {})

            # Try to find or create category
            cat_name = cat_prod.get("category", "")
            category_id = None
            if cat_name:
                existing_cat = await db.categories.find_one({"name": cat_name, "user_id": owner_id})
                if existing_cat:
                    category_id = existing_cat["category_id"]
                else:
                    new_cat = Category(name=cat_name, user_id=owner_id)
                    await db.categories.insert_one(new_cat.model_dump())
                    category_id = new_cat.category_id

            new_product = Product(
                name=cat_prod.get("name", item.get("product_name", "Nouveau produit")),
                category_id=category_id,
                subcategory=cat_prod.get("subcategory", ""),
                quantity=item["quantity"],
                unit=cat_prod.get("unit", "pièce"),
                purchase_price=item["unit_price"],
                selling_price=round(item["unit_price"] * 1.3, 2),  # 30% margin by default
                source_catalog_id=mapping.catalog_id,
                user_id=owner_id,
                store_id=order.get("store_id") or user.active_store_id,
            )
            await db.products.insert_one(new_product.model_dump())
            target_product_id = new_product.product_id

            # Create stock movement for new product
            movement = StockMovement(
                product_id=new_product.product_id,
                user_id=owner_id,
                store_id=order.get("store_id") or user.active_store_id,
                type="in",
                quantity=item["quantity"],
                reason=f"Commande {order_id} — nouveau produit créé",
                previous_quantity=0,
                new_quantity=item["quantity"]
            )
            await db.stock_movements.insert_one(movement.model_dump())

            results.append({"catalog_id": mapping.catalog_id, "action": "created", "product_id": target_product_id})

        elif target_product_id:
            # Link to existing product and update stock
            product = await db.products.find_one({"product_id": target_product_id, "user_id": owner_id}, {"_id": 0})
            if product:
                new_qty = product["quantity"] + item["quantity"]
                await db.products.update_one(
                    {"product_id": target_product_id},
                    {"$set": {"quantity": new_qty, "updated_at": datetime.now(timezone.utc)}}
                )

                movement = StockMovement(
                    product_id=target_product_id,
                    user_id=owner_id,
                    store_id=order.get("store_id") or user.active_store_id,
                    type="in",
                    quantity=item["quantity"],
                    reason=f"Commande {order_id} livrée",
                    previous_quantity=product["quantity"],
                    new_quantity=new_qty
                )
                await db.stock_movements.insert_one(movement.model_dump())

                # Check alerts
                product["quantity"] = new_qty
                await check_and_create_alerts(Product(**product), owner_id, store_id=order.get("store_id") or user.active_store_id)

                results.append({"catalog_id": mapping.catalog_id, "action": "linked", "product_id": target_product_id})

        # Save mapping for future orders
        if target_product_id:
            await db.catalog_product_mappings.update_one(
                {"user_id": owner_id, "catalog_id": mapping.catalog_id},
                {"$set": {
                    "mapping_id": f"map_{uuid.uuid4().hex[:12]}",
                    "product_id": target_product_id,
                    "user_id": owner_id,
                    "catalog_id": mapping.catalog_id,
                    "created_at": datetime.now(timezone.utc)
                }},
                upsert=True
            )

    # Mark order as delivered
    order_update_query = {"order_id": order_id, "user_id": owner_id}
    if order.get("store_id"):
        order_update_query["store_id"] = order["store_id"]
    await db.orders.update_one(
        order_update_query,
        {"$set": {"status": "delivered", "updated_at": datetime.now(timezone.utc)}}
    )

    return {"message": "Livraison confirmée", "results": results}


@api_router.post("/orders/map-product")
async def map_catalog_product(mapping: CatalogProductMappingCreate, user: User = Depends(require_permission("stock", "write"))):
    """Manually associate a catalog product with a shopkeeper inventory product."""
    owner_id = get_owner_id(user)

    # Verify the product exists
    product = await db.products.find_one({"product_id": mapping.product_id, "user_id": owner_id})
    ensure_scoped_document_access(user, product, detail="Acces refuse pour ce produit")
    if not product:
        raise HTTPException(status_code=404, detail="Produit non trouvé dans votre inventaire")

    # Verify the catalog product exists
    catalog_prod = await db.catalog_products.find_one({"catalog_id": mapping.catalog_id})
    if not catalog_prod:
        raise HTTPException(status_code=404, detail="Produit catalogue non trouvé")

    # Upsert mapping
    await db.catalog_product_mappings.update_one(
        {"user_id": owner_id, "catalog_id": mapping.catalog_id},
        {"$set": {
            "mapping_id": f"map_{uuid.uuid4().hex[:12]}",
            "product_id": mapping.product_id,
            "user_id": owner_id,
            "catalog_id": mapping.catalog_id,
            "created_at": datetime.now(timezone.utc)
        }},
        upsert=True
    )

    return {
        "message": "Association enregistrée",
        "catalog_id": mapping.catalog_id,
        "product_id": mapping.product_id,
    }



# ===================== PRODUCT VARIANTS ENDPOINTS =====================

@api_router.post("/products/{product_id}/variants")
async def add_product_variant(product_id: str, variant: ProductVariant, user: User = Depends(require_permission("stock", "write"))):
    owner_id = get_owner_id(user)
    product = await db.products.find_one({"product_id": product_id, "user_id": owner_id})
    if not product:
        raise HTTPException(status_code=404, detail="Produit non trouvé")
    
    ensure_scoped_document_access(user, product, detail="Acces refuse pour ce produit")
    variants = product.get("variants", [])
    new_variant = variant.model_dump()
    variants.append(new_variant)
    
    # Update total quantity = sum of variant quantities
    total_qty = sum(v.get("quantity", 0) for v in variants)
    
    await db.products.update_one(
        {"product_id": product_id},
        {"$set": {
            "variants": variants,
            "has_variants": True,
            "quantity": total_qty,
            "updated_at": datetime.now(timezone.utc),
        }}
    )
    
    await log_activity(user, "create", "stock", f"Variante '{variant.name}' ajoutée à {product['name']}")
    return {"message": "Variante ajoutée", "variant": new_variant, "total_quantity": total_qty}

@api_router.put("/products/{product_id}/variants/{variant_id}")
async def update_product_variant(product_id: str, variant_id: str, variant: ProductVariant, user: User = Depends(require_permission("stock", "write"))):
    owner_id = get_owner_id(user)
    product = await db.products.find_one({"product_id": product_id, "user_id": owner_id})
    if not product:
        raise HTTPException(status_code=404, detail="Produit non trouvé")
    
    variants = product.get("variants", [])
    ensure_scoped_document_access(user, product, detail="Acces refuse pour ce produit")
    found = False
    for i, v in enumerate(variants):
        if v.get("variant_id") == variant_id:
            update_data = variant.model_dump()
            update_data["variant_id"] = variant_id  # Keep the same ID
            variants[i] = update_data
            found = True
            break
    
    if not found:
        raise HTTPException(status_code=404, detail="Variante non trouvée")
    
    total_qty = sum(v.get("quantity", 0) for v in variants)
    
    await db.products.update_one(
        {"product_id": product_id},
        {"$set": {
            "variants": variants,
            "quantity": total_qty,
            "updated_at": datetime.now(timezone.utc),
        }}
    )
    
    return {"message": "Variante mise à jour", "total_quantity": total_qty}

@api_router.delete("/products/{product_id}/variants/{variant_id}")
async def delete_product_variant(product_id: str, variant_id: str, user: User = Depends(require_permission("stock", "write"))):
    owner_id = get_owner_id(user)
    product = await db.products.find_one({"product_id": product_id, "user_id": owner_id})
    if not product:
        raise HTTPException(status_code=404, detail="Produit non trouvé")
    
    variants = product.get("variants", [])
    ensure_scoped_document_access(user, product, detail="Acces refuse pour ce produit")
    new_variants = [v for v in variants if v.get("variant_id") != variant_id]
    
    if len(new_variants) == len(variants):
        raise HTTPException(status_code=404, detail="Variante non trouvée")
    
    total_qty = sum(v.get("quantity", 0) for v in new_variants)
    has_variants = len(new_variants) > 0
    
    await db.products.update_one(
        {"product_id": product_id},
        {"$set": {
            "variants": new_variants,
            "has_variants": has_variants,
            "quantity": total_qty,
            "updated_at": datetime.now(timezone.utc),
        }}
    )
    
    await log_activity(user, "delete", "stock", f"Variante supprimée du produit {product['name']}")
    return {"message": "Variante supprimée", "total_quantity": total_qty}

# ===================== SALES FORECAST (GEMINI) =====================

class ForecastProduct(BaseModel):
    product_id: str
    name: str
    current_stock: int
    velocity: float  # units/day
    days_of_stock: float  # how many days stock will last
    predicted_sales_7d: int
    predicted_sales_30d: int
    trend: str  # "up", "down", "stable"
    risk_level: str  # "critical", "warning", "ok"

class SalesForecastResponse(BaseModel):
    products: List[ForecastProduct] = []
    total_predicted_revenue_7d: float = 0.0
    total_predicted_revenue_30d: float = 0.0
    daily_forecast: List[Dict[str, Any]] = [] # Added for dashboard charts
    ai_summary: str = ""
    generated_at: str = ""
    currency: str = "XOF"

@api_router.get("/sales/forecast")
async def get_sales_forecast(user: User = Depends(require_permission("stock", "read"))):
    """Analyze sales trends and predict future sales using velocity data + Gemini AI"""
    owner_id = get_owner_id(user)
    store_id = user.active_store_id
    
    # Get products
    query = {"user_id": owner_id}
    if store_id:
        query["store_id"] = store_id
    products = await db.products.find(query, {"_id": 0}).to_list(1000)
    if not products:
        return SalesForecastResponse(generated_at=datetime.now(timezone.utc).isoformat()).model_dump()
    
    now = datetime.now(timezone.utc)
    
    # Sales last 30 days
    thirty_days_ago = now - timedelta(days=30)
    sales_query_30 = {"user_id": owner_id, "created_at": {"$gte": thirty_days_ago}}
    if store_id:
        sales_query_30["store_id"] = store_id
    sales_30 = await db.sales.find(sales_query_30).to_list(10000)
    
    # Sales last 7 days (for trend comparison)
    seven_days_ago = now - timedelta(days=7)
    
    # Aggregate by product
    from collections import defaultdict
    qty_30d = defaultdict(int)
    rev_30d = defaultdict(float)
    qty_7d = defaultdict(int)
    
    for s in sales_30:
        sale_date = parse_datetime_value(s.get("created_at"))
        is_last_7 = sale_date >= seven_days_ago if sale_date else False
        
        for item in s.get("items", []):
            pid = item.get("product_id", "")
            qty = item.get("quantity", 0)
            price = item.get("selling_price", 0)
            qty_30d[pid] += qty
            rev_30d[pid] += qty * price
            if is_last_7:
                qty_7d[pid] += qty
    
    # Build forecast per product
    forecast_products = []
    total_rev_7d = 0.0
    total_rev_30d = 0.0
    
    for p in products:
        pid = p["product_id"]
        stock = p.get("quantity", 0)
        selling_price = p.get("selling_price", 0)
        
        vel_30 = qty_30d[pid] / 30.0  # avg per day over 30d
        vel_7 = qty_7d[pid] / 7.0     # avg per day over 7d
        
        # Trend detection
        if vel_30 == 0:
            trend = "stable"
        elif vel_7 > vel_30 * 1.2:
            trend = "up"
        elif vel_7 < vel_30 * 0.8:
            trend = "down"
        else:
            trend = "stable"
        
        # Use recent velocity (weighted: 60% last 7d, 40% last 30d) for prediction
        effective_vel = vel_7 * 0.6 + vel_30 * 0.4 if vel_30 > 0 else vel_7
        
        predicted_7d = round(effective_vel * 7)
        predicted_30d = round(effective_vel * 30)
        
        days_of_stock = stock / effective_vel if effective_vel > 0 else 999
        
        # Risk level
        if stock == 0 and effective_vel > 0:
            risk = "critical"
        elif days_of_stock < 7:
            risk = "critical"
        elif days_of_stock < 14:
            risk = "warning"
        else:
            risk = "ok"
        
        rev_7d = predicted_7d * selling_price
        rev_30d = predicted_30d * selling_price
        total_rev_7d += rev_7d
        total_rev_30d += rev_30d
        
        # Only include products that have sales activity or stock
        if vel_30 > 0 or stock > 0:
            forecast_products.append(ForecastProduct(
                product_id=pid,
                name=p["name"],
                current_stock=stock,
                velocity=round(effective_vel, 2),
                days_of_stock=round(days_of_stock, 1),
                predicted_sales_7d=predicted_7d,
                predicted_sales_30d=predicted_30d,
                trend=trend,
                risk_level=risk,
            ))
    
    # Generate daily_forecast for the AreaChart in the dashboard
    # We mix actual sales from last 7 days + projected sales for next 14 days
    daily_forecast = []
    
    # Past 7 days actual revenue
    for i in range(7, 0, -1):
        date = now - timedelta(days=i)
        d_str = date.strftime("%Y-%m-%d")
        # Sum revenue for all products on this day from sales_30
        day_rev = 0
        for s in sales_30:
            s_date = s.get("created_at")
            if isinstance(s_date, str):
                try:
                    s_date = datetime.fromisoformat(s_date.replace("Z", "+00:00"))
                except:
                    continue
            if s_date and s_date.strftime("%Y-%m-%d") == d_str:
                day_rev += s.get("total_amount", 0)
        daily_forecast.append({"date": d_str, "expected_revenue": day_rev, "is_predicted": False})
        
    # Future 14 days projected revenue
    total_daily_velocity_rev = sum(
        (qty_7d[p["product_id"]] / 7.0 if qty_7d[p["product_id"]] > 0 else qty_30d[p["product_id"]] / 30.0) * p.get("selling_price", 0)
        for p in products
    )
    
    for i in range(14):
        date = now + timedelta(days=i)
        d_str = date.strftime("%Y-%m-%d")
        daily_forecast.append({
            "date": d_str, 
            "expected_revenue": round(total_daily_velocity_rev, 2),
            "is_predicted": True
        })
    
    # Sort: critical first, then by velocity desc
    risk_order = {"critical": 0, "warning": 1, "ok": 2}
    forecast_products.sort(key=lambda x: (risk_order.get(x.risk_level, 2), -x.velocity))
    
    # Gemini AI summary (optional, only if API key available)
    ai_summary = ""
    api_key = os.environ.get("GEMINI_API_KEY")
    if api_key and forecast_products:
        try:
            genai.configure(api_key=api_key)
            top_items = forecast_products[:10]
            items_text = "\n".join([
                f"- {fp.name}: stock={fp.current_stock}, vitesse={fp.velocity}/j, tendance={fp.trend}, risque={fp.risk_level}, jours_restants={fp.days_of_stock}"
                for fp in top_items
            ])
            
            critical_count = len([fp for fp in forecast_products if fp.risk_level == "critical"])
            warning_count = len([fp for fp in forecast_products if fp.risk_level == "warning"])
            
            owner_id = get_owner_id(user)
            user_doc = await db.users.find_one({"user_id": owner_id})
            currency = user_doc.get("currency", "XOF") if user_doc else "XOF"
            
            prompt_text = f"""Analyse ces prévisions de ventes et donne un résumé en 3-4 phrases concises en français.
Mentionne les produits critiques, les tendances importantes et une recommandation.

CA prévu 7 jours: {total_rev_7d:,.0f} {currency}
CA prévu 30 jours: {total_rev_30d:,.0f} {currency}
Produits critiques: {critical_count} | Attention: {warning_count}

Top produits:
{items_text}
"""
            model = genai.GenerativeModel(model_name='gemini-2.5-flash')
            response = model.generate_content(prompt_text)
            ai_summary = response.text
        except Exception as e:
            logger.error(f"Gemini forecast summary error: {e}")
            ai_summary = ""
    
    return SalesForecastResponse(
        products=forecast_products[:30],
        total_predicted_revenue_7d=round(total_rev_7d),
        total_predicted_revenue_30d=round(total_rev_30d),
        daily_forecast=daily_forecast,
        ai_summary=ai_summary,
        currency=currency,
        generated_at=now.isoformat(),
    ).model_dump()

@api_router.get("/sales/forecast/{product_id}")
async def get_product_sales_forecast(product_id: str, user: User = Depends(require_permission("stock", "read"))):
    """Analyze sales trends and predict future sales for a specific product"""
    owner_id = get_owner_id(user)
    product = await db.products.find_one({"product_id": product_id, "user_id": owner_id}, {"_id": 0})
    if not product:
        raise HTTPException(status_code=404, detail="Produit non trouvé")
        
    now = datetime.now(timezone.utc)
    thirty_days_ago = now - timedelta(days=30)
    seven_days_ago = now - timedelta(days=7)
    
    ensure_scoped_document_access(user, product, detail="Acces refuse pour ce produit")

    # Sales last 30 days for this product
    sales_query = {
        "user_id": owner_id, 
        "created_at": {"$gte": thirty_days_ago},
        "items.product_id": product_id
    }
    sales_query = apply_store_scope(sales_query, user)
        
    sales_30 = await db.sales.find(sales_query).to_list(1000)
    
    qty_30d = 0
    qty_7d = 0
    
    for s in sales_30:
        sale_date = parse_datetime_value(s.get("created_at"))
        is_last_7 = sale_date >= seven_days_ago if sale_date else False
        
        for item in s.get("items", []):
            if item.get("product_id") == product_id:
                qty = item.get("quantity", 0)
                qty_30d += qty
                if is_last_7:
                    qty_7d += qty
    
    stock = product.get("quantity", 0)
    
    vel_30 = qty_30d / 30.0
    vel_7 = qty_7d / 7.0
    
    if vel_30 == 0:
        trend = "stable"
    elif vel_7 > vel_30 * 1.2:
        trend = "up"
    elif vel_7 < vel_30 * 0.8:
        trend = "down"
    else:
        trend = "stable"
        
    effective_vel = vel_7 * 0.6 + vel_30 * 0.4 if vel_30 > 0 else vel_7
    days_of_stock = stock / effective_vel if effective_vel > 0 else 999
    
    if stock == 0 and effective_vel > 0:
        risk = "critical"
    elif days_of_stock < 7:
        risk = "critical"
    elif days_of_stock < 14:
        risk = "warning"
    else:
        risk = "ok"
        
    forecast = ForecastProduct(
        product_id=product_id,
        name=product["name"],
        current_stock=stock,
        velocity=round(effective_vel, 2),
        days_of_stock=round(days_of_stock, 1),
        predicted_sales_7d=round(effective_vel * 7),
        predicted_sales_30d=round(effective_vel * 30),
        trend=trend,
        risk_level=risk,
    )
    
    return forecast.model_dump()

# ===================== RETURNS & CREDIT NOTES ENDPOINTS =====================

async def _compute_return_totals(items: List[ReturnItem], owner_id: str, user: User) -> Dict[str, float]:
    tax_settings = await _load_tax_settings_for_user(user)
    product_ids = list({item.product_id for item in items if item.product_id})
    products = await db.products.find(
        {"product_id": {"$in": product_ids}, "user_id": owner_id},
        {"_id": 0, "product_id": 1, "tax_rate": 1},
    ).to_list(len(product_ids) or 1)
    product_map = {product["product_id"]: product for product in products}

    tax_items = []
    for item in items:
        tax_items.append({
            "product_id": item.product_id,
            "quantity": item.quantity,
            "selling_price": _round_money(item.unit_price),
            "total": _round_money(item.quantity * item.unit_price),
            "tax_rate": _resolve_product_tax_rate(
                product_map.get(item.product_id),
                tax_settings["tax_enabled"],
                tax_settings["tax_rate"],
            ),
        })

    totals = _compute_sale_totals(tax_items, tax_mode=tax_settings["tax_mode"])
    return {
        "total_amount": totals["taxable_total"],
        "tax_total": totals["tax_total"],
        "subtotal_ht": totals["subtotal_ht"],
        "tax_mode": totals["tax_mode"],
    }

@api_router.post("/returns")
async def create_return(data: ReturnCreate, user: User = Depends(require_procurement_access("write"))):
    owner_id = get_owner_id(user)
    
    # Build supplier name
    supplier_name = None
    if data.supplier_id:
        supplier = await db.suppliers.find_one({"supplier_id": data.supplier_id, "user_id": owner_id}, {"_id": 0})
        if supplier:
            supplier_name = supplier.get("name")
    
    totals = await _compute_return_totals(data.items, owner_id, user)
    
    ret = Return(
        user_id=owner_id,
        store_id=user.active_store_id,
        order_id=data.order_id,
        supplier_id=data.supplier_id,
        supplier_name=supplier_name,
        type=data.type,
        items=data.items,
        total_amount=totals["total_amount"],
        tax_total=totals["tax_total"],
        tax_mode=totals["tax_mode"],
        subtotal_ht=totals["subtotal_ht"],
        notes=data.notes,
    )
    
    await db.returns.insert_one(ret.model_dump())
    await log_activity(user, "create", "returns", f"Retour créé - {ret.total_amount:.0f} FCFA" + (f" - {supplier_name}" if supplier_name else ""))
    
    return ret.model_dump()

