@api_router.post("/webhooks/revenuecat")
async def revenuecat_webhook(request: Request):
    """Handle RevenueCat server-to-server notifications."""
    auth_header = request.headers.get("Authorization", "")
    if not verify_revenuecat_webhook(auth_header):
        await log_subscription_event(
            event_type="webhook_invalid_signature",
            provider="revenuecat",
            source="mobile",
            status="failed",
            message="Authorization RevenueCat invalide",
        )
        raise HTTPException(status_code=401, detail="Unauthorized")

    body = await request.json()
    event = body.get("event", {})
    event_type = event.get("type", "")
    app_user_id = event.get("app_user_id", "")

    if not app_user_id:
        return {"status": "ignored", "reason": "no app_user_id"}

    activate_events = {"INITIAL_PURCHASE", "RENEWAL", "UNCANCELLATION", "NON_RENEWING_PURCHASE"}
    deactivate_events = {"EXPIRATION", "BILLING_ISSUE"}
    cancel_events = {"CANCELLATION"}

    # Déduit le plan depuis le product_id RevenueCat
    product_id = (event.get("product_id") or "").lower()
    if "enterprise" in product_id:
        plan = "enterprise"
    elif "pro" in product_id:
        plan = "pro"
    else:
        plan = "starter"

    owner_doc = await db.users.find_one({"user_id": app_user_id}, {"_id": 0})
    account_doc = await ensure_business_account_for_user_doc(owner_doc or {"user_id": app_user_id, "role": "shopkeeper"})
    current_source = account_doc or owner_doc or {}
    current_plan = normalize_plan(current_source.get("plan"))
    current_provider = (current_source.get("subscription_provider") or "none").strip().lower()

    if current_plan == "enterprise" and plan in {"starter", "pro"}:
        logger.info(
            "RevenueCat %s ignored for enterprise-managed account %s (incoming plan=%s, current_provider=%s)",
            event_type,
            app_user_id,
            plan,
            current_provider,
        )
        await log_subscription_event(
            event_type="payment_ignored",
            provider="revenuecat",
            source="mobile",
            owner_user_id=app_user_id,
            plan=current_plan,
            status=current_source.get("subscription_status") or "active",
            provider_reference=product_id or event.get("transaction_id"),
            message="RevenueCat event ignored because the account is already managed as Enterprise on web billing.",
            metadata={
                "incoming_event_type": event_type,
                "incoming_product_id": product_id,
                "incoming_plan": plan,
                "current_plan": current_plan,
                "current_provider": current_provider,
            },
        )
        return {"status": "ignored", "reason": "enterprise_managed_on_web"}

    if event_type in activate_events:
        expiration_ms = event.get("expiration_at_ms")
        sub_end = (
            datetime.fromtimestamp(expiration_ms / 1000, tz=timezone.utc)
            if expiration_ms
            else datetime.now(timezone.utc) + timedelta(days=30)
        )
        await update_business_account_for_owner(
            app_user_id,
            {
                "plan": plan,
                "subscription_status": "active",
                "subscription_provider": "revenuecat",
                "subscription_end": sub_end,
            },
        )
        logger.info(f"RevenueCat {event_type} → plan={plan} user={app_user_id}")
        await log_subscription_event(
            event_type="payment_succeeded",
            provider="revenuecat",
            source="mobile",
            owner_user_id=app_user_id,
            plan=plan,
            status="active",
            provider_reference=product_id or event.get("transaction_id"),
            message=f"RevenueCat {event_type}",
            metadata={"subscription_end": _iso_or_none(sub_end), "product_id": product_id},
        )
    elif event_type in deactivate_events:
        await update_business_account_for_owner(
            app_user_id,
            {"subscription_status": "expired"},
        )
        logger.info(f"RevenueCat {event_type} - expired user {app_user_id}")
        await log_subscription_event(
            event_type="subscription_expired",
            provider="revenuecat",
            source="mobile",
            owner_user_id=app_user_id,
            plan=plan,
            status="expired",
            provider_reference=product_id or event.get("transaction_id"),
            message=f"RevenueCat {event_type}",
            metadata={"product_id": product_id},
        )
    elif event_type in cancel_events:
        await update_business_account_for_owner(
            app_user_id,
            {"subscription_status": "cancelled"},
        )
        logger.info(f"RevenueCat CANCELLATION for user {app_user_id}")
        await log_subscription_event(
            event_type="subscription_cancelled",
            provider="revenuecat",
            source="mobile",
            owner_user_id=app_user_id,
            status="cancelled",
            provider_reference=product_id or event.get("transaction_id"),
            message="RevenueCat cancellation",
            metadata={"product_id": product_id},
        )

    return {"status": "ok"}

def _resolve_revenuecat_server_key() -> str:
    return (
        os.environ.get("REVENUECAT_SECRET_KEY")
        or os.environ.get("REVENUECAT_API_KEY")
        or os.environ.get("REVENUECAT_V1_SECRET_KEY")
        or ""
    ).strip()


def _infer_plan_from_revenuecat_value(value: Optional[str]) -> Optional[str]:
    normalized = normalize_plan(value)
    if normalized in {"starter", "pro", "enterprise"}:
        return normalized
    lowered = str(value or "").lower()
    if "enterprise" in lowered:
        return "enterprise"
    if "pro" in lowered or "premium" in lowered:
        return "pro"
    if "starter" in lowered or "basic" in lowered:
        return "starter"
    return None


def _extract_revenuecat_active_subscription(subscriber: dict) -> Optional[dict]:
    now = datetime.now(timezone.utc)
    candidates: List[dict] = []

    entitlements = subscriber.get("entitlements") or {}
    if isinstance(entitlements, dict):
        for entitlement_name, entitlement in entitlements.items():
            if not isinstance(entitlement, dict):
                continue
            expires_at = parse_datetime_value(entitlement.get("expires_date"))
            if expires_at and expires_at < now:
                continue
            product_id = str(
                entitlement.get("product_identifier")
                or entitlement.get("product_id")
                or ""
            )
            plan = _infer_plan_from_revenuecat_value(entitlement_name) or _infer_plan_from_revenuecat_value(product_id)
            if not plan:
                continue
            candidates.append(
                {
                    "plan": plan,
                    "product_id": product_id,
                    "subscription_end": expires_at,
                    "priority": 3 if plan == "enterprise" else 2 if plan == "pro" else 1,
                }
            )

    subscriptions = subscriber.get("subscriptions") or {}
    if isinstance(subscriptions, dict):
        for product_id, sub in subscriptions.items():
            if not isinstance(sub, dict):
                continue
            expires_at = parse_datetime_value(sub.get("expires_date"))
            if expires_at and expires_at < now:
                continue
            plan = _infer_plan_from_revenuecat_value(str(product_id))
            if not plan:
                continue
            candidates.append(
                {
                    "plan": plan,
                    "product_id": str(product_id),
                    "subscription_end": expires_at,
                    "priority": 3 if plan == "enterprise" else 2 if plan == "pro" else 1,
                }
            )

    if not candidates:
        return None

    def _sort_key(item: dict):
        expires_at = item.get("subscription_end")
        expires_ts = expires_at.timestamp() if isinstance(expires_at, datetime) else float("inf")
        return (item.get("priority", 0), expires_ts)

    return sorted(candidates, key=_sort_key, reverse=True)[0]


async def _sync_subscription_from_revenuecat(app_user_id: str) -> Optional[dict]:
    server_key = _resolve_revenuecat_server_key()
    if not server_key:
        return None

    import httpx as _httpx

    url = f"https://api.revenuecat.com/v1/subscribers/{quote(app_user_id, safe='')}"
    headers = {
        "Authorization": f"Bearer {server_key}",
        "Accept": "application/json",
    }

    try:
        async with _httpx.AsyncClient(timeout=15.0) as client:
            response = await client.get(url, headers=headers)
        if response.status_code == 404:
            return {"active": False}
        if response.status_code < 200 or response.status_code >= 300:
            logger.warning("RevenueCat sync failed for %s: HTTP %s", app_user_id, response.status_code)
            return None
        payload = response.json()
        subscriber = payload.get("subscriber") if isinstance(payload, dict) else {}
        if not isinstance(subscriber, dict):
            return None
        active = _extract_revenuecat_active_subscription(subscriber)
        if not active:
            return {"active": False}
        return {
            "active": True,
            "plan": active["plan"],
            "product_id": active.get("product_id"),
            "subscription_end": active.get("subscription_end"),
        }
    except Exception as exc:
        logger.warning("RevenueCat sync exception for %s: %s", app_user_id, exc)
        return None


class SubscriptionSyncBody(BaseModel):
    purchased_plan: Optional[str] = None

@api_router.post("/subscription/sync")
async def sync_subscription(
    body: SubscriptionSyncBody = Body(SubscriptionSyncBody()),
    user: User = Depends(require_auth),
):
    """Manual sync fallback - check if subscription is still active."""
    owner_id = get_owner_id(user)
    owner_doc = await db.users.find_one({"user_id": owner_id}, {"_id": 0})
    if not owner_doc:
        raise HTTPException(status_code=404)
    account_doc = await ensure_business_account_for_user_doc(owner_doc)
    source = account_doc or owner_doc
    current_plan = normalize_plan(source.get("plan"))
    current_provider = (source.get("subscription_provider") or "none").strip().lower()

    # Fallback sync with RevenueCat to avoid stale Starter/Pro status when webhook is delayed.
    rc_state = await _sync_subscription_from_revenuecat(owner_id)
    rc_synced = False
    if rc_state is not None:
        if rc_state.get("active"):
            incoming_plan = normalize_plan(rc_state.get("plan"))
            # Never downgrade an Enterprise account managed by web billing from a mobile event.
            is_enterprise_managed_on_web = (
                current_plan == "enterprise"
                and current_provider in {"stripe", "flutterwave"}
                and incoming_plan in {"starter", "pro"}
            )
            if not is_enterprise_managed_on_web:
                update_payload: Dict[str, Any] = {
                    "plan": incoming_plan,
                    "subscription_status": "active",
                    "subscription_provider": "revenuecat",
                }
                if rc_state.get("subscription_end"):
                    update_payload["subscription_end"] = rc_state["subscription_end"]
                await update_business_account_for_owner(owner_id, update_payload)
                account_doc = await db.business_accounts.find_one({"owner_user_id": owner_id}, {"_id": 0})
                source = account_doc or owner_doc
                current_plan = normalize_plan(source.get("plan"))
                current_provider = (source.get("subscription_provider") or "none").strip().lower()
                rc_synced = True
        elif current_provider == "revenuecat" and current_plan in {"starter", "pro"}:
            await update_business_account_for_owner(owner_id, {"subscription_status": "expired"})
            account_doc = await db.business_accounts.find_one({"owner_user_id": owner_id}, {"_id": 0})
            source = account_doc or owner_doc
            current_plan = normalize_plan(source.get("plan"))
            rc_synced = True

    # If RevenueCat API sync failed/unavailable but mobile just completed a purchase,
    # trust the client-reported plan (the store already validated the transaction).
    hint_plan = normalize_plan(body.purchased_plan) if body.purchased_plan else None
    if not rc_synced and hint_plan and hint_plan in {"starter", "pro"}:
        is_enterprise_managed_on_web = (
            current_plan == "enterprise"
            and current_provider in {"stripe", "flutterwave"}
        )
        if not is_enterprise_managed_on_web and hint_plan != current_plan:
            update_payload = {
                "plan": hint_plan,
                "subscription_status": "active",
                "subscription_provider": "revenuecat",
                "subscription_end": datetime.now(timezone.utc) + timedelta(days=30),
            }
            await update_business_account_for_owner(owner_id, update_payload)
            logger.info("Subscription sync: applied client hint plan=%s for user %s (RevenueCat API unavailable)", hint_plan, owner_id)
            await log_subscription_event(
                event_type="sync_client_hint",
                provider="revenuecat",
                source="mobile",
                owner_user_id=owner_id,
                plan=hint_plan,
                status="active",
                message=f"Plan updated from client hint (RevenueCat API sync unavailable). rc_state={rc_state}",
            )
            account_doc = await db.business_accounts.find_one({"owner_user_id": owner_id}, {"_id": 0})
            source = account_doc or owner_doc
            current_plan = normalize_plan(source.get("plan"))

    sub_end = parse_datetime_value(source.get("subscription_end"))
    if sub_end and current_plan in ("pro", "enterprise"):
        sub_end_aware = sub_end if sub_end.tzinfo else sub_end.replace(tzinfo=timezone.utc)
        if sub_end_aware < datetime.now(timezone.utc):
            await update_business_account_for_owner(owner_id, {"subscription_status": "expired"})
            source["subscription_status"] = "expired"
    access_policy = compute_subscription_access_policy(source)
    effective_plan = current_plan if access_policy["can_use_advanced_features"] else "starter"
    return {
        "plan": current_plan,
        "effective_plan": effective_plan,
        "status": source.get("subscription_status", "active"),
        "subscription_access_phase": access_policy["subscription_access_phase"],
        "requires_payment_attention": access_policy["requires_payment_attention"],
    }

